def _safe_print(text: str, color: Optional[str] = None) -> None:
    """
    Print helper that tolerates emojis / Unicode on Windows consoles.

    Encodes using the current stdout encoding with errors='replace' so
    characters like traffic-light emojis don't crash with UnicodeEncodeError.
    """
    try:
        rendered = colored(text, color) if color is not None else text
    except Exception:
        rendered = text
    encoding = "ascii" if _LOG_ASCII_ONLY else (getattr(sys.stdout, "encoding", None) or "utf-8")
    try:
        safe = rendered.encode(encoding, errors="replace").decode(encoding, errors="replace")
    except Exception:
        safe = rendered
    try:
        print(safe)
        sys.stdout.flush()
    except Exception:
        # Last-resort: drop the line rather than crash
        pass


def _maybe_run_nt_smoke_test_only_fast() -> None:
    """
    Fast-path for CI smoke tests.

    `python -m na.discord_addons.cli.stream_live_csv --nt_smoke_test_only ...` is used in unit tests
    and should exit quickly without importing the full ML stack.
    """
    if __name__ != "__main__":
        return
    if "--nt_smoke_test_only" not in sys.argv:
        return

    p = argparse.ArgumentParser(add_help=False)
    p.add_argument("--nt_host", default="127.0.0.1")
    p.add_argument("--nt_port", type=int, default=5019)
    p.add_argument("--nt_adapter", default="native")
    p.add_argument("--nt_account", default="SIM")
    p.add_argument("--nt_instrument", default="")
    p.add_argument("--nt_require_snapshot", action="store_true")
    p.add_argument("--nt_connect_timeout_sec", type=float, default=5.0)
    p.add_argument("--nt_snapshot_timeout_sec", type=float, default=5.0)
    args, _unknown = p.parse_known_args()

    adapter = str(getattr(args, "nt_adapter", "native") or "native").lower()
    if adapter != "mock":
        _safe_print(f"NT_READY|connected=false|snapshot=false|account={args.nt_account}|instrument={args.nt_instrument}|port={args.nt_port}")
        _safe_print(f"BRIDGE_STOPPED|port={args.nt_port}|ok=true|reason=nt_smoke_test_only")
        raise SystemExit(0)

    # Mock transport is in-memory; no sockets required.
    try:
        from na.discord_addons.mock_nt_transport import MockNTTransport
    except Exception as exc:  # pragma: no cover
        _safe_print(f"NT_READY|connected=false|snapshot=false|account={args.nt_account}|instrument={args.nt_instrument}|port={args.nt_port}")
        _safe_print(f"BRIDGE_STOPPED|port={args.nt_port}|ok=false|reason=import_mock_transport_failed:{exc}")
        raise SystemExit(2)

    snapshot_seen = False

    def _cb(msg: Dict[str, Any]) -> None:
        nonlocal snapshot_seen
        try:
            if str(msg.get("type") or "").upper() == "POSITION_SNAPSHOT":
                snapshot_seen = True
        except Exception:
            pass

    bridge = MockNTTransport(
        host=str(args.nt_host),
        port=int(args.nt_port),
        account=str(args.nt_account or "SIM"),
        instruments=[str(args.nt_instrument or "")] if str(args.nt_instrument or "") else [],
        protocol_version=1,
    )
    bridge.add_callback(_cb)
    bridge.start()

    _safe_print(
        f"NT_READY|connected=true|snapshot={str(bool(snapshot_seen)).lower()}|account={args.nt_account}|instrument={args.nt_instrument}|port={args.nt_port}"
    )
    bridge.shutdown()
    _safe_print(f"BRIDGE_STOPPED|port={args.nt_port}|ok=true|reason=nt_smoke_test_only")
    raise SystemExit(0)


_maybe_run_nt_smoke_test_only_fast()


import numpy as np
import pandas as pd


def _json_default(obj: Any) -> Any:
    np_mod = globals().get("np", None)
    pd_mod = globals().get("pd", None)
    if np_mod is not None:
        try:
            if isinstance(obj, (np_mod.integer, np_mod.floating, np_mod.bool_)):
                return obj.item()
            if isinstance(obj, np_mod.ndarray):
                return obj.tolist()
        except Exception:
            pass
    if pd_mod is not None:
        try:
            if isinstance(obj, pd_mod.Timestamp):
                return obj.isoformat()
        except Exception:
            pass
    if isinstance(obj, (set, tuple)):
        return list(obj)
    if isinstance(obj, bytes):
        try:
            return obj.decode("utf-8")
        except Exception:
            return obj.decode("utf-8", errors="replace")
    return str(obj)


def _json_dumps(payload: Any, *, indent: Optional[int] = None) -> str:
    return json.dumps(payload, ensure_ascii=False, default=_json_default, indent=indent)


def _stable_dumps(payload: Any) -> str:
    return json.dumps(payload, sort_keys=True, separators=(",", ":"), ensure_ascii=True, default=_json_default)


def _atomic_write_text(path: Path, text: str, *, retries: int = 2, retry_delay_sec: float = 0.05) -> None:
    """Write ``text`` to ``path`` atomically (temp file + os.replace) with bounded retries.

    Hardens hot snapshot files (status.json, run_health_summary.json, ...) against
    external file locks (antivirus / cloud sync): readers can never observe a
    truncated file, and a transient sharing violation heals on the next attempt
    instead of leaving a poisoned destination handle. See 2026-06-10 zombie-run
    incident: status.json was left truncated mid-write and never recovered.
    """
    path = Path(path)
    last_exc: Optional[BaseException] = None
    for _attempt in range(max(1, int(retries) + 1)):
        tmp = path.with_name(f".{path.name}.{os.getpid()}-{threading.get_ident()}.tmp")
        try:
            path.parent.mkdir(parents=True, exist_ok=True)
            with tmp.open("w", encoding="utf-8", newline="\n") as fh:
                fh.write(text)
                fh.flush()
                try:
                    os.fsync(fh.fileno())
                except Exception:
                    pass
            os.replace(tmp, path)
            return
        except Exception as exc:
            last_exc = exc
            try:
                tmp.unlink(missing_ok=True)
            except Exception:
                pass
            time.sleep(max(0.0, float(retry_delay_sec)))
    if last_exc is not None:
        raise last_exc


def _append_text_with_retry(path: Path, text: str, *, retries: int = 2, retry_delay_sec: float = 0.05) -> None:
    """Append ``text`` to ``path`` (flush + fsync) with bounded retries.

    Every attempt opens a fresh handle, so a transient external lock cannot
    permanently wedge the writer the way a single held handle can.
    """
    path = Path(path)
    last_exc: Optional[BaseException] = None
    for _attempt in range(max(1, int(retries) + 1)):
        try:
            path.parent.mkdir(parents=True, exist_ok=True)
            with path.open("a", encoding="utf-8", newline="\n") as fh:
                fh.write(text)
                fh.flush()
                try:
                    os.fsync(fh.fileno())
                except Exception:
                    pass
            return
        except Exception as exc:
            last_exc = exc
            time.sleep(max(0.0, float(retry_delay_sec)))
    if last_exc is not None:
        raise last_exc


def _csv_row_text(header: Sequence[str], row: Mapping[str, Any]) -> str:
    """Render a single CSV row (matching csv.DictWriter output) as text."""
    buf = io.StringIO()
    writer = csv.DictWriter(buf, fieldnames=list(header), lineterminator="\n")
    writer.writerow(row)
    return buf.getvalue()


class FiberServer:
    def __init__(
        self,
        host: str,
        port: int,
        *,
        queue_max: int = 50000,
        logger: Optional[logging.Logger] = None,
    ) -> None:
        self.host = host
        self.port = int(port)
        self.queue: "queue.Queue[Dict[str, Any]]" = queue.Queue(maxsize=max(1, int(queue_max)))
        self.logger = logger
        self._stop = threading.Event()
        self._thread: Optional[threading.Thread] = None
        self._server: Optional[socket.socket] = None
        self._client: Optional[socket.socket] = None
        self._rx_buffer = bytearray()
        self.dropped = 0
        self._conn_id = 0
        self._rx_bytes = 0
        self._first_line_seen = False
        self._last_log_ts = 0.0
        self._json_errors = 0
        self._exc_logged = False
        self._client_addr: Optional[Any] = None
        self._last_msg_recv_mono: Optional[float] = None
        self._last_msg_recv_utc: Optional[str] = None
        self._last_msg_type: Optional[str] = None
        self._last_bar_recv_mono: Optional[float] = None
        self._last_bar_recv_utc: Optional[str] = None
        self._last_bar_utc_ticks: Optional[int] = None
        self._queue_full_disconnects = 0

    def start(self) -> None:
        if self._thread is not None:
            return
        self._thread = threading.Thread(target=self._run, name="fiber-server", daemon=True)
        self._thread.start()

    def shutdown(self) -> None:
        self._stop.set()
        try:
            if self._client is not None:
                self._client.close()
        except Exception:
            pass
        try:
            if self._server is not None:
                self._server.close()
        except Exception:
            pass
        self._client = None
        self._server = None
        if self._thread and self._thread.is_alive():
            self._thread.join(timeout=2.0)

    def _run(self) -> None:
        while not self._stop.is_set():
            try:
                if self._server is None:
                    srv = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                    srv.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
                    srv.bind((self.host, self.port))
                    srv.listen(1)
                    srv.settimeout(0.5)
                    self._server = srv
                    if self.logger:
                        self.logger.info("Fiber server listening on %s:%s", self.host, self.port)
                if self._client is None:
                    try:
                        client, addr = self._server.accept() if self._server else (None, None)
                    except socket.timeout:
                        continue
                    if client is None:
                        continue
                    client.settimeout(0.5)
                    # Detect a silently-dead NT peer (host crash / cable pull) at the OS level
                    # instead of relying solely on the app-level stale-feed timeout.
                    try:
                        client.setsockopt(socket.SOL_SOCKET, socket.SO_KEEPALIVE, 1)
                        if hasattr(socket, "SIO_KEEPALIVE_VALS"):
                            # Windows: (on/off, keepalive_time_ms, keepalive_interval_ms)
                            client.ioctl(socket.SIO_KEEPALIVE_VALS, (1, 10000, 3000))
                    except (AttributeError, OSError):
                        pass
                    self._client = client
                    self._client_addr = addr
                    self._rx_buffer = bytearray()
                    self._rx_bytes = 0
                    self._first_line_seen = False
                    self._json_errors = 0
                    self._exc_logged = False
                    self._last_msg_recv_mono = None
                    self._last_msg_recv_utc = None
                    self._last_msg_type = None
                    self._last_bar_recv_mono = None
                    self._last_bar_recv_utc = None
                    self._last_bar_utc_ticks = None
                    self._conn_id += 1
                    if self.logger:
                        self.logger.info("Fiber client connected. conn_id=%s addr=%s", self._conn_id, addr)
                try:
                    chunk = self._client.recv(4096) if self._client else b""
                except socket.timeout:
                    continue
                except Exception as exc:
                    if self.logger and not self._exc_logged:
                        self._exc_logged = True
                        self.logger.exception("Fiber recv exception; closing client. conn_id=%s", self._conn_id)
                    self._close_client(reason="recv_exception", exc=exc)
                    continue
                if not chunk:
                    if self.logger:
                        self.logger.info(
                            "Fiber EOF recv=0; closing client. conn_id=%s bytes=%s json_errors=%s",
                            self._conn_id,
                            self._rx_bytes,
                            self._json_errors,
                        )
                    self._close_client(reason="recv_eof")
                    continue
                self._rx_bytes += len(chunk)
                self._rx_buffer.extend(chunk)
                while b"\n" in self._rx_buffer:
                    raw, _, rest = self._rx_buffer.partition(b"\n")
                    self._rx_buffer = bytearray(rest)
                    line = raw.decode("utf-8", errors="replace").strip()
                    if not line:
                        continue
                    if not self._first_line_seen:
                        self._first_line_seen = True
                        if self.logger:
                            preview = line[:300]
                            self.logger.info(
                                "Fiber first line received. conn_id=%s len=%s line=%s",
                                self._conn_id,
                                len(line),
                                preview,
                            )
                    try:
                        msg = json.loads(line)
                    except Exception:
                        self._json_errors += 1
                        self._log_rate("Fiber JSON parse error. conn_id=%s total=%s" % (self._conn_id, self._json_errors))
                        continue
                    msg["_recv_ts_utc"] = utc_ts()
                    msg["_recv_ts_mono"] = time.monotonic()
                    msg_type = str(msg.get("type") or "").upper()
                    self._last_msg_recv_mono = msg["_recv_ts_mono"]
                    self._last_msg_recv_utc = msg["_recv_ts_utc"]
                    self._last_msg_type = msg_type or None
                    if msg_type == "BAR":
                        self._last_bar_recv_mono = msg["_recv_ts_mono"]
                        self._last_bar_recv_utc = msg["_recv_ts_utc"]
                        try:
                            self._last_bar_utc_ticks = int(msg.get("utcTicks"))
                        except Exception:
                            self._last_bar_utc_ticks = None
                    try:
                        self.queue.put_nowait(msg)
                    except queue.Full:
                        self._handle_queue_overflow(msg_type=msg_type)
                        continue
            except Exception:
                if self.logger and not self._exc_logged:
                    self._exc_logged = True
                    self.logger.exception("Fiber server loop exception; closing client. conn_id=%s", self._conn_id)
                self._close_client(reason="server_loop_exception")

    def _log_rate(self, msg: str, *, every_sec: float = 2.0) -> None:
        if not self.logger:
            return
        now = time.time()
        if now - self._last_log_ts < every_sec:
            return
        self._last_log_ts = now
        self.logger.info("%s", msg)

    def _close_client(self, *, reason: str, exc: Optional[BaseException] = None) -> None:
        if self.logger:
            self.logger.info("Fiber server closing client. conn_id=%s reason=%s", self._conn_id, reason)
        try:
            if self._client:
                self._client.close()
        except Exception:
            pass
        self._client = None
        self._client_addr = None

    def reset_client(self, *, reason: str) -> None:
        self._close_client(reason=reason)

    def _handle_queue_overflow(self, *, msg_type: str) -> None:
        self.dropped += 1
        self._queue_full_disconnects += 1
        drained = 0
        try:
            while True:
                self.queue.get_nowait()
                drained += 1
        except queue.Empty:
            pass
        reset_msg = {
            "type": "RESET",
            "reason": "receiver_queue_overflow",
            "overflow_msg_type": str(msg_type or ""),
            "dropped_total": int(self.dropped),
            "drained_count": int(drained),
            "conn_id": int(self._conn_id),
            "_recv_ts_utc": utc_ts(),
            "_recv_ts_mono": time.monotonic(),
        }
        try:
            self.queue.put_nowait(reset_msg)
        except queue.Full:
            pass
        if self.logger:
            self.logger.warning(
                "Fiber queue FULL - forcing replay. drop_count=%s queue_max=%s drained=%s conn_id=%s msg_type=%s",
                self.dropped,
                self.queue.maxsize,
                drained,
                self._conn_id,
                msg_type,
            )
        self._close_client(reason="queue_full_replay_required")

    def watchdog_snapshot(self) -> Dict[str, Any]:
        return {
            "conn_id": int(self._conn_id),
            "has_client": bool(self._client is not None),
            "client_addr": self._client_addr,
            "last_msg_recv_mono": self._last_msg_recv_mono,
            "last_msg_recv_utc": self._last_msg_recv_utc,
            "last_msg_type": self._last_msg_type,
            "last_bar_recv_mono": self._last_bar_recv_mono,
            "last_bar_recv_utc": self._last_bar_recv_utc,
            "last_bar_utc_ticks": self._last_bar_utc_ticks,
            "queue_depth": int(self.queue.qsize()),
            "queue_max": int(self.queue.maxsize),
            "dropped": int(self.dropped),
            "queue_full_disconnects": int(self._queue_full_disconnects),
            "rx_bytes": int(self._rx_bytes),
            "json_errors": int(self._json_errors),
        }


