def _normalize_scalar(value: Any, *, precision: int = 10) -> Any:
    if value is None:
        return None
    if isinstance(value, (np.integer, np.floating, np.bool_)):
        value = value.item()
    if isinstance(value, pd.Timestamp):
        return value.isoformat()
    reason = "smoke_fail"
    exit_code = 0
    try:
        fval = float(value)
    except Exception:
        return str(value)
    if math.isnan(fval) or math.isinf(fval):
        return None
    return float(f"{fval:.{precision}f}")


def _row_hash_from_mapping(values: Mapping[str, Any]) -> str:
    items: List[List[Any]] = []
    for key in sorted(values.keys()):
        items.append([str(key), _normalize_scalar(values.get(key))])
    payload = _stable_dumps(items)
    return hashlib.sha256(payload.encode("utf-8")).hexdigest()


def _file_sha256(path: Path) -> Optional[str]:
    try:
        h = hashlib.sha256()
        with path.open("rb") as fh:
            for chunk in iter(lambda: fh.read(1024 * 1024), b""):
                h.update(chunk)
        return h.hexdigest()
    except Exception:
        return None


