def _append_csv_row(path: Path, header: Sequence[str], row: Mapping[str, Any]) -> None:
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    write_header = not path.exists() or path.stat().st_size <= 0
    with path.open("a", encoding="utf-8", newline="\n") as fh:
        writer = csv.DictWriter(fh, fieldnames=list(header), extrasaction="ignore", lineterminator="\n")
        if write_header:
            writer.writeheader()
        writer.writerow({key: row.get(key, "") for key in header})
        try:
            fh.flush()
            os.fsync(fh.fileno())
        except Exception:
            pass


def _csv_bool(value: Any) -> str:
    if value is None:
        return ""
    return "true" if bool(value) else "false"


def _gate_report_summary(
    *,
    gate_prob_raw: bool,
    gate_vwap_raw: bool,
    gate_ema_raw: bool,
    gate_tod_raw: bool,
    gate_vwap_enabled: Optional[bool] = None,
    gate_ema_enabled: Optional[bool] = None,
    gate_tod_enabled: Optional[bool] = None,
) -> Tuple[str, Dict[str, Any]]:
    vwap_enabled = True if gate_vwap_enabled is None else bool(gate_vwap_enabled)
    ema_enabled = True if gate_ema_enabled is None else bool(gate_ema_enabled)
    tod_enabled = True if gate_tod_enabled is None else bool(gate_tod_enabled)

    def _char(letter: str, enabled: bool, passed: bool) -> str:
        if not enabled:
            return letter.upper()
        return letter.upper() if passed else letter.lower()

    prob_pass = bool(gate_prob_raw)
    vwap_pass = (not vwap_enabled) or bool(gate_vwap_raw)
    ema_pass = (not ema_enabled) or bool(gate_ema_raw)
    tod_pass = (not tod_enabled) or bool(gate_tod_raw)

    gate_meta = {
        "gate_prob_enabled": True,
        "gate_prob_raw_pass": prob_pass,
        "gate_prob_effective_pass": prob_pass,
        "gate_vwap_enabled": vwap_enabled,
        "gate_vwap_raw_pass": vwap_pass,
        "gate_vwap_effective_pass": vwap_pass,
        "gate_ema_enabled": ema_enabled,
        "gate_ema_raw_pass": ema_pass,
        "gate_ema_effective_pass": ema_pass,
        "gate_tod_enabled": tod_enabled,
        "gate_tod_raw_pass": tod_pass,
        "gate_tod_effective_pass": tod_pass,
    }
    gates = "".join([
        "P" if prob_pass else "p",
        _char("V", vwap_enabled, bool(gate_vwap_raw)),
        _char("E", ema_enabled, bool(gate_ema_raw)),
        _char("T", tod_enabled, bool(gate_tod_raw)),
    ])
    gate_meta["gates_text"] = gates
    return gates, gate_meta


def _gate_failure_reason_from_state(state: Mapping[str, bool]) -> str:
    for key in _GATE_PRIORITY:
        if key in state and not bool(state[key]):
            return f"{key}_fail"
    return "ok"


def _normalize_vwap_gate_mode(mode: Any) -> str:
    raw = str(mode or "trend").strip().lower()
    if raw in {"any", "off", "none", "disabled", "disable"}:
        return "any"
    if raw in {"fade", "faded", "mean_revert", "mean_reversion", "reversion", "countertrend"}:
        return "fade"
    return "trend"


def _alignment_from_direction(*, side: Optional[str], direction: Optional[str]) -> Optional[str]:
    side_txt = str(side or "").upper()
    direction_txt = str(direction or "").lower()
    if side_txt not in {"LONG", "SHORT"} or direction_txt not in {"up", "down"}:
        return None
    if (direction_txt == "up" and side_txt == "LONG") or (direction_txt == "down" and side_txt == "SHORT"):
        return "aligned"
    return "countertrend"


def _compute_vwap_gate_raw(
    *,
    close: Optional[float],
    vwap: Optional[float],
    longish: bool,
    prob: Optional[float],
    mode: Any,
    override_pts: float = 0.0,
    override_prob_threshold: float = 0.28,
) -> bool:
    if close is None or not np.isfinite(close) or vwap is None or not np.isfinite(vwap):
        return True

    gate_mode = _normalize_vwap_gate_mode(mode)
    if gate_mode == "any":
        return True
    if gate_mode == "fade":
        gate_pass = (close < vwap) if longish else (close > vwap)
    else:
        gate_pass = (close > vwap) if longish else (close < vwap)

    if gate_pass:
        return True
    if float(override_pts or 0.0) <= 0.0:
        return False

    vwap_dist = abs(float(close) - float(vwap))
    if vwap_dist < float(override_pts):
        return False
    if prob is None or not np.isfinite(prob):
        return False

    override_thr = float(override_prob_threshold or 0.28)
    if longish and prob >= (1.0 - override_thr):
        return True
    if (not longish) and prob <= override_thr:
        return True
    return False


def _gate_failure_detail(
    *,
    gate_state: Mapping[str, bool],
    prob: Optional[float],
    p_buy: float,
    p_sell: float,
    close: Optional[float],
    vwap: Optional[float],
    ema20: Optional[float],
    ema50: Optional[float],
    ts_dt: Optional[pd.Timestamp],
    trade_window_start: str,
    trade_window_end: str,
    phase2_setup_prob: Optional[float],
    phase2_p_setup: Optional[float],
    risk_reason: Optional[str],
    vwap_gate_mode: Any = "trend",
) -> Tuple[Optional[str], Optional[str]]:
    failed_gate: Optional[str] = None
    for key in _GATE_PRIORITY:
        if key in gate_state and not bool(gate_state[key]):
            failed_gate = key
            break
    if failed_gate is None:
        return None, None

    def _fmt(val: Optional[float]) -> str:
        if val is None or not np.isfinite(val):
            return "n/a"
        return f"{val:.3f}"

    compare: Optional[str] = None
    if failed_gate == "prob":
        short_req = 1.0 - float(p_sell)
        short_prob = None if prob is None or not np.isfinite(prob) else float(1.0 - prob)
        compare = (
            f"prob={_fmt(prob)} not >= p_buy={_fmt(p_buy)} and not <= short_cut={_fmt(p_sell)}"
            f" (short_prob={_fmt(short_prob)}, p_short_required={_fmt(short_req)})"
        )
    elif failed_gate == "setup":
        compare = f"p_setup={_fmt(phase2_setup_prob)} < { _fmt(phase2_p_setup) }"
    elif failed_gate == "vwap":
        longish = False
        if prob is not None and np.isfinite(prob):
            longish = prob >= 0.5
        gate_mode = _normalize_vwap_gate_mode(vwap_gate_mode)
        if gate_mode == "any":
            compare = "vwap_gate_mode=any"
        elif gate_mode == "fade":
            if longish:
                compare = f"close={_fmt(close)} >= vwap={_fmt(vwap)}"
            else:
                compare = f"close={_fmt(close)} <= vwap={_fmt(vwap)}"
        else:
            if longish:
                compare = f"close={_fmt(close)} <= vwap={_fmt(vwap)}"
            else:
                compare = f"close={_fmt(close)} >= vwap={_fmt(vwap)}"
    elif failed_gate == "ema":
        longish = False
        if prob is not None and np.isfinite(prob):
            longish = prob >= 0.5
        if longish:
            compare = f"ema20={_fmt(ema20)} <= ema50={_fmt(ema50)}"
        else:
            compare = f"ema20={_fmt(ema20)} >= ema50={_fmt(ema50)}"
    elif failed_gate == "tod":
        ts_txt = ts_dt.strftime("%H:%M") if isinstance(ts_dt, pd.Timestamp) else "n/a"
        compare = f"ts={ts_txt} not in {trade_window_start}-{trade_window_end}"
    elif failed_gate == "risk":
        reason_txt = risk_reason or "unknown"
        compare = f"risk_blocked reason={reason_txt}"

    return failed_gate, compare


def _format_gate_state(state: Mapping[str, bool]) -> str:
    parts: List[str] = []
    for key in _GATE_PRIORITY:
        if key in state:
            parts.append(f"{key}={1 if state[key] else 0}")
    return " ".join(parts)


def _override_confident_long(
    *,
    side: str,
    prob_long: Optional[float],
    hold_conf: Optional[float],
    override_prob_min: float,
    override_hold_conf_min: float,
) -> bool:
    if side != "LONG":
        return False
    if override_prob_min >= 1.0 or override_hold_conf_min >= 1.0:
        return False
    if prob_long is None or hold_conf is None:
        return False
    if not np.isfinite(prob_long) or not np.isfinite(hold_conf):
        return False
    return bool(prob_long >= override_prob_min and hold_conf >= override_hold_conf_min)


def _apply_override_to_open_allowed(
    *,
    base_open_allowed: bool,
    override_confident_long: bool,
    other_gates_ok: bool,
) -> Tuple[bool, bool]:
    override_applied = bool((not base_open_allowed) and override_confident_long and other_gates_ok)
    open_allowed = bool(base_open_allowed or override_applied)
    return open_allowed, override_applied


def _coerce_bool_flag(value: Any, *, default: bool = False) -> bool:
    if isinstance(value, (bool, int, np.bool_)):
        return bool(value)
    return bool(default)


def _safety_escalation_state(status: str) -> str:
    """Normalize status codes to escalation state. Shim for compatibility."""
    mapping = {
        "missing_stop_soft_failed": "soft_failed",
        "protection_timeout_retry": "retrying",
        "repair_exhausted": "hard_failed",
    }
    return mapping.get(str(status or "").strip().lower(), "unknown")


def _strict_intent_parity_is_hard_block(reason: str) -> bool:
    """Check if parity violation is hard block. Shim for compatibility."""
    return "contract_violation" in str(reason or "").lower()


def _resolve_execution_intended_mode(run_mode: str, nt_enabled: bool, replay_execution_intended: bool) -> bool:
    """Resolve if execution is intended based on mode. Shim for compatibility."""
    if run_mode == "live":
        return nt_enabled
    if run_mode == "replay":
        return nt_enabled and replay_execution_intended
    return False


def _safe_truthy(value: Any) -> bool:
    """Safely convert value to boolean. Shim for compatibility."""
    if value is None:
        return False
    return bool(value)


def _finalize_entry_emit_action(
    *,
    action: str,
    phase2_setup_pass: Any,
    override_applied: Any,
    allow_setup_fail_entries: bool = False,
    blocked_by: Sequence[str],
) -> Tuple[str, List[str], Optional[str], bool]:
    action_upper = str(action or "").upper()
    blocked = [str(item) for item in list(blocked_by or []) if str(item)]
    if action_upper not in {"OPEN", "FLIP"}:
        return action_upper, blocked, None, True
    setup_pass = _coerce_bool_flag(phase2_setup_pass, default=True)
    override_used = bool(override_applied)
    setup_fail_entries_allowed = bool(allow_setup_fail_entries)
    block_reason: Optional[str] = None
    if not setup_pass and not override_used and not setup_fail_entries_allowed:
        block_reason = "phase2_setup_blocked"
        if "setup" not in blocked:
            blocked.append("setup")
    elif setup_fail_entries_allowed and "setup" in blocked:
        blocked = [item for item in blocked if item != "setup"]
    emit_allowed = not blocked and block_reason is None
    final_action = action_upper if emit_allowed else "NO_TRADE"
    return final_action, blocked, block_reason, emit_allowed


def _resolve_no_trade_reason_detail(
    *,
    action: str,
    final_action: Optional[str],
    reason_detail: Optional[str],
    blocked_by: Sequence[str],
    gate_state: Optional[Mapping[str, bool]] = None,
    entry_block_reason: Optional[str] = None,
    publish_block_reason: Optional[str] = None,
    readiness_snapshot: Optional[Mapping[str, Any]] = None,
) -> str:
    def _first_preflight_blocker(
        *,
        readiness: Optional[Mapping[str, Any]],
        blocked: Sequence[str],
        gates: Optional[Mapping[str, bool]],
    ) -> str:
        readiness_map = dict(readiness or {})
        if readiness_map:
            if not bool(readiness_map.get("armed_ok", True)):
                return "not_armed"
            if bool(readiness_map.get("nt_enabled", False)):
                if not bool(readiness_map.get("nt_connected", True)) or not bool(readiness_map.get("nt_ready", True)):
                    return "nt_not_ready"
            if readiness_map.get("feed_health_ok") is False:
                return "feed_stale"
            if readiness_map.get("offline_ok") is False:
                return "offline_exec_blocked"
        for blocked_reason in blocked or []:
            blocked_txt = str(blocked_reason or "").strip()
            if blocked_txt:
                return blocked_txt
        if gates:
            first_gate_fail = _gate_failure_reason_from_state(gates)
            if first_gate_fail != "ok":
                return first_gate_fail
            for key, enabled in gates.items():
                if not bool(enabled):
                    return f"{str(key)}_fail"
        return "ok"

    action_upper = str(action or "").upper()
    final_action_upper = str(final_action or action_upper).upper()
    reason_txt = str(reason_detail or "").strip()
    if action_upper != "NO_TRADE" and final_action_upper != "NO_TRADE":
        return reason_txt
    if reason_txt:
        return reason_txt
    block_reason_txt = str(entry_block_reason or publish_block_reason or "").strip()
    if block_reason_txt:
        return f"gate_pass_but_publish_blocked:{block_reason_txt}"
    preflight_blocker = _first_preflight_blocker(
        readiness=readiness_snapshot,
        blocked=blocked_by,
        gates=gate_state,
    )
    if preflight_blocker != "ok":
        return preflight_blocker
    return "no_emittable_strategy_event"

