def _load_prop_guardrails(path: Optional[str]) -> Tuple[Optional[EnhancedGuardrails], Optional[Path]]:
    if not path:
        if _STRICT_CONFIG_MODE:
            raise RuntimeError(
                "NA_LIVE_STRICT_CONFIG_MODE=1: prop guardrails config path is required but was not provided."
            )
        return None, None
    cfg_path = Path(path).expanduser()
    if not cfg_path.exists():
        if _STRICT_CONFIG_MODE:
            raise FileNotFoundError(
                f"NA_LIVE_STRICT_CONFIG_MODE=1: prop guardrails config not found at {cfg_path}"
            )
        logger.warning("Prop guardrails config not found at %s; continuing without prop safety integration.", cfg_path)
        return None, None
    try:
        import yaml  # type: ignore
    except Exception as exc:
        if _STRICT_CONFIG_MODE:
            raise RuntimeError(
                f"NA_LIVE_STRICT_CONFIG_MODE=1: PyYAML required to load {cfg_path} but is not installed."
            ) from exc
        logger.warning("PyYAML unavailable; skipping prop guardrails config %s", cfg_path)
        return None, None
    try:
        payload = yaml.safe_load(cfg_path.read_text(encoding="utf-8")) or {}
    except Exception as exc:
        if _STRICT_CONFIG_MODE:
            raise RuntimeError(
                f"NA_LIVE_STRICT_CONFIG_MODE=1: failed to parse prop guardrails YAML at {cfg_path}"
            ) from exc
        logger.warning("Failed to parse prop guardrails YAML at %s: %s", cfg_path, exc)
        return None, None
    risk_cfg_raw = payload.get("risk") if isinstance(payload.get("risk"), Mapping) else {}
    vol_cfg_raw = payload.get("volatility") if isinstance(payload.get("volatility"), Mapping) else {}
    guard_cfg_raw = payload.get("guardrails") if isinstance(payload.get("guardrails"), Mapping) else {}
    risk_cfg = PropRiskConfig(
        max_daily_loss=float(risk_cfg_raw.get("max_daily_loss", 500.0)),
        daily_loss_warning=float(risk_cfg_raw.get("daily_loss_warning", 300.0)),
        max_drawdown=float(risk_cfg_raw.get("max_drawdown", 2000.0)),
        drawdown_warning=float(risk_cfg_raw.get("drawdown_warning", 1500.0)),
        max_trades_per_day=int(risk_cfg_raw.get("max_trades_per_day", 5)),
        max_consecutive_losses=int(risk_cfg_raw.get("max_consecutive_losses", 2)),
        max_contracts=int(risk_cfg_raw.get("max_contracts", 2)),
        max_risk_per_trade=float(risk_cfg_raw.get("max_risk_per_trade", 400.0)),
        allowed_start_time=str(risk_cfg_raw.get("allowed_start_time", "09:30")),
        allowed_end_time=str(risk_cfg_raw.get("allowed_end_time", "14:30")),
        no_trade_before=str(risk_cfg_raw.get("no_trade_before", "09:35")),
        no_trade_after=str(risk_cfg_raw.get("no_trade_after", "14:15")),
    )
    configured_pre_send_slippage = float(vol_cfg_raw.get("max_slippage_points", 2.0))
    configured_fill_slippage = float(guard_cfg_raw.get("fill_slippage_max", configured_pre_send_slippage))
    unified_slippage_points = min(configured_pre_send_slippage, configured_fill_slippage)
    if abs(configured_pre_send_slippage - configured_fill_slippage) > 1e-9:
        logger.warning(
            "Prop guardrails slippage mismatch in %s; unifying pre-send %.2f pts and fill %.2f pts to %.2f pts.",
            cfg_path,
            configured_pre_send_slippage,
            configured_fill_slippage,
            unified_slippage_points,
        )
    vol_cfg = VolatilityConfig(
        atr_spike_multiplier=float(vol_cfg_raw.get("atr_spike_multiplier", 2.0)),
        atr_lookback_bars=int(vol_cfg_raw.get("atr_lookback_bars", 20)),
        price_velocity_threshold=float(vol_cfg_raw.get("price_velocity_threshold", 5.0)),
        velocity_lookback_bars=int(vol_cfg_raw.get("velocity_lookback_bars", 5)),
        high_vol_regime_atr_mult=float(vol_cfg_raw.get("high_vol_regime_atr_mult", 1.5)),
        extreme_vol_regime_atr_mult=float(vol_cfg_raw.get("extreme_vol_regime_atr_mult", 2.5)),
        max_signal_age_sec=float(vol_cfg_raw.get("max_signal_age_sec", 3.0)),
        max_slippage_points=float(unified_slippage_points),
    )
    guard_cfg = EnhancedGuardRailConfig(
        price_age_max_sec=float(guard_cfg_raw.get("price_age_max_sec", 10.0)),
        bar_age_max_sec=float(guard_cfg_raw.get("bar_age_max_sec", 90.0)),
        snapshot_age_max_sec=float(guard_cfg_raw.get("snapshot_age_max_sec", 60.0)),
        atr_spike_multiplier=float(vol_cfg_raw.get("atr_spike_multiplier", 2.0)),
        max_slippage_points=float(unified_slippage_points),
        signal_max_age_sec=float(vol_cfg_raw.get("max_signal_age_sec", 3.0)),
        max_daily_loss=float(risk_cfg_raw.get("max_daily_loss", 500.0)),
        max_trades_per_day=int(risk_cfg_raw.get("max_trades_per_day", 5)),
        max_consecutive_losses=int(risk_cfg_raw.get("max_consecutive_losses", 2)),
        fill_slippage_max=float(unified_slippage_points),
        signal_validation_enabled=bool(guard_cfg_raw.get("signal_validation_enabled", True)),
        volatility_check_enabled=bool(guard_cfg_raw.get("volatility_check_enabled", True)),
    )
    return EnhancedGuardrails(guard_cfg, vol_cfg, risk_cfg), cfg_path

def _merge_custom_presets_into_registry() -> None:
    """
    Merge user-defined presets from YAML into PRESETS.

    Enable by setting:
      NA_CUSTOM_PRESETS_YAML=C:\\path\\to\\custom_es_risk_presets.yaml
    """
    import os
    from pathlib import Path

    yaml_path = os.environ.get("NA_CUSTOM_PRESETS_YAML")
    if not yaml_path:
        return

    p = Path(yaml_path)
    if not p.exists():
        raise FileNotFoundError(f"NA_CUSTOM_PRESETS_YAML not found: {p}")

    try:
        import yaml  # requires PyYAML
    except Exception as e:
        raise RuntimeError("Missing dependency: PyYAML (pip install pyyaml)") from e

    doc = yaml.safe_load(p.read_text(encoding="utf-8")) or {}
    presets = doc.get("risk_presets") or {}
    if not isinstance(presets, dict):
        raise ValueError("custom preset YAML must contain a mapping under 'risk_presets:'")

    overlap = set(presets).intersection(PRESETS)
    if overlap:
        names = ", ".join(sorted(overlap))
        raise ValueError(f"custom preset YAML duplicates existing presets: {names}")
    PRESETS.update(presets)


def _simplified_repo_root() -> Path:
    here = Path(__file__).resolve()
    for parent in here.parents:
        if parent.name == "simplified":
            return parent
    return here.parents[0]


def _load_phase2_manifest(tag: str) -> Tuple[Path, Dict[str, Any]]:
    root = _simplified_repo_root()
    raw_tag = str(tag)
    tag = raw_tag.strip()
    if tag != raw_tag:
        logger.warning("[PHASE2] stripped whitespace from phase2_tag %r -> %r", raw_tag, tag)
    manifest_path = root / "artifacts" / "phase2" / "candidates" / tag / "manifest.json"
    try:
        payload = json.loads(manifest_path.read_text(encoding="utf-8"))
    except FileNotFoundError as exc:
        if tag.startswith("retrain_v7"):
            raise RuntimeError(
                f"Phase-2 manifest not found for deployable v7 tag '{tag}': {manifest_path}. "
                "Treat this candidate as incomplete until manifest.json exists."
            ) from exc
        raise RuntimeError(f"Phase-2 manifest not found for tag '{tag}': {manifest_path}") from exc
    except json.JSONDecodeError as exc:
        raise RuntimeError(f"Phase-2 manifest at {manifest_path} is not valid JSON: {exc}") from exc

    def _resolve_manifest_paths(manifest: Dict[str, Any], manifest_file: Path) -> Dict[str, Any]:
        """
        Resolve manifest paths anchored to the manifest directory.

        - Relative paths resolve to `manifest_file.parent` (primary) and then to repo-root (fallback).
        - Legacy absolute paths are coerced to safe, relocatable values when possible.
        """
        base = manifest_file.parent.resolve()
        repo_root = _simplified_repo_root().parent.resolve()

        def _resolve_value(key: str, raw: Any) -> Any:
            if not isinstance(raw, str) or not raw.strip():
                return raw
            p = Path(raw).expanduser()
            if p.is_absolute():
                # Legacy absolute paths: make them relocatable.
                if key in ("setup_model_path", "dir_model_path", "close_model_path"):
                    return str((base / p.name).resolve())
                if key == "artifact_dir":
                    return str(base)
                if key == "csv":
                    # Best-effort: map to repo-root `data/...` if present in the absolute path.
                    parts = list(p.parts)
                    lower = [x.lower() for x in parts]
                    if "data" in lower:
                        i = lower.index("data")
                        return str((repo_root / Path(*parts[i:])).resolve())
                    return str(p)
                return str(p)

            # Relative path: prefer manifest-dir relative; fallback to repo-root relative.
            cand = (base / p).resolve()
            if cand.exists():
                return str(cand)
            cand2 = (repo_root / p).resolve()
            return str(cand2)

        for key in ("setup_model_path", "dir_model_path", "close_model_path", "artifact_dir", "csv"):
            if key in manifest:
                manifest[key] = _resolve_value(key, manifest.get(key))
        return manifest

    payload = _resolve_manifest_paths(payload, manifest_path)
    return manifest_path, payload


def _validate_deployable_phase2_manifest(tag: str, manifest_path: Path, manifest: Mapping[str, Any]) -> None:
    """Fail fast before a rejected v7 candidate can silently fall back to preset thresholds."""
    config_block = manifest.get("config") or {}
    decision_policy = config_block.get("decision_policy") if isinstance(config_block, Mapping) else {}
    try:
        Phase2DecisionPolicy.from_mapping(decision_policy if isinstance(decision_policy, Mapping) else {})
    except Exception as exc:
        raise RuntimeError(
            f"Phase-2 candidate '{tag}' has unsupported decision_policy at {manifest_path}: {exc}. "
            "Failing closed instead of running with mismatched live/replay policy."
        ) from exc
    tag_txt = str(tag or "").strip()
    manifest_tag = str(manifest.get("tag") or tag_txt).strip()
    is_v7_candidate = tag_txt.startswith("retrain_v7") or manifest_tag.startswith("retrain_v7")
    if not is_v7_candidate:
        return
    if bool(manifest.get("rejected")):
        reason = str(manifest.get("rejected_reason") or "no rejected_reason recorded")
        raise RuntimeError(
            f"Phase-2 v7 candidate '{tag_txt}' is rejected and is not deployable: {reason}. "
            "Use retrain_v6_pass2_grid_02 or retrain_v4 until a v7 candidate has rejected=false "
            "and non-empty p_setup/p_long/p_short thresholds."
        )
    thresholds = manifest.get("thresholds") or {}
    if not isinstance(thresholds, Mapping):
        thresholds = {}
    missing = [key for key in ("p_setup", "p_long", "p_short") if thresholds.get(key) is None]
    if missing:
        raise RuntimeError(
            f"Phase-2 v7 candidate '{tag_txt}' is incomplete at {manifest_path}: "
            f"missing thresholds {', '.join(missing)}. Do not replay/promote it until the "
            "manifest contains p_setup, p_long, and p_short."
        )


def _apply_phase2_manifest_overrides(
    args: argparse.Namespace,
    manifest_path: Path,
    manifest: Mapping[str, Any],
    argv_tokens: Sequence[str],
) -> argparse.Namespace:
    if getattr(args, "disable_safety_gates", False):
        logger.info("Safety gates disabled; skipping Phase-2 manifest overrides.")
        return args
    args.phase2 = True
    args.phase2_feature_hash = manifest.get("feature_hash")
    args.phase2_manifest_path = str(manifest_path)

    preset_fields = set(getattr(args, "_preset_fields", set()))

    def _maybe_manifest_override(attr: str, manifest_value: Any, flag_name: str) -> None:
        if manifest_value is None:
            return
        # BooleanOptionalAction exposes an explicit `--no-...` form for disable flags.
        # Treat either spelling as an explicit CLI override so manifest defaults do not
        # silently re-enable a field the caller intentionally turned off.
        if _flag_in_argv(argv_tokens, flag_name) or _flag_in_argv(argv_tokens, f"--no-{flag_name.lstrip('-')}"):
            return
        if attr in preset_fields:
            return
        setattr(args, attr, manifest_value)

    _maybe_manifest_override("setup_model_path", manifest.get("setup_model_path"), "--setup_model_path")
    dir_model_val = manifest.get("dir_model_path")
    _maybe_manifest_override("dir_model_path", dir_model_val, "--dir_model_path")
    close_cfg = manifest.get("close") or {}
    close_model_val = manifest.get("close_model_path")
    if close_model_val is None and isinstance(close_cfg, Mapping):
        close_model_val = close_cfg.get("model_path")
    _maybe_manifest_override("close_model_path", close_model_val, "--close_model_path")
    if isinstance(close_cfg, Mapping):
        _maybe_manifest_override("phase2_close_enabled", close_cfg.get("enabled"), "--phase2_close_enabled")
        _maybe_manifest_override("phase2_close_threshold", close_cfg.get("threshold"), "--phase2_close_threshold")
    if dir_model_val and not _flag_in_argv(argv_tokens, "--model"):
        args.model = dir_model_val
    thresholds = manifest.get("thresholds") or {}
    args.phase2_manifest_thresholds = dict(thresholds) if isinstance(thresholds, Mapping) else {}
    use_manifest_flag = getattr(args, "phase2_use_manifest_thresholds", None)
    use_manifest = True if use_manifest_flag is None else bool(use_manifest_flag)
    if isinstance(thresholds, Mapping) and thresholds.get("p_setup") is not None:
        setattr(args, "phase2_manifest_p_setup", thresholds.get("p_setup"))
    setattr(args, "phase2_cli_p_setup_supplied", _flag_in_argv(argv_tokens, "--p_setup"))
    # IMPORTANT: p_setup controls Phase-2 setup gating and must follow the manifest when
    # manifest thresholds are enabled, even if a preset provides a default.
    if use_manifest and thresholds.get("p_setup") is not None and not _flag_in_argv(argv_tokens, "--p_setup"):
        setattr(args, "p_setup", thresholds.get("p_setup"))
        setattr(args, "phase2_p_setup_source", "phase2_tag")
    else:
        _maybe_manifest_override("p_setup", thresholds.get("p_setup"), "--p_setup")
    if use_manifest:
        # IMPORTANT: When manifest thresholds are enabled, p_long/p_short must follow the manifest
        # unless explicitly overridden on the CLI (even if a preset provided defaults).
        if thresholds.get("p_long") is not None and not _flag_in_argv(argv_tokens, "--p_long"):
            setattr(args, "p_long", thresholds.get("p_long"))
        else:
            _maybe_manifest_override("p_long", thresholds.get("p_long"), "--p_long")
        if thresholds.get("p_short") is not None and not _flag_in_argv(argv_tokens, "--p_short"):
            setattr(args, "p_short", thresholds.get("p_short"))
        else:
            _maybe_manifest_override("p_short", thresholds.get("p_short"), "--p_short")
    elif thresholds.get("p_long") is not None or thresholds.get("p_short") is not None:
        logger.info(
            "[PHASE2] manifest provides p_long/p_short but overrides are disabled "
            "(pass --no_phase2_use_manifest_thresholds to disable)."
        )
    config_block = manifest.get("config") or {}
    decision_policy = config_block.get("decision_policy") if isinstance(config_block, Mapping) else {}
    policy_obj = Phase2DecisionPolicy.from_mapping(decision_policy if isinstance(decision_policy, Mapping) else {})
    if not _flag_in_argv(argv_tokens, "--entry_trend_filter"):
        setattr(args, "entry_trend_filter", policy_obj.entry_trend_filter)
    if not _flag_in_argv(argv_tokens, "--min_signal_persistence_bars"):
        setattr(args, "min_signal_persistence_bars", int(policy_obj.min_signal_persistence_bars))
    if not _flag_in_argv(argv_tokens, "--cooldown_bars_after_flip"):
        setattr(args, "cooldown_bars_after_flip", int(policy_obj.cooldown_bars_after_flip))
    setattr(args, "phase2_decision_policy", policy_obj.to_manifest())
    _maybe_manifest_override("session_tz", config_block.get("tz"), "--session_tz")
    _maybe_manifest_override("trade_window_start", config_block.get("trade_window_start"), "--trade_window_start")
    _maybe_manifest_override("trade_window_end", config_block.get("trade_window_end"), "--trade_window_end")
    _maybe_manifest_override("rth_start", _coerce_time_str(config_block.get("rth_start")), "--rth_start")
    _maybe_manifest_override("rth_end", _coerce_time_str(config_block.get("rth_end")), "--rth_end")
    logger.info(
        "[PHASE2] manifest=%s tag=%s setup=%s dir=%s close=%s p_setup=%s p_long=%s p_short=%s close_threshold=%s",
        manifest_path,
        getattr(args, "phase2_tag", None),
        getattr(args, "setup_model_path", None),
        getattr(args, "dir_model_path", None) or dir_model_val,
        getattr(args, "close_model_path", None) or close_model_val,
        getattr(args, "p_setup", None),
        getattr(args, "p_long", None),
        getattr(args, "p_short", None),
        getattr(args, "phase2_close_threshold", None),
    )
    return args


def _log_effective_run_config(args: argparse.Namespace) -> Dict[str, Any]:
    phase2_enabled = bool(getattr(args, "phase2", False))
    preset_name = getattr(args, "preset", None)
    phase2_tag = getattr(args, "phase2_tag", None)
    contracts = float(getattr(args, "contracts", 1.0) or 1.0)
    if contracts <= 0:
        contracts = 1.0
    p_setup = float(getattr(args, "p_setup", 0.0) or 0.0) if phase2_enabled else None
    if phase2_enabled:
        p_long = float(getattr(args, "p_long", ENGINE.p_buy) or ENGINE.p_buy)
        p_short = float(getattr(args, "p_short", 1.0 - ENGINE.p_sell) or (1.0 - ENGINE.p_sell))
        eff_p_buy = p_long
        eff_p_sell = 1.0 - p_short
    else:
        p_long = float(getattr(args, "p_buy", ENGINE.p_buy) or ENGINE.p_buy)
        p_short = float(getattr(args, "p_sell", ENGINE.p_sell) or ENGINE.p_sell)
        eff_p_buy = p_long
        eff_p_sell = p_short
    payload = {
        "phase2": phase2_enabled,
        "phase2_tag": phase2_tag,
        "preset": preset_name,
        "contracts": float(contracts),
        "p_setup": p_setup,
        "p_long": p_long,
        "p_short": p_short,
        "p_buy": eff_p_buy,
        "p_sell": eff_p_sell,
        "tz": getattr(args, "session_tz", "America/Denver"),
        "window_start": getattr(args, "trade_window_start", "07:30"),
        "window_end": getattr(args, "trade_window_end", "12:00"),
    }
    setup_txt = f"{p_setup:.2f}" if (p_setup is not None) else "n/a"
    logger.info(
        "EFFECTIVE RUN CONFIG preset=%s phase2=%s tag=%s tz=%s window=%s-%s contracts=%.2f "
        "p_setup=%s p_long=%.2f p_short=%.2f p_buy=%.2f p_sell=%.2f",
        preset_name or "n/a",
        phase2_enabled,
        phase2_tag or "n/a",
        payload["tz"],
        payload["window_start"],
        payload["window_end"],
        payload["contracts"],
        setup_txt,
        p_long,
        p_short,
        eff_p_buy,
        eff_p_sell,
    )
    return payload


def _flag_in_argv(argv: Optional[Sequence[str]], flag: str) -> bool:
    if not argv:
        return False
    normalized = flag if flag.startswith("--") else f"--{flag}"
    for token in argv:
        if token == normalized or token.startswith(f"{normalized}="):
            return True
    return False


def _areas_from_computation(computation: Any, *, max_levels: int) -> List[AreaOfInterestLevel]:
    if computation is None:
        return []
    snapshot = getattr(computation, "snapshot", None)
    if snapshot is None:
        return []
    current_price = _safe_float(getattr(snapshot, "current_price", None))
    entries: List[Tuple[float, str, float, Optional[float]]] = []

    def register(label: str, raw_value: Any) -> None:
        value = _safe_float(raw_value)
        if value is None:
            return
        delta = None if current_price is None else (value - current_price)
        dist = abs(delta) if delta is not None else 0.0
        entries.append((dist, label, value, delta))

    register("Prior RTH High", getattr(snapshot, "prev_high", None))
    register("Prior RTH Low", getattr(snapshot, "prev_low", None))
    register("Prior Close (Gap Fill)", getattr(snapshot, "prev_close", None))
    register("Prior RTH VWAP", getattr(snapshot, "prev_session_vwap", None))

    overnight_high = _safe_float(getattr(snapshot, "overnight_high", None))
    overnight_low = _safe_float(getattr(snapshot, "overnight_low", None))
    register("Overnight High", overnight_high)
    register("Overnight Low", overnight_low)
    if overnight_high is not None and overnight_low is not None:
        register("Overnight Mid", (overnight_high + overnight_low) / 2.0)

    window = getattr(computation, "window", None)
    window_frame = getattr(window, "frame", None)
    if isinstance(window_frame, pd.DataFrame) and not window_frame.empty:
        try:
            volume_sum = float(window_frame["Volume"].sum())
            if volume_sum > 0.0:
                vwap = float((window_frame["Close"] * window_frame["Volume"]).sum() / volume_sum)
                register("Overnight VWAP", vwap)
        except Exception:
            pass

    local_df = getattr(computation, "dataframe", None)
    if isinstance(local_df, pd.DataFrame) and not local_df.empty:
        try:
            latest = local_df.index.max()
            window_start = latest - timedelta(hours=24)
            recent = local_df[local_df.index >= window_start]
            if not recent.empty:
                register("24h High", float(recent["High"].max()))
                register("24h Low", float(recent["Low"].min()))
        except Exception:
            pass

    if not entries:
        return []

    entries.sort(key=lambda item: (item[0], item[2]))
    limit = len(entries) if max_levels <= 0 else max(1, int(max_levels))
    seen: set[float] = set()
    areas: List[AreaOfInterestLevel] = []
    for _, label, price, delta in entries:
        key = round(price, 6)
        if key in seen:
            continue
        seen.add(key)
        areas.append(AreaOfInterestLevel(label=label, price=price, delta=delta))
        if len(areas) >= limit:
            break
    return areas


def _select_planner_target(config: Any, instrument_alias: str) -> Optional[Any]:
    alias = (instrument_alias or "").upper()
    config_inst = ""
    try:
        config_inst = (getattr(config, "instrument", "") or "").upper()
    except Exception:
        config_inst = ""
    if alias and config_inst == alias:
        return None
    targets = getattr(config, "targets", None)
    if not targets:
        return None
    for target in targets:
        try:
            target_inst = (getattr(target, "instrument", "") or config_inst or "").upper()
        except Exception:
            target_inst = config_inst
        if alias and target_inst == alias:
            return target
    return targets[0]


def _load_planner_areas(
    *,
    config_path: Optional[Path],
    instrument_alias: str,
    max_levels: int,
) -> Tuple[List[AreaOfInterestLevel], Optional[pd.Timestamp], Optional[float]]:
    if load_planner_config is None or generate_plan_payload is None:
        raise RuntimeError("premarket planner modules unavailable")
    cfg_path = str(config_path) if config_path is not None else None
    cfg = load_planner_config(cfg_path)
    target = _select_planner_target(cfg, instrument_alias)
    computation = generate_plan_payload(cfg, target)
    areas = _areas_from_computation(computation, max_levels=max_levels)
    snapshot = getattr(computation, "snapshot", None)
    snapshot_ts = getattr(snapshot, "last_update", None) if snapshot is not None else None
    current_price = None
    try:
        if snapshot is not None:
            current_price = float(getattr(snapshot, "current_price", None))
    except (TypeError, ValueError):
        current_price = None
    return areas, snapshot_ts, current_price


def calibrate_proba(p_raw: np.ndarray, calibrator: Optional[Any]) -> np.ndarray:
    """Apply calibrator if present; otherwise identity."""
    if calibrator is None:
        return np.asarray(p_raw, dtype=float).ravel()

    x = np.asarray(p_raw, dtype=float).reshape(-1, 1)
    try:
        if hasattr(calibrator, "predict_proba"):
            p = np.asarray(calibrator.predict_proba(x))
            return p[:, 1] if p.ndim == 2 and p.shape[1] >= 2 else p.ravel()
        if hasattr(calibrator, "predict"):
            p = np.asarray(calibrator.predict(x)).ravel()
            # If it's a hard classifier, map {0,1} to probs directly
            if set(np.unique(p)) <= {0.0, 1.0}:
                return p
            # Otherwise assume it's a logit-style score
            return 1.0 / (1.0 + np.exp(-p))
        if hasattr(calibrator, "transform"):
            p = np.asarray(calibrator.transform(x)).ravel()
            return p
    except Exception as e:
        logger.debug(f"calibrate_proba fallback due to {e}")

    return np.asarray(p_raw, dtype=float).ravel()


_ALIGNMENT_WARNINGS: Dict[str, bool] = {}
_PHASE2_LABEL_EXPECTATIONS = {
    "setup": {0: ("FLAT",), 1: ("TRADE",)},
    "direction": {0: ("SHORT",), 1: ("LONG",)},
    "close": {0: ("HOLD",), 1: ("CLOSE",)},
}
_GATE_PRIORITY = ("tod", "risk", "setup", "prob", "vwap", "ema")


def _drop_leak_prone_columns(X: pd.DataFrame) -> pd.DataFrame:
    drop_exact = {"Open", "High", "Low", "Close", "Volume"}
    suspicious = ("follow", "future", "lead", "ahead", "fwd")
    safe_sus = {"hi_break_follow", "lo_break_follow"}
    cols: List[str] = []
    for col in X.columns:
        if col in drop_exact:
            continue
        lc = str(col).lower()
        if col not in safe_sus and any(token in lc for token in suspicious):
            continue
        cols.append(col)
    return X[cols]


def _align_X(
    feats: pd.DataFrame,
    feature_names: Optional[Sequence[str]],
    *,
    warn_context: str = "model",
    strict: bool = False,
) -> Tuple[pd.DataFrame, List[str]]:
    numeric = feats.select_dtypes(include=[np.number, "bool"]).astype(float)
    if feature_names is None:
        filtered = _drop_leak_prone_columns(numeric)
        return filtered, list(filtered.columns)
    if _FEATURE_GUARD_AVAILABLE:
        mandatory = set(MANDATORY_MODEL_FEATURES)
        silent_zeros = [str(name) for name in feature_names if str(name) not in numeric.columns and str(name) in mandatory]
        if silent_zeros:
            raise FeatureMismatchError(
                f"_align_X would silently zero-fill {len(silent_zeros)} model-required feature(s): {silent_zeros}"
            )
    else:
        logger.error(
            "_align_X hard guard disabled — feature constants not importable. "
            "Missing model features will be silently zero-filled."
        )
    missing: List[str] = []
    for name in feature_names:
        if name not in numeric.columns:
            numeric[name] = 0.0
            missing.append(str(name))
    if missing and not _ALIGNMENT_WARNINGS.get(warn_context):
        display = ", ".join(missing[:12])
        if len(missing) > 12:
            display = f"{display} (+{len(missing) - 12} more)"
        logger.warning(
            "Missing %d feature(s) required for %s; filled with 0.0 -> %s",
            len(missing),
            warn_context,
            display,
        )
        _ALIGNMENT_WARNINGS[warn_context] = True
        if strict:
            short_list = ", ".join(missing[:20])
            if len(missing) > 20:
                short_list = f"{short_list} (+{len(missing) - 20} more)"
            raise RuntimeError(f"{warn_context} missing features: {short_list}")
    ordered = numeric[list(feature_names)]
    if strict and ordered.shape[1] == 0:
        raise RuntimeError(f"{warn_context} alignment produced 0 columns.")
    return ordered, list(feature_names)


def _align_X_for_model(feats: pd.DataFrame, feature_names: Optional[List[str]]) -> Tuple[pd.DataFrame, List[str]]:
    return _align_X(feats, feature_names, warn_context="model")


def _phase2_label_mapping(schema_path: Path) -> Dict[int, str]:
    try:
        payload = json.loads(schema_path.read_text(encoding="utf-8"))
    except FileNotFoundError as exc:
        raise RuntimeError(f"Phase-2 label schema missing: {schema_path}") from exc
    except Exception as exc:
        raise RuntimeError(f"Phase-2 label schema at {schema_path} is not valid JSON: {exc}") from exc
    mapping_obj: Optional[Mapping[Any, Any]] = None
    params = payload.get("params")
    if isinstance(params, Mapping):
        maybe = params.get("mapping")
        if isinstance(maybe, Mapping):
            mapping_obj = maybe
    if mapping_obj is None:
        maybe = payload.get("mapping")
        if isinstance(maybe, Mapping):
            mapping_obj = maybe
    if mapping_obj is None:
        raise RuntimeError(f"Phase-2 label schema at {schema_path} does not define params.mapping.")
    mapping: Dict[int, str] = {}
    for key, value in mapping_obj.items():
        try:
            idx = int(key)
        except Exception:
            continue
        mapping[idx] = str(value).strip().upper()
    return mapping


def _validate_phase2_label_schema(schema_path: Path, *, role: str) -> None:
    expected = _PHASE2_LABEL_EXPECTATIONS[role]
    mapping = _phase2_label_mapping(schema_path)
    if len(mapping) != len(expected):
        raise RuntimeError(
            f"Phase-2 {role} label schema at {schema_path} expected {len(expected)} classes but found {len(mapping)}."
        )
    for idx, allowed in expected.items():
        label = mapping.get(idx)
        if label is None:
            raise RuntimeError(f"Phase-2 {role} label schema at {schema_path} missing class index {idx}.")
        if label not in allowed:
            allowed_txt = " or ".join(allowed)
            raise RuntimeError(
                f"Phase-2 {role} label schema at {schema_path} expected class {idx}={allowed_txt}, found '{label}'."
            )


def _predict_proba_safely(
    model: Any,
    X: pd.DataFrame,
    *,
    meta: Optional[dict[str, Any]] = None,
    model_path: Optional[str | Path] = None,
    ) -> np.ndarray:
    def _disable_xgb_feature_validation(obj: Any, *, max_depth: int = 4) -> None:
        if max_depth <= 0 or obj is None:
            return
        try:
            get_booster = getattr(obj, "get_booster", None)
            if callable(get_booster):
                try:
                    booster = get_booster()
                except Exception:
                    booster = None
                if booster is not None:
                    try:
                        setattr(booster, "feature_names", None)
                    except Exception:
                        pass
                    try:
                        setattr(booster, "feature_types", None)
                    except Exception:
                        pass
        except Exception:
            pass
        # CalibratedClassifierCV and other wrappers can hide the underlying estimator(s).
        for attr in ("estimator", "base_estimator", "model", "clf", "classifier"):
            try:
                child = getattr(obj, attr, None)
            except Exception:
                child = None
            if child is not None and child is not obj:
                _disable_xgb_feature_validation(child, max_depth=max_depth - 1)
        for attr in ("estimators_", "calibrated_classifiers_", "models_", "pipelines_"):
            try:
                children = getattr(obj, attr, None)
            except Exception:
                children = None
            if isinstance(children, (list, tuple)):
                for child in children:
                    if child is not None and child is not obj:
                        _disable_xgb_feature_validation(child, max_depth=max_depth - 1)

    def _sigmoid(z: np.ndarray) -> np.ndarray:
        z = np.asarray(z, dtype=float)
        z = np.clip(z, -50, 50)
        return 1.0 / (1.0 + np.exp(-z))

    def _proba_from_model(M: Any, D: pd.DataFrame) -> np.ndarray:
        meta_info = meta
        if meta_info is None:
            meta_info = getattr(M, "_na_meta", None)
        if is_train_v2_bundle(M, meta_info):
            return predict_train_v2_bundle_proba(M, D)
        if hasattr(M, "predict_proba"):
            prob = M.predict_proba(D)
            return select_long_proba(prob, M, meta=meta_info, model_path=model_path)
        if hasattr(M, "decision_function"):
            scores = np.asarray(M.decision_function(D), dtype=float)
            return _sigmoid(scores)
        pred = M.predict(D)
        arr = np.asarray(pred, dtype=float)
        classes = getattr(M, "classes_", None)
        if classes is not None:
            idx = ensure_long_index(M, meta=meta_info, model_path=model_path)
            try:
                classes_list = list(classes)
                long_code = classes_list[int(idx)]
                return (arr == long_code).astype(float)
            except Exception:
                pass
        if np.nanmax(arr) > 1.2 or np.nanmin(arr) < -0.2:
            return _sigmoid(arr)
        return arr

    try:
        raw = _proba_from_model(model, X)
    except Exception as exc:
        msg = str(exc)
        # XGBoost >=2 can enforce feature-name matching; some sklearn wrappers (notably CalibratedClassifierCV)
        # can drop names internally, causing hard failures even when we already aligned columns.
        # _disable_xgb_feature_validation() only suppresses the model's internal name check — it does NOT
        # bypass the upstream _align_X feature guard which has already verified column presence.
        # Log at WARNING so this path is visible in production; frequent hits indicate a schema drift risk.
        if "did not contain feature names" in msg and "expected" in msg:
            try:
                logger.warning(
                    "_predict_proba_safely: XGBoost feature-name mismatch from sklearn wrapper; "
                    "disabling internal XGBoost name check and retrying. "
                    "This is a CalibratedClassifierCV/XGBoost >=2 compatibility shim — if you see this "
                    "repeatedly, verify that model and feature schema are in sync. error=%s", msg
                )
                _disable_xgb_feature_validation(model)
                raw = _proba_from_model(model, X)
            except Exception:
                pass
        if "raw" not in locals():
            X2 = X.replace([np.inf, -np.inf], np.nan).fillna(0.0)
            try:
                raw = _proba_from_model(model, X2)
            except Exception as exc2:
                msg2 = str(exc2)
                if "did not contain feature names" in msg2 and "expected" in msg2:
                    logger.warning(
                        "_predict_proba_safely: XGBoost feature-name mismatch on NaN-filled fallback; "
                        "disabling internal name check. error=%s", msg2
                    )
                    _disable_xgb_feature_validation(model)
                    raw = _proba_from_model(model, X2)
                else:
                    raise
    prob = np.asarray(raw, dtype=float)
    if prob.ndim >= 2:
        prob = select_long_proba(prob, model, meta=meta, model_path=model_path)
    return np.clip(prob, 0.0, 1.0)


def _select_long_probability(
    p_raw: np.ndarray,
    model: Any,
    model_path: str | Path,
) -> np.ndarray:
    """Project raw predict_proba output to P(LONG).
    - If binary and model.classes_ contains 1 â†’ use that column.
    - If multiclass, prefer meta sidecar proba_code or class_names mapping to LONG.
    - Fallback: if classes_ contains 2 â†’ take that column; else last column.
    """
    arr = np.asarray(p_raw)
    if arr.ndim == 1:
        return arr
    if arr.ndim == 2 and arr.shape[1] == 2:
        try:
            if hasattr(model, "classes_") and 1 in list(model.classes_):
                idx = int(np.where(np.asarray(model.classes_) == 1)[0][0])
                return arr[:, idx]
        except Exception:
            pass
        return arr[:, 1]

    # Multiclass
    # Inspect meta
    meta_idx = None
    try:
        pth = Path(model_path)
        try:
            meta = pth.with_suffix(".meta.json")
        except ValueError:
            meta = pth.parent / (pth.name + ".meta.json")
        if meta.exists():
            js = json.loads(meta.read_text())
            if isinstance(js.get("proba_code"), (int, float)):
                proba_code = int(js["proba_code"])
                if hasattr(model, "classes_"):
                    classes = list(getattr(model, "classes_"))
                    if proba_code in classes:
                        meta_idx = int(np.where(np.asarray(classes) == proba_code)[0][0])
            elif isinstance(js.get("class_names"), list) and hasattr(model, "classes_"):
                names = [str(x).upper() for x in js["class_names"]]
                if "LONG" in names:
                    long_pos = names.index("LONG")
                    # classes_ are codes aligned to names order
                    meta_idx = long_pos
    except Exception:
        meta_idx = None

    if meta_idx is not None and 0 <= meta_idx < arr.shape[1]:
        return arr[:, int(meta_idx)]

    try:
        classes = list(getattr(model, "classes_")) if hasattr(model, "classes_") else []
        if 2 in classes:
            idx = int(np.where(np.asarray(classes) == 2)[0][0])
            return arr[:, idx]
    except Exception:
        pass
    # Fallback to last column
    return arr[:, -1]


@dataclass(frozen=True)
class ShadowCandidateSpec:
    model_path: str
    model_id: Optional[str] = None


@dataclass
class _ShadowTrade:
    side: str
    entry_price: float
    stop: Optional[float]
    target: Optional[float]
    timestamp: pd.Timestamp
    features: Tuple[float, ...]
    entry_prob: float
    size: float = 1.0


class ShadowRiskManager:
    def __init__(self, preset: Optional[RiskPresetConfig], session_tz: str) -> None:
        self.preset = preset
        self.session_tz = session_tz or DENVER_TZ
        self.max_trades = int(getattr(preset, "max_trades_per_session", 0) or 0) if preset else 0
        self.trade_window_start = self._parse_time(getattr(preset, "trade_window_start", "07:30"))
        self.trade_window_end = self._parse_time(getattr(preset, "trade_window_end", "13:00"))
        self._last_date: Optional[dt_type.date] = None
        self._trades_today = 0

    @staticmethod
    def _parse_time(value: str) -> dtime:
        parsed = _parse_time_value(value)
        if parsed is None:
            return dtime(0, 0)
        return parsed

    def _local_time(self, ts: pd.Timestamp) -> Tuple[dt_type.date, dtime]:
        try:
            tz = ZoneInfo(self.session_tz)
        except Exception:
            tz = None
        dt_val = ts
        if tz is not None:
            if dt_val.tzinfo is None:
                dt_val = dt_val.replace(tzinfo=tz)
            else:
                dt_val = dt_val.astimezone(tz)
        local_date = dt_val.date()
        local_time = dt_val.timetz().replace(tzinfo=None)
        return local_date, local_time

    def allow_entry(self, ts: pd.Timestamp) -> bool:
        if self.preset is None:
            return True
        local_date, local_time = self._local_time(ts)
        if self._last_date != local_date:
            self._last_date = local_date
            self._trades_today = 0
        if self.max_trades > 0 and self._trades_today >= self.max_trades:
            return False
        start = self.trade_window_start
        end = self.trade_window_end
        if start < end and not (start <= local_time <= end):
            return False
        return True

    def record_entry(self) -> None:
        if self.preset is None:
            return
        self._trades_today += 1


class ShadowCandidateRunner:
    def __init__(
        self,
        *,
        spec: ShadowCandidateSpec,
        instrument: str,
        point_value: float,
        tick_size: float,
        session_tz: str,
        p_buy: float,
        p_sell: float,
        trade_window_start: str,
        trade_window_end: str,
        preset_name: str,
        risk_preset: Optional[RiskPresetConfig],
        writer: ExperienceWriter,
        champion_model_id: Optional[str],
        shadow_run_id: str,
    ) -> None:
        self.spec = spec
        self.instrument = instrument
        self.point_value = point_value
        self.tick_size = tick_size
        self.session_tz = session_tz
        self.p_buy = p_buy
        self.p_sell = p_sell
        self.trade_window_start = trade_window_start
        self.trade_window_end = trade_window_end
        self.preset_name = preset_name or ""
        self.writer = writer
        self.champion_model_id = champion_model_id
        self.shadow_run_id = shadow_run_id
        self._open_trade: Optional[_ShadowTrade] = None
        self._trade_seq = 0
        self._enabled = True
        self._candidate_id = spec.model_id or Path(spec.model_path).stem
        self._model_sha: Optional[str] = None
        self.risk_manager = ShadowRiskManager(risk_preset, session_tz)
        self._init_models()
        self._init_engine()

    def _init_models(self) -> None:
        try:
            model, feature_names, calibrator, meta = load_model_features_and_calibrator(self.spec.model_path)
        except Exception as exc:
            logger.error("Shadow candidate %s failed to load: %s", self.spec.model_path, exc)
            self._enabled = False
            return
        self.model = model
        self.expected_features = list(feature_names) if feature_names is not None else None
        self.calibrator = calibrator
        self.model_meta = meta
        try:
            self._model_sha = compute_sha256(Path(self.spec.model_path))
        except Exception:
            self._model_sha = None

    def _init_engine(self) -> None:
        if TransitionEngine is None or TransitionConfig is None or Instrument is None:
            self.engine = None
            return
        try:
            cfg = TransitionConfig(
                p_buy=self.p_buy,
                p_sell=self.p_sell,
                session_tz=self.session_tz,
                trade_window_start=self.trade_window_start,
                trade_window_end=self.trade_window_end,
                prob_bands_long=PROB_BANDS.get("long", {"A+": 0.60, "B+": 0.55}),
                prob_bands_short=PROB_BANDS.get("short", {"A+": 0.40, "B+": 0.45}),
                atr_k=float(RISK_DEFAULTS.get("atr_k", 2.0) or 2.0),
                    max_bars_in_trade=int(RISK_DEFAULTS.get("max_bars_in_trade", 20) or 20),
                fallback_stop_pct=float(RISK_DEFAULTS.get("fallback_stop_pct", 0.0035) or 0.0035),
            )
            inst = Instrument(
                alias=self.instrument,
                point_value=float(self.point_value),
                tick_size=float(self.tick_size),
            )
            self.engine = TransitionEngine(cfg, inst)
        except Exception as exc:
            logger.warning("Shadow candidate %s failed to init TransitionEngine: %s", self.spec.model_path, exc)
            self.engine = None

    @property
    def enabled(self) -> bool:
        return self._enabled

    def process_rows(self, feats: pd.DataFrame, feature_cols: List[str]) -> None:
        if not self.enabled or feats.empty:
            return
        frame = feats.set_index("Datetime")
        X, _ = _align_X_for_model(frame, self.expected_features)
        try:
            probs_raw = _predict_proba_safely(
                self.model,
                X,
                meta=self.model_meta,
                model_path=self.spec.model_path,
            )
            probs = calibrate_proba(probs_raw, self.calibrator)
        except Exception as exc:
            logger.debug("Shadow candidate %s failed to score: %s", self.spec.model_path, exc)
            return
        prob_arr = np.asarray(probs, dtype=float).reshape(-1)
        feature_vectors = X.to_numpy(copy=False)
        total = min(len(feats), len(prob_arr))
        for idx in range(total):
            row = feats.iloc[idx].copy()
            prob_val = float(prob_arr[idx])
            row["proba"] = prob_val
            ts_dt = _ensure_denver_naive(row["Datetime"])
            if ts_dt is None:
                continue
            events = self._generate_events(row, feature_cols)
            features_vec: Tuple[float, ...] = ()
            if idx < len(feature_vectors):
                try:
                    features_vec = tuple(float(x) for x in feature_vectors[idx].tolist())
                except Exception:
                    features_vec = tuple()
            for ev in events:
                self._handle_event(ev=ev, ts=ts_dt, prob=prob_val, row=row, features=features_vec)

    def _generate_events(self, row: pd.Series, feature_cols: List[str]) -> List[Dict[str, Any]]:
        events: List[Dict[str, Any]] = []
        if self.engine is not None:
            try:
                erow = _engine_row_from_series(row, self.instrument, feature_cols)
                raw = self.engine.step(erow) or []
                for ev in raw:
                    converted = self._convert_engine_event(ev)
                    if converted:
                        events.append(converted)
            except Exception as exc:
                logger.debug("Shadow engine step failed: %s", exc)
        if not events:
            events.extend(self._fallback_events(row))
        return events

    def _fallback_events(self, row: pd.Series) -> List[Dict[str, Any]]:
        events: List[Dict[str, Any]] = []
        price = float(row.get("Close", np.nan))
        if not np.isfinite(price):
            return events
        prob = float(row.get("proba", np.nan))
        desired = 1 if prob >= self.p_buy else (-1 if prob <= self.p_sell else 0)
        if desired == 0 and self._open_trade is not None:
            events.append({
                "type": "CLOSE",
                "side": self._open_trade.side,
                "price": price,
                "prob": prob,
                "risk": {"stop": self._open_trade.stop, "target": self._open_trade.target},
            })
            return events
        if desired == 0:
            return events
        side = "LONG" if desired > 0 else "SHORT"
        stop = price - (self.tick_size * 8) if desired > 0 else price + (self.tick_size * 8)
        events.append({
            "type": "OPEN" if self._open_trade is None else "FLIP",
            "side": side,
            "price": price,
            "prob": prob,
            "risk": {"stop": stop, "target": None},
        })
        return events

    @staticmethod
    def _convert_engine_event(ev: Any) -> Optional[Dict[str, Any]]:
        if isinstance(ev, dict):
            action = str(ev.get("action") or ev.get("type") or "").upper()
            if action not in ("OPEN", "FLIP", "CLOSE"):
                return None
            return {
                "type": action,
                "side": str(ev.get("side") or "").upper(),
                "price": ev.get("entry") or ev.get("price"),
                "prob": ev.get("prob"),
                "risk": (ev.get("risk") if isinstance(ev.get("risk"), dict) else {"stop": ev.get("stop"), "target": ev.get("target")}),
            }
        action = str(getattr(ev, "action", "") or getattr(ev, "type", "")).upper()
        if action not in ("OPEN", "FLIP", "CLOSE"):
            return None
        return {
            "type": action,
            "side": str(getattr(ev, "side", "")).upper(),
            "price": getattr(ev, "entry", None) or getattr(ev, "price", None),
            "prob": getattr(ev, "prob", None),
            "risk": {"stop": getattr(ev, "stop", None), "target": getattr(ev, "target", None)},
        }

    def _handle_event(
        self,
        *,
        ev: Dict[str, Any],
        ts: pd.Timestamp,
        prob: float,
        row: pd.Series,
        features: Tuple[float, ...],
    ) -> None:
        typ = str(ev.get("type") or "").upper()
        side = str(ev.get("side") or "").upper()
        price_val = ev.get("price")
        try:
            price = float(price_val)
        except (TypeError, ValueError):
            price = float(row.get("Close", np.nan))
        if not np.isfinite(price):
            return
        if typ in ("OPEN", "FLIP"):
            if not self.risk_manager.allow_entry(ts):
                return
            if typ == "FLIP" and self._open_trade is not None:
                self._record_exit(ts, price, prob, features)
            self._open_trade = _ShadowTrade(
                side=side or "LONG",
                entry_price=price,
                stop=(ev.get("risk") or {}).get("stop"),
                target=(ev.get("risk") or {}).get("target"),
                timestamp=ts,
                features=features,
                entry_prob=prob,
            )
            self.risk_manager.record_entry()
        elif typ == "CLOSE" and self._open_trade is not None:
            self._record_exit(ts, price, prob, features)

    def _record_exit(self, ts: pd.Timestamp, price: float, prob: float, features: Tuple[float, ...]) -> None:
        if self._open_trade is None:
            return
        trade = self._open_trade
        self._trade_seq += 1
        self._open_trade = None
        entry_price = trade.entry_price
        stop = trade.stop if trade.stop is not None else entry_price
        risk = abs(entry_price - float(stop))
        r_multiple = 0.0
        if risk > 1e-9:
            if trade.side == "LONG":
                r_multiple = (price - entry_price) / risk
            else:
                r_multiple = (entry_price - price) / risk
        pnl = r_multiple * risk * self.point_value
        trade_id = f"shadow-{self._candidate_id}-{self._trade_seq}"
        metadata = {
            "mode": "shadow",
            "champion_model_id": self.champion_model_id,
            "candidate_model_id": self._candidate_id,
            "shadow_run_id": self.shadow_run_id,
            "candidate_model_path": self.spec.model_path,
            "candidate_model_sha": self._model_sha,
            "entry_prob": trade.entry_prob,
            "exit_prob": prob,
        }
        exp = Experience(
            trade_id=trade_id,
            instrument=self.instrument,
            strategy="shadow",
            preset=self.preset_name,
            model_run_id=self._candidate_id,
            timestamp=ts.to_pydatetime(),
            side=trade.side,
            qty=trade.size,
            entry_price=entry_price,
            exit_price=price,
            pnl=float(pnl),
            r_multiple=float(r_multiple),
            base_r_multiple=float(r_multiple),
            features=trade.features,
            risk_flags=("shadow",),
            metadata=metadata,
        )
        try:
            self.writer.append(exp)
        except Exception:
            logger.debug("Failed to append shadow experience %s", trade_id, exc_info=True)


class ShadowController:
    def __init__(
        self,
        *,
        enabled: bool,
        specs: Sequence[ShadowCandidateSpec],
        experience_dir: Path,
        pattern: str,
        instrument: str,
        point_value: float,
        tick_size: float,
        session_tz: str,
        p_buy: float,
        p_sell: float,
        trade_window_start: str,
        trade_window_end: str,
        preset_name: str,
        risk_preset: Optional[RiskPresetConfig],
        champion_model_id: Optional[str],
        shadow_run_id: str,
    ) -> None:
        self.enabled = bool(enabled)
        self.instrument = instrument
        self.shadow_run_id = shadow_run_id
        self.writer = ExperienceWriter(experience_dir, instrument, pattern)
        self.runners: List[ShadowCandidateRunner] = []
        if not self.enabled:
            return
        for spec in specs:
            if not spec.model_path:
                continue
            try:
                runner = ShadowCandidateRunner(
                    spec=spec,
                    instrument=instrument,
                    point_value=point_value,
                    tick_size=tick_size,
                    session_tz=session_tz,
                    p_buy=p_buy,
                    p_sell=p_sell,
                    trade_window_start=trade_window_start,
                    trade_window_end=trade_window_end,
                    preset_name=preset_name,
                    risk_preset=risk_preset,
                    writer=self.writer,
                    champion_model_id=champion_model_id,
                    shadow_run_id=shadow_run_id,
                )
            except Exception as exc:
                logger.warning("Failed to init shadow runner for %s: %s", spec.model_path, exc)
                continue
            if runner.enabled:
                self.runners.append(runner)
        if not self.runners:
            self.enabled = False

    def process_rows(self, feats: pd.DataFrame, feature_cols: List[str]) -> None:
        if not self.enabled or not self.runners or feats.empty:
            return
        for runner in self.runners:
            runner.process_rows(feats, feature_cols)


# ----------------------------- status line ------------------------------
def _should_invert_from_meta(model_fp: Path) -> bool:
    """If <model>.meta.json says probas represent SHORT, auto flip to LONG."""
    try:
        meta = Path(model_fp).with_suffix(".meta.json")
        if meta.exists():
            js = json.loads(meta.read_text())
            flag = str(js.get("proba_class", "")).strip().upper()
            return flag == "SHORT"
    except Exception:
        pass
    return False


class StatusPrinter:
    """One-line ticker that overwrites the same console line."""
    def __init__(self, enabled: bool = False, width: int = 140) -> None:
        self.enabled = bool(enabled)
        self.width = int(width)
        self.last_len = 0
        self.is_tty = sys.stdout.isatty()

    def write(self, s: str) -> None:
        if not self.enabled:
            return
        msg = " ".join(str(s).split())
        if self.is_tty:
            if len(msg) > self.width:
                msg = msg[: self.width - 1] + "â€¦"
            pad = " " * max(0, self.last_len - len(msg))
            sys.stdout.write("\r" + msg + pad)
            sys.stdout.flush()
            self.last_len = len(msg)
        else:
            print(msg)

    def done(self) -> None:
        if self.enabled and self.is_tty:
            sys.stdout.write("\n")
            sys.stdout.flush()
            self.last_len = 0


