BASE_COLS = ["Datetime", "Open", "High", "Low", "Close", "Volume"]
DEFAULT_EXPLANATIONS_PATH = Path("runs") / "live" / "explanations.jsonl"
DENVER_TZ = "America/Denver"
_DEFAULT_AUTO_INGEST_CSV = Path("data") / "intraday" / "es" / "ES.csv"

class _PriceBarsCsvEmitter:
    def __init__(self, path: Path) -> None:
        self.path = Path(path).expanduser().resolve()
        self.path.parent.mkdir(parents=True, exist_ok=True)
        self._header_written = self.path.exists() and self.path.stat().st_size > 0
        self._last_ts: Optional[str] = None
        self._prime_last_ts()

    def _prime_last_ts(self) -> None:
        try:
            if not self.path.exists() or self.path.stat().st_size <= 0:
                return
            with self.path.open("rb") as fh:
                fh.seek(0, os.SEEK_END)
                size = fh.tell()
                if size <= 0:
                    return
                read_size = min(size, 16 * 1024)
                fh.seek(size - read_size, os.SEEK_SET)
                tail = fh.read(read_size).decode("utf-8", errors="ignore")
            lines = [ln.strip() for ln in tail.splitlines() if ln.strip()]
            if not lines:
                return
            for ln in reversed(lines):
                if ln.lower().startswith("datetime,"):
                    continue
                ts = ln.split(",", 1)[0].strip()
                if ts:
                    self._last_ts = ts
                    return
        except Exception:
            return

    def append_row(
        self,
        *,
        ts_raw: str,
        instrument: str,
        open_px: float,
        high_px: float,
        low_px: float,
        close_px: float,
        volume: float,
    ) -> None:
        ts_key = str(ts_raw or "")
        if not ts_key:
            return
        if self._last_ts == ts_key:
            return
        self._last_ts = ts_key
        import csv as _csv

        write_header = not self._header_written
        with self.path.open("a", newline="", encoding="utf-8") as handle:
            writer = _csv.writer(handle)
            if write_header:
                writer.writerow(["Datetime", "Open", "High", "Low", "Close", "Volume", "Instrument"])
                self._header_written = True
            writer.writerow([ts_key, open_px, high_px, low_px, close_px, volume, instrument])


def _timeframe_from_bar_interval_sec(bar_interval_sec: int) -> str:
    interval = int(bar_interval_sec or 0)
    if interval <= 0:
        return "5m"
    if interval % 3600 == 0:
        return f"{interval // 3600}h"
    if interval % 60 == 0:
        return f"{interval // 60}m"
    return f"{interval}s"


def _now_denver() -> pd.Timestamp:
    return pd.Timestamp.now(tz=DENVER_TZ)

def utc_ts() -> str:
    # Normalized execution-layer timestamp (America/Denver) for logs/records.
    return _now_denver().isoformat()

def _now_wall() -> pd.Timestamp:
    # OS wall-clock timestamp with local timezone/offset.
    return pd.Timestamp(dt_type.now().astimezone())

def wall_ts() -> str:
    # Timestamp formatted to match the operator PC clock (local timezone/offset).
    return _now_wall().isoformat()


def _canonical_ts(ts: Any) -> Optional[pd.Timestamp]:
    """Return tz-aware timestamp in America/Denver."""
    if ts is None:
        return None
    try:
        parsed = pd.to_datetime(ts)
    except Exception:
        return None
    if pd.isna(parsed):
        return None
    try:
        if parsed.tzinfo is None:
            return parsed.tz_localize(DENVER_TZ)
        return parsed.tz_convert(DENVER_TZ)
    except Exception:
        return None


def _canonical_ts_str(ts: Any) -> str:
    """Formatted ISO-8601 with timezone; falls back to America/Denver if conversion fails."""
    den = _canonical_ts(ts)
    if den is None:
        try:
            return pd.Timestamp(ts).tz_localize(DENVER_TZ).isoformat()
        except Exception:
            return pd.Timestamp.now(tz=DENVER_TZ).isoformat()
    return den.isoformat()


def _epoch_to_denver_iso(val: Any) -> str:
    if val is None or val == "":
        return ""
    try:
        return (
            dt_type.fromtimestamp(float(val), tz=timezone.utc)
            .astimezone(ZoneInfo(DENVER_TZ))
            .isoformat()
        )
    except Exception:
        return _canonical_ts_str(val) or ""


class _AutoMysqlIngestor:
    def __init__(
        self,
        *,
        path: Path,
        source_name: Optional[str],
        interval_sec: float,
        error_threshold: int,
        ingest_runs: bool = True,
        skip_zip_duplicates: bool = True,
        force: bool = False,
        price_bars_csv: Optional[str],
        price_bars_instrument: Optional[str],
        price_bars_timeframe: Optional[str] = None,
        price_bars_timezone: Optional[str] = None,
        price_bars_timeframe_sec: Optional[int] = None,
    ) -> None:
        self.path = Path(path).expanduser().resolve()
        self.source_name = source_name
        self.interval_sec = max(5.0, float(interval_sec or 0.0))
        self.min_interval_sec = min(5.0, self.interval_sec)
        self.error_threshold = int(error_threshold)
        self.ingest_runs = bool(ingest_runs)
        self.skip_zip_duplicates = bool(skip_zip_duplicates)
        self.force = bool(force)
        self.price_bars_csv = str(price_bars_csv) if price_bars_csv else None
        self.price_bars_instrument = str(price_bars_instrument) if price_bars_instrument else None
        self.price_bars_timeframe = str(price_bars_timeframe) if price_bars_timeframe else None
        self.price_bars_timezone = str(price_bars_timezone) if price_bars_timezone else None
        self.price_bars_timeframe_sec = int(price_bars_timeframe_sec) if price_bars_timeframe_sec else None
        self._stop = threading.Event()
        self._dirty = threading.Event()
        self._thread: Optional[threading.Thread] = None
        self._disabled = False
        self._bars_stat: Optional[Tuple[float, int]] = None
        self._repo_root = Path(__file__).resolve().parents[4]
        self._last_ingest_mono: Optional[float] = None
        self._loop = None

    def notify_dirty(self) -> None:
        if self._disabled:
            return
        self._dirty.set()

    def start(self) -> None:
        if self._thread is not None or self._disabled:
            return
        self._thread = threading.Thread(target=self._run, name="auto-mysql-ingest", daemon=True)
        self._thread.start()

    def stop(self) -> None:
        if self._thread is None:
            return
        self._stop.set()
        self._thread.join(timeout=10.0)
        self._thread = None

    def _run(self) -> None:
        while not self._stop.is_set():
            # Wait for either a timer tick or a "dirty" notification from the streamer.
            fired = self._dirty.wait(self.interval_sec)
            if self._stop.is_set():
                break
            if fired:
                self._dirty.clear()
                now = time.monotonic()
                if self._last_ingest_mono is not None:
                    elapsed = now - self._last_ingest_mono
                    if elapsed < self.min_interval_sec:
                        self._stop.wait(self.min_interval_sec - elapsed)
                        if self._stop.is_set():
                            break
            self._run_once()

        # Final ingest on shutdown.
        self._run_once()

    def _run_once(self) -> None:
        if self._disabled:
            return
        try:
            if not self.path.exists():
                return

            if self.ingest_runs:
                summary = self._run_backend_ingest_zip(path=self.path, source_name=self.source_name or self.path.name)
                if summary is not None:
                    logger.info(
                        "Auto-ingest ok path=%s ingested=%s skipped=%s errors=%s batch_id=%s",
                        self.path,
                        summary.get("files_ingested", None),
                        summary.get("files_skipped", None),
                        summary.get("errors", None),
                        summary.get("batch_id", None),
                    )
            self._maybe_ingest_price_bars()
            self._last_ingest_mono = time.monotonic()
        except Exception as exc:
            logger.warning("Auto-ingest failed for %s: %s", self.path, exc)

    def _backend_cli(self) -> Optional[Path]:
        backend_root = self._repo_root / "backend"
        ts_cli = backend_root / "src" / "cli.ts"
        tsx = backend_root / "node_modules" / "tsx" / "dist" / "cli.mjs"
        if ts_cli.exists() and tsx.exists():
            return ts_cli
        js_cli = backend_root / "dist" / "cli.js"
        if js_cli.exists():
            return js_cli
        return None

    def _run_backend_ingest_zip(self, *, path: Path, source_name: str) -> Optional[dict]:
        # Canonical: use the Node backend ingestion (core schema) to avoid writing into
        # premarket_charts/diag_* tables and to keep ingestion behavior consistent.
        backend_root = self._repo_root / "backend"
        cli = self._backend_cli()
        if cli is None:
            logger.warning("Auto-ingest disabled: backend ingest CLI not found under %s", backend_root)
            self._disabled = True
            return None

        default_instrument = self.price_bars_instrument
        default_timeframe_sec = self.price_bars_timeframe_sec
        extra_defaults: list[str] = []
        if default_instrument:
            extra_defaults += ["--instrument", str(default_instrument)]
        if default_timeframe_sec:
            extra_defaults += ["--timeframeSec", str(int(default_timeframe_sec))]

        if cli.suffix.lower() == ".ts":
            tsx = backend_root / "node_modules" / "tsx" / "dist" / "cli.mjs"
            cmd = [
                "node",
                str(tsx),
                str(cli),
                "--zip",
                str(path),
                "--sourceName",
                str(source_name),
                "--errorThreshold",
                str(int(self.error_threshold)),
                "--mutable",
                "--rawRecords",
                "all",
                "--runIdMismatch",
                "fail",
                *extra_defaults,
            ]
        else:
            cmd = [
                "node",
                str(cli),
                "--zip",
                str(path),
                "--sourceName",
                str(source_name),
                "--errorThreshold",
                str(int(self.error_threshold)),
                "--mutable",
                "--rawRecords",
                "all",
                "--runIdMismatch",
                "fail",
                *extra_defaults,
            ]

        try:
            res = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                check=False,
                cwd=str(backend_root),
                timeout=30,
            )
        except FileNotFoundError:
            logger.warning("Auto-ingest disabled: node not found on PATH")
            self._disabled = True
            return None
        if res.returncode != 0:
            preview = ((res.stderr or "").strip() or (res.stdout or "").strip())[:800]
            logger.warning("Auto-ingest backend failed (rc=%s): %s", res.returncode, preview)
            return None

        out = (res.stdout or "").strip()
        if not out:
            return {}
        try:
            return json.loads(out)
        except Exception:
            return {"stdout": out[:2000]}

    def _read_run_id_from_status(self) -> Optional[str]:
        status_path = self.path / "status.json"
        if not status_path.exists():
            return None
        try:
            doc = json.loads(status_path.read_text(encoding="utf-8"))
        except Exception:
            return None
        if isinstance(doc, dict):
            for key in ("run_id", "runId", "run", "id"):
                val = doc.get(key)
                if isinstance(val, str) and val.strip():
                    return val.strip()
        return None

    def _maybe_ingest_price_bars(self) -> None:
        if not self.price_bars_csv:
            return
        try:
            csv_path = Path(self.price_bars_csv).expanduser().resolve()
        except Exception:
            return
        if not csv_path.exists():
            return
        try:
            stat = csv_path.stat()
            current_stat = (float(stat.st_mtime), int(stat.st_size))
        except Exception:
            current_stat = None
        if current_stat is not None and self._bars_stat is not None and current_stat == self._bars_stat:
            return

        # Preferred: pure-Python ingestion if premarket_charts is available (unit-testable).
        try:
            import asyncio
            from premarket_charts.backend import ingest_csv_data  # type: ignore

            loop = self._loop
            if loop is None:
                loop = asyncio.new_event_loop()
                self._loop = loop
            instrument = self.price_bars_instrument or "ES"
            timeframe = self.price_bars_timeframe or "5m"
            coro = ingest_csv_data.ingest_csv_to_db(
                csv_path=csv_path,
                instrument=instrument,
                timeframe=timeframe,
                timezone=self.price_bars_timezone,
                source_name=str(self.source_name or self.path.name),
                error_threshold=int(self.error_threshold),
                mutable=True,
            )
            _ = loop.run_until_complete(coro)
            self._bars_stat = current_stat
            logger.info("Auto-ingest price_bars ok csv=%s instrument=%s timeframe=%s", csv_path, instrument, timeframe)
            return
        except Exception:
            pass

        # Fallback: backend CLI if present.
        try:
            backend_root = self._repo_root / "backend"
            cli = self._backend_cli()
            if cli is None:
                return
            run_id = self._read_run_id_from_status()
            if not run_id:
                return
            instrument = self.price_bars_instrument or "ES"
            timeframe_sec = int(self.price_bars_timeframe_sec or 300)
            if cli.suffix.lower() == ".ts":
                tsx = backend_root / "node_modules" / "tsx" / "dist" / "cli.mjs"
                cmd = [
                    "node",
                    str(tsx),
                    str(cli),
                    "--barsCsv",
                    str(csv_path),
                    "--runId",
                    str(run_id),
                    "--instrument",
                    str(instrument),
                    "--timeframeSec",
                    str(timeframe_sec),
                    "--sourceName",
                    str(self.source_name or self.path.name),
                    "--errorThreshold",
                    str(int(self.error_threshold)),
                    "--mutable",
                ]
            else:
                cmd = [
                    "node",
                    str(cli),
                    "--barsCsv",
                    str(csv_path),
                    "--runId",
                    str(run_id),
                    "--instrument",
                    str(instrument),
                    "--timeframeSec",
                    str(timeframe_sec),
                    "--sourceName",
                    str(self.source_name or self.path.name),
                    "--errorThreshold",
                    str(int(self.error_threshold)),
                    "--mutable",
                ]
            res = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                check=False,
                cwd=str(backend_root),
                timeout=30,
            )
            if res.returncode != 0:
                preview = ((res.stderr or "").strip() or (res.stdout or "").strip())[:800]
                logger.warning("Auto-ingest price_bars failed (rc=%s) csv=%s: %s", res.returncode, csv_path, preview)
                return
            self._bars_stat = current_stat
            logger.info("Auto-ingest price_bars ok csv=%s instrument=%s timeframe_sec=%s", csv_path, instrument, timeframe_sec)
        except Exception as exc:
            logger.warning("Auto-ingest price_bars failed csv=%s: %s", csv_path, exc)


class _AutoDbIngestor:
    def __init__(
        self,
        *,
        path: Path,
        interval_sec: float,
        init_db: bool,
        price_bars_csv: Optional[str],
        price_bars_instrument: Optional[str],
        price_bars_timeframe_sec: Optional[int],
        mysql_host: Optional[str],
        mysql_port: Optional[int],
        mysql_user: Optional[str],
        mysql_pass: Optional[str],
        mysql_db: Optional[str],
    ) -> None:
        self.path = path
        self.interval_sec = max(5.0, float(interval_sec or 0.0))
        self.init_db = bool(init_db)
        self.price_bars_csv = price_bars_csv
        self.price_bars_instrument = price_bars_instrument
        self.price_bars_timeframe_sec = price_bars_timeframe_sec
        self.mysql_host = mysql_host
        self.mysql_port = mysql_port
        self.mysql_user = mysql_user
        self.mysql_pass = mysql_pass
        self.mysql_db = mysql_db
        self._stop = threading.Event()
        self._thread: Optional[threading.Thread] = None
        self._init_done = False
        self._repo_root = Path(__file__).resolve().parents[4]

    def start(self) -> None:
        if self._thread is not None:
            return
        self._thread = threading.Thread(target=self._run, name="auto-db-ingest", daemon=True)
        self._thread.start()

    def stop(self) -> None:
        if self._thread is None:
            return
        self._stop.set()
        self._thread.join(timeout=10.0)
        self._thread = None

    def _run(self) -> None:
        while not self._stop.is_set():
            self._run_once()
            self._stop.wait(self.interval_sec)
        self._run_once()

    def _run_once(self) -> None:
        if not self.path.exists():
            try:
                self.path.mkdir(parents=True, exist_ok=True)
            except Exception:
                return
            return
        status_path = self.path / "status.json"
        if not status_path.exists():
            return
        try:
            json.loads(status_path.read_text(encoding="utf-8"))
        except Exception:
            return
        if not (self._repo_root / "ingest_zip").exists():
            logger.warning("DB ingest disabled: ingest_zip package not found at %s", self._repo_root)
            return
        cmd = [sys.executable, "-m", "ingest_zip", "--zip", str(self.path)]
        if self.init_db and not self._init_done:
            cmd.insert(3, "--init-db")
        if self.price_bars_csv:
            cmd += ["--price_bars_csv", str(self.price_bars_csv)]
            if self.price_bars_instrument:
                cmd += ["--instrument", str(self.price_bars_instrument)]
            if self.price_bars_timeframe_sec:
                cmd += ["--timeframe_sec", str(int(self.price_bars_timeframe_sec))]
        if self.mysql_host:
            cmd += ["--mysql-host", str(self.mysql_host)]
        if self.mysql_port:
            cmd += ["--mysql-port", str(self.mysql_port)]
        if self.mysql_user:
            cmd += ["--mysql-user", str(self.mysql_user)]
        if self.mysql_pass:
            cmd += ["--mysql-pass", str(self.mysql_pass)]
        if self.mysql_db:
            cmd += ["--mysql-db", str(self.mysql_db)]
        try:
            env = os.environ.copy()
            repo_root = str(self._repo_root)
            env["PYTHONPATH"] = repo_root + os.pathsep + env.get("PYTHONPATH", "")
            res = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                check=False,
                cwd=repo_root,
                env=env,
                timeout=60,
            )
            if res.returncode == 0:
                self._init_done = True
                return
            out = (res.stdout or "").strip()
            err = (res.stderr or "").strip()
            preview = (err or out)[:800]
            logger.warning("DB ingest failed (rc=%s): %s", res.returncode, preview)
        except Exception as exc:
            logger.warning("DB ingest exception: %s", exc)

def _validate_nt_instrument_name(instr: str) -> str:
    raw = instr.strip().upper()
    num_pattern = re.compile(r"^(?P<sym>[A-Z]{1,4})[ -](?P<mon>\d{2})-(?P<yr>\d{2})$")
    text_pattern = re.compile(r"^(?P<sym>[A-Z]{1,4})[ -](?P<mon>[A-Z]{3})(?P<yr>\d{2})$")
    m_num = num_pattern.match(raw)
    if m_num:
        sym = m_num.group("sym")
        mon = m_num.group("mon")
        yr = m_num.group("yr")
        try:
            mon_int = int(mon)
        except Exception as exc:
            raise ValueError(f"NT instrument month must be 01-12; got '{mon}'") from exc
        if mon_int < 1 or mon_int > 12:
            raise ValueError(f"NT instrument month must be 01-12; got '{mon}'")
        return f"{sym} {mon}-{yr}"
    m_text = text_pattern.match(raw)
    if m_text:
        sym = m_text.group("sym")
        mon = m_text.group("mon")
        yr = m_text.group("yr")
        months = {"JAN", "FEB", "MAR", "APR", "MAY", "JUN", "JUL", "AUG", "SEP", "OCT", "NOV", "DEC"}
        if mon not in months:
            raise ValueError(f"NT instrument month must be Jan-Dec; got '{mon}'")
        return f"{sym} {mon}{yr}"
    raise ValueError(
        f"NT instrument must be full contract (e.g., ES 03-26 or ES MAR26); got '{instr}'"
    )


_MONTH_ALIASES = {
    "JAN": "01",
    "FEB": "02",
    "MAR": "03",
    "APR": "04",
    "MAY": "05",
    "JUN": "06",
    "JUL": "07",
    "AUG": "08",
    "SEP": "09",
    "OCT": "10",
    "NOV": "11",
    "DEC": "12",
}


def _normalize_instrument(instr: Optional[str]) -> str:
    if not instr:
        return ""
    raw = re.sub(r"\s+", " ", str(instr).strip().upper())
    if not raw:
        return ""
    m_num = re.match(r"^(?P<sym>[A-Z]{1,6})\s+(?P<mon>\d{1,2})[-/ ](?P<yr>\d{2,4})$", raw)
    if m_num:
        sym = m_num.group("sym")
        mon = int(m_num.group("mon"))
        yr = m_num.group("yr")[-2:]
        return f"{sym} {mon:02d}-{yr}"
    m_txt = re.match(r"^(?P<sym>[A-Z]{1,6})\s+(?P<mon>[A-Z]{3})\s*(?P<yr>\d{2,4})$", raw)
    if m_txt:
        sym = m_txt.group("sym")
        mon = _MONTH_ALIASES.get(m_txt.group("mon"))
        yr = m_txt.group("yr")[-2:]
        if mon:
            return f"{sym} {mon}-{yr}"
    return raw


def _instrument_parts(norm: str) -> Tuple[str, Optional[str]]:
    if not norm:
        return "", None
    parts = norm.split(" ", 1)
    sym = parts[0]
    contract = None
    if len(parts) == 2 and re.match(r"^\d{2}-\d{2}$", parts[1]):
        contract = parts[1]
    return sym, contract


def _instrument_matches(left: Optional[str], right: Optional[str]) -> bool:
    if not left and not right:
        return True
    left_norm = _normalize_instrument(left)
    right_norm = _normalize_instrument(right)
    left_sym, left_contract = _instrument_parts(left_norm)
    right_sym, right_contract = _instrument_parts(right_norm)
    if not left_sym or not right_sym:
        return False
    if left_sym != right_sym:
        return False
    if left_contract and right_contract:
        return left_contract == right_contract
    return True


def _normalize_exec_instrument(instr: Optional[str]) -> str:
    return _normalize_instrument(instr)


def _normalize_nt_instrument_for_match(instr: Optional[str]) -> str:
    return _normalize_instrument(instr)


def _prefer_contract_text_format(instr: Optional[str]) -> str:
    raw = re.sub(r"\s+", " ", str(instr or "").strip().upper())
    if not raw:
        return ""
    m_num = re.match(r"^(?P<sym>[A-Z]{1,6})\s+(?P<mon>\d{1,2})[-/ ](?P<yr>\d{2,4})$", raw)
    if not m_num:
        return raw
    sym = m_num.group("sym")
    mon_num = f"{int(m_num.group('mon')):02d}"
    yr = m_num.group("yr")[-2:]
    mon_txt = next((name for name, alias in _MONTH_ALIASES.items() if alias == mon_num), None)
    if not mon_txt:
        return raw
    return f"{sym} {mon_txt}{yr}"


def _parse_ts_variants(msg: Mapping[str, Any]) -> Optional[Any]:
    for key in (
        "snapshot_ts",
        "snapshotTimestamp",
        "snapshot_time",
        "timestamp",
        "ts",
        "time",
        "event_time",
    ):
        if key in msg and msg.get(key) is not None:
            return msg.get(key)
    return None


def _generate_audit_report(out_dir: Path) -> Dict[str, Any]:
    report: Dict[str, Any] = {}
    out_dir = Path(out_dir)
    status_path = out_dir / "status.json"
    ledger_path = out_dir / "event_ledger.jsonl"
    signals_path = out_dir / "signals.jsonl"
    nt_path = out_dir / "nt_bridge.jsonl"
    report["out_dir"] = str(out_dir)
    status = {}
    if status_path.exists():
        try:
            status = json.loads(status_path.read_text(encoding="utf-8"))
        except Exception:
            status = {}
    report["run_id"] = status.get("run_id")
    report["run_mode"] = status.get("run_mode")
    report["time_mode"] = status.get("time_mode")
    report["nt_exec_policy"] = status.get("nt_exec_policy")

    def _first_last_jsonl(path: Path) -> Tuple[Optional[Dict[str, Any]], Optional[Dict[str, Any]]]:
        first = last = None
        if not path.exists():
            return first, last
        with path.open("rb") as fh:
            while True:
                line = fh.readline()
                if not line:
                    break
                if line.strip():
                    first = json.loads(line)
                    break
            fh.seek(0, os.SEEK_END)
            end = fh.tell()
            size = min(16384, end)
            if end:
                fh.seek(-size, os.SEEK_END)
                chunk = fh.read().splitlines()
                for line in reversed(chunk):
                    if line.strip():
                        last = json.loads(line)
                        break
        return first, last

    first_signal, last_signal = _first_last_jsonl(signals_path)
    report["first_bar_ts"] = (first_signal or {}).get("ts")
    report["last_bar_ts"] = (last_signal or {}).get("ts")

    first_snap = last_snap = None
    if nt_path.exists():
        with nt_path.open("r", encoding="utf-8") as fh:
            for line in fh:
                if not line.strip():
                    continue
                try:
                    data = json.loads(line)
                except Exception:
                    continue
                if data.get("msg", {}).get("type") == "POSITION_SNAPSHOT":
                    first_snap = data.get("msg", {}).get("timestamp")
                    break
        with nt_path.open("rb") as fh:
            fh.seek(0, os.SEEK_END)
            end = fh.tell()
            size = min(16384, end)
            if end:
                fh.seek(-size, os.SEEK_END)
                lines = fh.read().splitlines()
                for line in reversed(lines):
                    if not line.strip():
                        continue
                    try:
                        data = json.loads(line)
                    except Exception:
                        continue
                    if data.get("msg", {}).get("type") == "POSITION_SNAPSHOT":
                        last_snap = data.get("msg", {}).get("timestamp")
                        break
    report["first_snapshot_ts"] = first_snap
    report["last_snapshot_ts"] = last_snap

    block_counts: Dict[str, Dict[str, Any]] = {}
    lockout_counts: Dict[str, Dict[str, Any]] = {}
    first_block = None
    first_lockout = None
    if ledger_path.exists():
        with ledger_path.open("r", encoding="utf-8") as fh:
            for line in fh:
                if not line.strip():
                    continue
                try:
                    ev = json.loads(line)
                except Exception:
                    continue
                et = ev.get("event_type")
                if et == "BLOCK":
                    if first_block is None:
                        first_block = ev
                    code = ev.get("block_code") or "unknown"
                    rec = block_counts.setdefault(code, {"count": 0, "first_ts": None, "last_ts": None})
                    rec["count"] += 1
                    rec["owning_layer"] = ev.get("owning_layer")
                    rec["operator_action"] = ev.get("operator_action")
                    rec["first_ts"] = rec["first_ts"] or ev.get("ts")
                    rec["last_ts"] = ev.get("ts")
                elif et == "LOCKOUT":
                    if first_lockout is None:
                        first_lockout = ev
                    code = ev.get("lockout_code") or "unknown"
                    rec = lockout_counts.setdefault(code, {"count": 0, "first_ts": None, "last_ts": None})
                    rec["count"] += 1
                    rec["owning_layer"] = ev.get("owning_layer")
                    rec["operator_action"] = ev.get("operator_action")
                    rec["first_ts"] = rec["first_ts"] or ev.get("ts")
                    rec["last_ts"] = ev.get("ts")

    report["blocks"] = block_counts
    report["lockouts"] = lockout_counts
    report["first_block"] = first_block
    report["first_lockout"] = first_lockout

    contradictions: List[str] = []
    if "stale_bar_ignored_in_replay" in block_counts and "blocked_stale_bar" in block_counts:
        contradictions.append("stale_bar_ignored_in_replay present AND blocked_stale_bar present")
    if report.get("run_mode") == "replay" and "market_closed" in block_counts:
        contradictions.append("market_closed present during replay")
    snapshot_last_ts = status.get("snapshot_last_ts")
    if snapshot_last_ts and str(snapshot_last_ts).startswith("1970-"):
        contradictions.append("snapshot_last_ts shows epoch while NT snapshot has ISO timestamps")
    report["contradictions"] = contradictions

    primary_reason = status.get("primary_reason_code")
    first_trade_block = None
    if first_lockout:
        first_trade_block = first_lockout.get("lockout_code")
    elif first_block:
        first_trade_block = first_block.get("block_code")
    report["primary_reason_code"] = primary_reason
    report["first_trade_block_code"] = first_trade_block
    report["primary_reason_disagrees"] = bool(primary_reason and first_trade_block and primary_reason != first_trade_block)
    return report


def _write_audit_report(out_dir: Path) -> None:
    report = _generate_audit_report(out_dir)
    out_dir = Path(out_dir)
    json_path = out_dir / "audit_report.json"
    md_path = out_dir / "audit_report.md"
    json_path.write_text(_json_dumps(report), encoding="utf-8")
    lines = []
    lines.append(f"# Audit Report: {out_dir}")
    lines.append("")
    lines.append("## Run Timeline")
    lines.append(f"- run_id: {report.get('run_id')}")
    lines.append(f"- run_mode: {report.get('run_mode')}")
    lines.append(f"- time_mode: {report.get('time_mode')}")
    lines.append(f"- nt_exec_policy: {report.get('nt_exec_policy')}")
    lines.append(f"- first_bar_ts: {report.get('first_bar_ts')}")
    lines.append(f"- last_bar_ts: {report.get('last_bar_ts')}")
    lines.append(f"- first_snapshot_ts: {report.get('first_snapshot_ts')}")
    lines.append(f"- last_snapshot_ts: {report.get('last_snapshot_ts')}")
    lines.append("")
    lines.append("## Block/Lockout Truth Table")
    if report.get("blocks"):
        lines.append("### BLOCK")
        for code, meta in report["blocks"].items():
            lines.append(
                f"- {code}: count={meta.get('count')} owning_layer={meta.get('owning_layer')} first_ts={meta.get('first_ts')}"
            )
    if report.get("lockouts"):
        lines.append("### LOCKOUT")
        for code, meta in report["lockouts"].items():
            lines.append(
                f"- {code}: count={meta.get('count')} owning_layer={meta.get('owning_layer')} first_ts={meta.get('first_ts')}"
            )
    lines.append("")
    lines.append("## Contradictions")
    if report.get("contradictions"):
        for item in report["contradictions"]:
            lines.append(f"- {item}")
    else:
        lines.append("- none")
    lines.append("")
    lines.append("## Primary Stop Reason")
    lines.append(f"- status.primary_reason_code: {report.get('primary_reason_code')}")
    lines.append(f"- first_trade_block_code: {report.get('first_trade_block_code')}")
    lines.append(f"- primary_reason_disagrees: {report.get('primary_reason_disagrees')}")
    md_path.write_text("\n".join(lines), encoding="utf-8")
_TIME_ONLY_RE = re.compile(r"^\s*\d{1,2}:\d{2}:\d{2}\s*$")
_BAR_FMT = "%Y-%m-%d %H:%M"

# --- Grade order helper (higher = stricter) ---
GRADE_ORDER = {"": 0, "C": 1, "B+": 2, "A+": 3}
def _grade_at_least(grade: str, min_grade: str) -> bool:
    return GRADE_ORDER.get(grade or "", 0) >= GRADE_ORDER.get(min_grade or "", 0)


def _normalize_ohlcv_columns(df: pd.DataFrame, *, drop_missing_ohlcv: bool = True) -> pd.DataFrame:
    df = df.copy()
    rename: Dict[Any, str] = {}
    for c in df.columns:
        lc = str(c).lower()
        if lc in ("datetime", "date", "time", "timestamp") or lc.endswith("datetime"):
            rename[c] = "Datetime"
        elif lc == "open" or lc.endswith("_open"):
            rename[c] = "Open"
        elif lc == "high" or lc.endswith("_high"):
            rename[c] = "High"
        elif lc == "low" or lc.endswith("_low"):
            rename[c] = "Low"
        elif lc == "close" or lc.endswith("_close"):
            rename[c] = "Close"
        elif lc == "volume" or lc.endswith("_volume"):
            rename[c] = "Volume"
        elif lc == "bid" or lc.endswith("_bid"):
            rename[c] = "Bid"
        elif lc == "ask" or lc.endswith("_ask"):
            rename[c] = "Ask"
    if rename:
        df = df.rename(columns=rename)

    if "Datetime" not in df.columns:
        raise ValueError("No Datetime column found.")

    for c in ["Open", "High", "Low", "Close", "Volume", "Bid", "Ask"]:
        if c in df.columns:
            df[c] = pd.to_numeric(df[c], errors="coerce")
    keep = [c for c in ["Open", "High", "Low", "Close", "Volume"] if c in df.columns]
    if keep and drop_missing_ohlcv:
        df = df.dropna(subset=keep).reset_index(drop=True)
    return df


def _ensure_denver_naive(ts: Any) -> Optional[pd.Timestamp]:
    if ts is None:
        return None
    try:
        parsed = pd.to_datetime(ts)
    except Exception:
        return None
    if pd.isna(parsed):
        return None
    tzinfo = getattr(parsed, "tzinfo", None)
    if tzinfo is not None:
        try:
            parsed = parsed.tz_convert(DENVER_TZ)
        except Exception:
            parsed = parsed.tz_localize(DENVER_TZ)
        parsed = parsed.tz_localize(None)
    else:
        parsed = pd.Timestamp(parsed.to_pydatetime().replace(tzinfo=None))
    return parsed


def _ensure_session_tz(ts: Any, tz: str) -> Optional[pd.Timestamp]:
    """Convert a timestamp to the requested session tz (tz-aware)."""
    if ts is None:
        return None
    try:
        parsed = pd.to_datetime(ts)
    except Exception:
        return None
    if pd.isna(parsed):
        return None
    try:
        return parsed.tz_convert(tz) if parsed.tzinfo is not None else parsed.tz_localize(tz)
    except Exception:
        return None


class EmissionLedger:
    """Persistent ledger of emitted client_order_id for idempotency and restart safety."""

    def __init__(self, path: Path) -> None:
        self.path = Path(path)
        self.path.parent.mkdir(parents=True, exist_ok=True)
        self._seen: Dict[str, Dict[str, Any]] = {}
        self._lock = threading.Lock()
        self._load()

    def _load(self) -> None:
        if not self.path.exists():
            return
        try:
            for line in self.path.read_text(encoding="utf-8").splitlines():
                if not line.strip():
                    continue
                try:
                    rec = json.loads(line)
                except Exception:
                    logger.warning("Skipping malformed emission ledger line")
                    continue
                cid = rec.get("client_order_id")
                if cid:
                    self._seen[str(cid)] = rec
        except Exception:
            self._seen = {}

    def seen(self, client_order_id: str) -> bool:
        return client_order_id in self._seen

    def append(self, client_order_id: str, payload: Dict[str, Any]) -> None:
        record = {"client_order_id": client_order_id, **payload}
        with self._lock:
            self._seen[client_order_id] = record
            with self.path.open("a", encoding="utf-8", newline="\n") as fh:
                fh.write(_json_dumps(record) + "\n")
                fh.flush()
                try:
                    os.fsync(fh.fileno())
                except Exception:
                    pass


class FileLock:
    """Simple file lock to avoid concurrent emitters on same out_dir."""

    def __init__(self, path: Path) -> None:
        self.path = Path(path)
        self._fd: Optional[int] = None
        self.locked = False

    def acquire(self) -> None:
        try:
            self._fd = os.open(self.path, os.O_CREAT | os.O_EXCL | os.O_RDWR)
            os.write(self._fd, str(os.getpid()).encode("ascii"))
            self.locked = True
        except FileExistsError:
            raise RuntimeError(f"Emitter already running (lock file {self.path} exists)")

    def release(self) -> None:
        try:
            if self._fd is not None:
                os.close(self._fd)
            if self.path.exists():
                self.path.unlink()
        except Exception:
            pass
        self.locked = False


def _normalize_bar_times(
    df: pd.DataFrame,
    csv_tz: Optional[str] = None,
    session_tz: Optional[str] = None,
    bar_interval_sec: int = 300,
    allow_off_grid: bool = False,
    allow_duplicates: bool = False,
    off_grid_grace_sec: float = 0.0,
    return_audit: bool = False,
) -> Tuple[pd.DataFrame, Dict[str, int]] | Tuple[pd.DataFrame, Dict[str, int], List[Dict[str, Any]]]:
    stats = {
        "total_rows": int(len(df)),
        "dropped_time_only": 0,
        "dropped_parse_fail": 0,
        "dropped_off_grid": 0,
        "deduped": 0,
        "rounded_off_grid": 0,
    }
    audit: List[Dict[str, Any]] = []
    if df.empty:
        stats["kept_rows"] = 0
        if return_audit:
            return df, stats, audit
        return df, stats

    work = df.copy()
    text_dt = work["Datetime"].astype(str)
    time_only_mask = text_dt.str.match(_TIME_ONLY_RE, na=False)
    if time_only_mask.any():
        stats["dropped_time_only"] = int(time_only_mask.sum())
        work = work.loc[~time_only_mask].copy()

    tz_hint = text_dt.str.contains(r"(?:Z|[+-]\d{2}:?\d{2})$", na=False)
    if tz_hint.any():
        parsed = pd.to_datetime(work["Datetime"], errors="coerce", utc=True)
        stats["parsed_with_utc"] = 1
    else:
        parsed = pd.to_datetime(work["Datetime"], errors="coerce", utc=False)
        if not pd.api.types.is_datetime64_any_dtype(parsed):
            # Mixed/offset timestamps can yield object dtype; re-parse as UTC to restore .dt access.
            parsed = pd.to_datetime(work["Datetime"], errors="coerce", utc=True)
            stats["parsed_with_utc"] = 1
    parse_fail = parsed.isna()
    if parse_fail.any():
        stats["dropped_parse_fail"] = int(parse_fail.sum())
        work = work.loc[~parse_fail].copy()
        parsed = parsed.loc[~parse_fail]

    tz = getattr(parsed.dt, "tz", None)
    stats["tz_aware"] = 1 if tz is not None else 0
    target_tz = session_tz or "America/Denver"
    if tz is not None:
        parsed = parsed.dt.tz_convert(target_tz).dt.tz_localize(None)
    else:
        stats["tz_localized"] = 0
        if csv_tz and target_tz and str(csv_tz) != str(target_tz):
            try:
                parsed = parsed.dt.tz_localize(csv_tz).dt.tz_convert(target_tz).dt.tz_localize(None)
                stats["tz_localized"] = 1
            except Exception:
                stats["tz_localized"] = 0

    interval = int(bar_interval_sec or 0)
    if interval > 0:
        parsed_original = parsed.copy()
        try:
            seconds_since_midnight = (parsed - parsed.dt.normalize()).dt.total_seconds()
            remainder = seconds_since_midnight % interval
            grid_mask = remainder == 0
        except Exception:
            minute = parsed.dt.minute
            second = parsed.dt.second
            minute_step = max(1, int(round(interval / 60))) if interval >= 60 else 1
            grid_mask = (minute % minute_step == 0) & (second == 0)
            remainder = None
            parsed_original = parsed.copy()
        grace = max(0.0, float(off_grid_grace_sec or 0.0))
        if grace > 0.0:
            try:
                seconds_since_midnight = (parsed - parsed.dt.normalize()).dt.total_seconds()
                nearest = np.round(seconds_since_midnight / interval) * interval
                offset = nearest - seconds_since_midnight
                within = np.abs(offset) <= grace
                if within.any():
                    adjusted = parsed + pd.to_timedelta(offset, unit="s")
                    changed = within & (offset != 0)
                    if changed.any():
                        stats["rounded_off_grid"] = int(changed.sum())
                        for orig_ts, new_ts, delta in zip(
                            parsed_original[changed],
                            adjusted[changed],
                            offset[changed],
                        ):
                            audit.append(
                                {
                                    "event": "bar_time_rounded",
                                    "original_ts": _canonical_ts_str(orig_ts),
                                    "adjusted_ts": _canonical_ts_str(new_ts),
                                    "delta_sec": float(delta),
                                }
                            )
                    parsed = adjusted
                    grid_mask = within | (offset == 0)
            except Exception:
                pass
        if not grid_mask.all():
            stats["dropped_off_grid"] = int((~grid_mask).sum())
            if return_audit:
                for ts_val in parsed_original.loc[~grid_mask]:
                    audit.append(
                        {
                            "event": "bar_time_dropped",
                            "reason": "off_grid",
                            "ts": _canonical_ts_str(ts_val),
                        }
                    )
            if not allow_off_grid:
                work = work.loc[grid_mask].copy()
                parsed = parsed.loc[grid_mask]
    stats["grid_aligned"] = int(len(parsed))

    work = work.assign(Datetime=pd.Series(parsed.to_numpy(), index=work.index))
    work = work.sort_values("Datetime")
    dup_mask = work.duplicated(subset=["Datetime"], keep="last")
    if dup_mask.any():
        stats["deduped"] = int(dup_mask.sum())
        if not allow_duplicates:
            work = work.loc[~dup_mask]

    work = work.reset_index(drop=True)
    stats["kept_rows"] = int(len(work))
    if return_audit:
        return work, stats, audit
    return work, stats


def _format_bar(ts: Any) -> str:
    dt = _ensure_denver_naive(ts)
    if dt is None:
        return "NA"
    return dt.strftime(_BAR_FMT)


