class FxAlexContextBuilder:
    """Builds L1Context objects with swing/trend metadata."""

    def __init__(
        self,
        *,
        ma_lookback: int,
        sweep_lookback: int,
        swing_window: int,
        session_tz: str,
        rth_start: str,
        rth_end: str,
    ) -> None:
        self.ma_lookback = max(1, int(ma_lookback))
        self.sweep_lookback = max(1, int(sweep_lookback))
        self.swing_window = max(1, int(swing_window))
        self.session_tz = session_tz
        self.rth_start = self._parse_time(rth_start) or dtime(7, 30)
        self.rth_end = self._parse_time(rth_end) or dtime(14, 0)
        self._close_window: Deque[float] = deque(maxlen=self.ma_lookback)
        self._recent_highs: Deque[float] = deque(maxlen=self.sweep_lookback)
        self._recent_lows: Deque[float] = deque(maxlen=self.sweep_lookback)
        self._swing_buffer: Deque[_BarSnapshot] = deque(maxlen=2 * self.swing_window + 1)
        self._last_swing_high: Optional[float] = None
        self._prior_swing_high: Optional[float] = None
        self._last_swing_low: Optional[float] = None
        self._prior_swing_low: Optional[float] = None

    @staticmethod
    def _parse_time(val: str) -> Optional[dtime]:
        return _parse_time_value(val)

    def update(
        self,
        *,
        idx: int,
        ts: dt_type,
        open_: float,
        high: float,
        low: float,
        close: float,
        volume: float,
    ) -> L1Context:
        snapshot = _BarSnapshot(idx, ts, open_, high, low, close, volume)
        self._close_window.append(close)
        self._recent_highs.append(high)
        self._recent_lows.append(low)
        self._swing_buffer.append(snapshot)
        self._update_swings()
        ma_val: Optional[float] = None
        if len(self._close_window) >= self.ma_lookback:
            try:
                ma_val = float(sum(self._close_window)) / float(len(self._close_window))
            except Exception:
                ma_val = None
        trend: Literal["UP", "DOWN", "NONE"] = "NONE"
        if ma_val is not None:
            if close > ma_val:
                trend = "UP"
            elif close < ma_val:
                trend = "DOWN"
        recent_high = max(self._recent_highs) if self._recent_highs else None
        recent_low = min(self._recent_lows) if self._recent_lows else None
        ctx = L1Context(
            idx=idx,
            ts=ts,
            open=open_,
            high=high,
            low=low,
            close=close,
            volume=volume,
            htf_trend=trend,
            last_swing_high=self._last_swing_high,
            prior_swing_high=self._prior_swing_high,
            last_swing_low=self._last_swing_low,
            prior_swing_low=self._prior_swing_low,
            recent_high=recent_high,
            recent_low=recent_low,
            is_rth=self._in_rth(ts),
        )
        return ctx

    def _update_swings(self) -> None:
        if len(self._swing_buffer) < self._swing_buffer.maxlen:
            return
        center_idx = self.swing_window
        buf = list(self._swing_buffer)
        center = buf[center_idx]
        highs = [b.high for b in buf]
        lows = [b.low for b in buf]
        if all(center.high > val for i, val in enumerate(highs) if i != center_idx):
            self._prior_swing_high = self._last_swing_high
            self._last_swing_high = center.high
        if all(center.low < val for i, val in enumerate(lows) if i != center_idx):
            self._prior_swing_low = self._last_swing_low
            self._last_swing_low = center.low

    def _in_rth(self, ts: dt_type) -> bool:
        try:
            t = ts.time()
        except Exception:
            return True
        if self.rth_start <= self.rth_end:
            return self.rth_start <= t < self.rth_end
        # handle overnight windows if configured
        return t >= self.rth_start or t < self.rth_end


# ----------------------------- fallback transition policy ---------------
@dataclass
class FallbackPolicyCfg:
    p_buy: float
    p_sell: float
    proba_cut_bad: float
    atr_k: float
    max_bars_in_trade: int  # <=0 disables bar-cap exit
    trade_window_start: str
    trade_window_end: str
    session_tz: str
    hold_threshold_long: float = 0.60
    hold_threshold_short: float = 0.40
    exit_prob_confirm_bars: int = 1
    persist_prob_bars: int = 1
    min_hold_bars: int = 1
    # gate toggles
    use_vwap_gate: bool = True
    min_target_r_multiple: float = 1.0
    vwap_gate_mode: str = "trend"
    use_ema_gate: bool = True
    use_tod_gate: bool = True
    # how to combine gates
    gate_mode: str = "prob_and_one"   # "prob_and_both" | "prob_and_one" | "any_two"
    # confidence bonuses
    entry_bonus_prob_ema: float = 0.15
    entry_bonus_prob_vwap: float = 0.10
    entry_bonus_all3: float = 0.25
    hold_bonus_scale: float = 0.50
    # dynamic probability thresholds
    use_dyn_thresh: bool = False
    dyn_p_window: int = 200
    dyn_q_buy: float = 0.70   # buy when p above 70th percentile
    dyn_q_sell: float = 0.30  # sell when p below 30th percentile
    max_adverse_r: float = 0.0  # exit if trade moves this many R against us (>0 enables)
    override_prob_min: float = 1.0
    override_hold_conf_min: float = 1.0


class FallbackTransition:
    """Minimal OPEN/FLIP/CLOSE policy if `TransitionEngine` is unavailable,
    with detailed per-bar tracing and optional status-line callback.
    """
    def __init__(
        self,
        instrument: InstrumentSpec,
        cfg: FallbackPolicyCfg,
        *,
        trace: bool = False,
        status=None,
        emit=None,
        model_run_id: Optional[int] = None,
        contracts_per_trade: float = 1.0,
    ) -> None:
        self.inst = instrument
        self.cfg = cfg
        self.trace = trace
        self.status_cb = status  # callable or None
        self.emit_cb = emit       # optional printf/logger hook
        self.model_run_id = model_run_id
        try:
            contracts_value = float(contracts_per_trade or 1.0)
        except Exception:
            contracts_value = 1.0
        if contracts_value <= 0:
            contracts_value = 1.0
        self.contracts_per_trade = contracts_value
        self.pos = 0  # -1, 0, +1
        self.bars_in_trade = 0
        self.entry_price: Optional[float] = None
        self.entry_time: Optional[pd.Timestamp] = None
        self.entry_stop: Optional[float] = None
        self.entry_target: Optional[float] = None
        self.last_event_ts = None
        self._pbuf = deque(maxlen=int(getattr(cfg, "dyn_p_window", 200)))
        self._bad_prob_streak = 0
        self._good_prob_streak = 0

    def _in_window(self, ts: pd.Timestamp) -> bool:
        ts_dt = _ensure_denver_naive(ts)
        if ts_dt is None:
            return True
        start = _parse_time_value(self.cfg.trade_window_start)
        end = _parse_time_value(self.cfg.trade_window_end)
        if start is None or end is None:
            return True
        from datetime import time as dtime
        t = ts_dt.time()
        window_start = dtime(start.hour, start.minute)
        window_end = dtime(end.hour, end.minute)
        return (t >= window_start) and (t < window_end)

    # --- confidence helpers (heuristics) ---
    def _entry_conf(self, p: float) -> float:
        if p >= self.cfg.p_buy:
            return (p - self.cfg.p_buy) / max(1e-9, 1.0 - self.cfg.p_buy)
        if p <= self.cfg.p_sell:
            return (self.cfg.p_sell - p) / max(1e-9, self.cfg.p_sell)
        return 0.0

    def _hold_conf(self, p: float) -> float:
        cut = float(self.cfg.proba_cut_bad)
        if self.pos > 0:
            return np.clip((p - (1.0 - cut)) / max(1e-9, cut), 0.0, 1.0)
        if self.pos < 0:
            return np.clip((cut - p) / max(1e-9, cut), 0.0, 1.0)
        return 0.0

    def _trace(self, *, ts, action: str, p: float, close: float,
               gate_prob: bool, gate_vwap: bool, gate_ema: bool, gate_tod: bool,
               gate_vwap_raw: Optional[bool] = None, gate_ema_raw: Optional[bool] = None,
               gate_tod_raw: Optional[bool] = None,
               gate_vwap_enabled: Optional[bool] = None,
               gate_ema_enabled: Optional[bool] = None,
               gate_tod_enabled: Optional[bool] = None,
               vwap: Optional[float], ema20: Optional[float], ema50: Optional[float],
               atr: Optional[float],
               entry_bonus: float = 0.0, hold_bonus: float = 0.0) -> None:
        side = "LONG" if self.pos > 0 else ("SHORT" if self.pos < 0 else "FLAT")
        bars = self.bars_in_trade
        entry_conf = self._entry_conf(p)
        hold_conf = self._hold_conf(p)
        entry_conf = float(np.clip(entry_conf + max(0.0, entry_bonus), 0.0, 1.0))
        hold_conf  = float(np.clip(hold_conf  + max(0.0, hold_bonus),  0.0, 1.0))

        # PnL in R (if we have an entry stop)
        R_val = None
        if self.entry_price is not None and self.entry_stop is not None and np.isfinite(self.entry_stop):
            risk = abs(self.entry_price - self.entry_stop)
            if risk > 1e-9:
                if self.pos > 0:
                    R_val = (close - self.entry_price) / risk
                elif self.pos < 0:
                    R_val = (self.entry_price - close) / risk

        mins = None
        if self.entry_time is not None:
            try:
                current_ts = _ensure_denver_naive(ts)
                entry_ts = _ensure_denver_naive(self.entry_time)
                if current_ts is not None and entry_ts is not None:
                    mins = (current_ts - entry_ts).total_seconds() / 60.0
            except Exception:
                mins = None

        gate_vwap_raw = gate_vwap if gate_vwap_raw is None else gate_vwap_raw
        gate_ema_raw = gate_ema if gate_ema_raw is None else gate_ema_raw
        gate_tod_raw = gate_tod if gate_tod_raw is None else gate_tod_raw
        gates, gate_meta = _gate_report_summary(
            gate_prob_raw=gate_prob,
            gate_vwap_raw=gate_vwap_raw,
            gate_ema_raw=gate_ema_raw,
            gate_tod_raw=gate_tod_raw,
            gate_vwap_enabled=gate_vwap_enabled,
            gate_ema_enabled=gate_ema_enabled,
            gate_tod_enabled=gate_tod_enabled,
        )
        gate_prob_eff = gate_meta["gate_prob_effective_pass"]
        gate_vwap_eff = gate_meta["gate_vwap_effective_pass"]
        gate_ema_eff = gate_meta["gate_ema_effective_pass"]
        gate_tod_eff = gate_meta["gate_tod_effective_pass"]

        stop_str = f"{self.entry_stop:.2f}" if self.entry_stop is not None and np.isfinite(self.entry_stop) else "--"
        tgt_str  = f"{self.entry_target:.2f}" if self.entry_target is not None and np.isfinite(self.entry_target) else "--"
        ts_base = _ensure_denver_naive(ts)
        ts_s = ts_base.strftime("%H:%M") if ts_base is not None else "??:??"
        age_str  = f"{mins:.1f}m" if mins is not None and np.isfinite(mins) else "--"
        R_str    = f"{R_val:.2f}" if R_val is not None and np.isfinite(R_val) else "--"

        msg = (f"[{ts_s}] {action} {side} p={p:.3f} px={close:.2f} | "
               f"bars={bars} age={age_str} R={R_str} | "
               f"gates={gates} stop={stop_str} tgt={tgt_str} "
               f"| entry={int(round(entry_conf*100))}% hold={int(round(hold_conf*100))}%")

        delivered = False
        if callable(getattr(self, "status_cb", None)):
            self.status_cb(msg)
            delivered = True
        if callable(getattr(self, "emit_cb", None)):
            try:
                context_payload = {
                    "phase_hint": action,
                    "gate_prob": bool(gate_prob_eff),
                    "gate_vwap": bool(gate_vwap_eff),
                    "gate_ema": bool(gate_ema_eff),
                    "gate_tod": bool(gate_tod_eff),
                    "gates_detail": gate_meta,
                    "vwap_sess": vwap,
                    "ema_20": ema20,
                    "ema_50": ema50,
                    "atr_14": atr,
                    "bars_in_trade": bars,
                    "age_minutes": mins,
                    "r_value": R_val,
                    "entry_bonus": entry_bonus,
                    "hold_bonus": hold_bonus,
                    "model_run_id": self.model_run_id,
                }
                self.emit_cb(
                    action,
                    side,
                    ts,
                    close,
                    p,
                    entry_conf,
                    hold_conf,
                    gates,
                    stop_str,
                    tgt_str,
                    R_str,
                    context=context_payload,
                )
                delivered = True
            except Exception:
                pass
        if not delivered and (self.trace or logger.isEnabledFor(logging.DEBUG)):
            level = logging.INFO if self.trace else logging.DEBUG
            logger.log(level, msg)

    def _apply_contract_size(self, ev: Dict[str, Any]) -> None:
        if "contracts" not in ev or ev["contracts"] is None:
            ev["contracts"] = self.contracts_per_trade
        if ev.get("size") is None:
            ev["size"] = self.contracts_per_trade
        if ev.get("size_hint") is None:
            ev["size_hint"] = self.contracts_per_trade

    def step(self, row: pd.Series) -> Optional[Dict[str, Any]]:
        p = float(row.get("proba", np.nan))
        if not np.isfinite(p):
            return None
        close = float(row.get("Close", np.nan))
        vwap = float(row.get("vwap_sess", np.nan)) if pd.notna(row.get("vwap_sess", np.nan)) else None
        ema20 = float(row.get("ema_20", np.nan)) if pd.notna(row.get("ema_20", np.nan)) else None
        ema50 = float(row.get("ema_50", np.nan)) if pd.notna(row.get("ema_50", np.nan)) else None
        atr   = float(row.get("atr_14", np.nan)) if pd.notna(row.get("atr_14", np.nan)) else None
        ts = _ensure_denver_naive(row.get("Datetime"))
        if ts is None:
            return None

        if self.pos == 0:
            self._bad_prob_streak = 0
            self._good_prob_streak = 0

        # ---- dynamic thresholds (update buffer, compute current cuts) ----
        self._pbuf.append(float(p))
        if self.cfg.use_dyn_thresh and len(self._pbuf) >= 50:
            arr = np.asarray(self._pbuf, dtype=float)
            curr_p_buy  = float(np.quantile(arr, self.cfg.dyn_q_buy))
            curr_p_sell = float(np.quantile(arr, self.cfg.dyn_q_sell))
        else:
            curr_p_buy, curr_p_sell = self.cfg.p_buy, self.cfg.p_sell

        # ---- desired side by dynamic cuts ----
        desired = 0
        if p >= curr_p_buy:
            desired = +1
        elif p <= curr_p_sell:
            desired = -1

        # ---- gate toggles from cfg ----
        use_vwap = bool(getattr(self.cfg, "use_vwap_gate", True))
        use_ema  = bool(getattr(self.cfg, "use_ema_gate",  True))
        use_tod  = bool(getattr(self.cfg, "use_tod_gate",  True))

        # direction for EMA/VWAP gates: prefer phase2 signal, then desired, else p>0.5
        dir_signal = None
        try:
            dir_raw = row.get("phase2_direction_signal")
            if dir_raw is not None and pd.notna(dir_raw):
                dir_signal = int(dir_raw)
        except Exception:
            dir_signal = None
        if not dir_signal:
            dir_signal = desired
        longish = (dir_signal > 0) or (dir_signal == 0 and p >= 0.5)

        # ---- raw gates (market state) ----
        gate_prob = (p >= curr_p_buy) or (p <= curr_p_sell)
        gate_vwap_raw = _compute_vwap_gate_raw(
            close=close,
            vwap=vwap,
            longish=longish,
            prob=p,
            mode=getattr(self.cfg, "vwap_gate_mode", "trend"),
            override_pts=float(getattr(self.cfg, "vwap_fade_override_pts", 0) or 0),
            override_prob_threshold=float(getattr(self.cfg, "vwap_fade_prob_threshold", 0.28) or 0.28),
        )
        gate_ema_raw  = True
        if np.isfinite(ema20 or np.nan) and np.isfinite(ema50 or np.nan):
            gate_ema_raw = (ema20 > ema50) if longish else (ema20 < ema50)
        gate_tod_raw = self._in_window(ts)

        # ---- effective gates (respect toggles) ----
        gate_vwap = (not use_vwap) or gate_vwap_raw
        gate_ema  = (not use_ema)  or gate_ema_raw
        gate_tod  = (not use_tod)  or gate_tod_raw

        # ---- how to combine gates for ENTRY ----
        if   self.cfg.gate_mode == "prob_and_both":
            entry_ok = gate_prob and gate_vwap and gate_ema and gate_tod
        elif self.cfg.gate_mode == "prob_and_one":
            entry_ok = gate_prob and (gate_vwap or gate_ema) and gate_tod
        elif self.cfg.gate_mode == "any_two":
            entry_ok = (int(gate_prob) + int(gate_vwap) + int(gate_ema) >= 2) and gate_tod
        else:
            entry_ok = gate_prob and gate_vwap and gate_ema and gate_tod  # default

        # Never enter against trend when EMA gate disagrees (even if gate_mode allows it)
        if entry_ok and desired != 0 and bool(getattr(self.cfg, "use_ema_gate", True)):
            if not gate_ema_raw:
                entry_ok = False

        # ---- bonuses for trace (informational only) ----
        combo = None
        if gate_prob and (gate_vwap_raw and gate_ema_raw):
            combo = "all3"
        elif gate_prob and gate_ema_raw:
            combo = "prob+ema"
        elif gate_prob and gate_vwap_raw:
            combo = "prob+vwap"

        entry_bonus = 0.0
        if combo == "all3":
            entry_bonus = float(getattr(self.cfg, "entry_bonus_all3", 0.25))
        elif combo == "prob+ema":
            entry_bonus = float(getattr(self.cfg, "entry_bonus_prob_ema", 0.15))
        elif combo == "prob+vwap":
            entry_bonus = float(getattr(self.cfg, "entry_bonus_prob_vwap", 0.10))
        hold_bonus = entry_bonus * float(getattr(self.cfg, "hold_bonus_scale", 0.50))

        # ---- exits first ----
        if self.pos != 0:
            self.bars_in_trade += 1
            # Enhanced reversal detection and risk minimization
            reversal = (desired != 0 and desired != self.pos)
            # If reversal and gates allow, flip immediately (prefer keeping good trades)
            if reversal and entry_ok:
                typ = "FLIP"
                self.pos = desired
                self.bars_in_trade = 0
                self.entry_price = close
                self.entry_time = _ensure_denver_naive(ts)
                ev = self._make_event(typ, ts, close, p, gate_prob, gate_vwap, gate_ema, gate_tod, atr)
                self.entry_stop   = (ev.get("risk") or {}).get("stop")
                self.entry_target = (ev.get("risk") or {}).get("target")
                self._trace(
                    ts=ts,
                    action=typ,
                    p=p,
                    close=close,
                    gate_prob=gate_prob,
                    gate_vwap=gate_vwap,
                    gate_ema=gate_ema,
                    gate_tod=gate_tod,
                    gate_vwap_raw=gate_vwap_raw,
                    gate_ema_raw=gate_ema_raw,
                    gate_tod_raw=gate_tod_raw,
                    gate_vwap_enabled=use_vwap,
                    gate_ema_enabled=use_ema,
                    gate_tod_enabled=use_tod,
                    vwap=vwap,
                    ema20=ema20,
                    ema50=ema50,
                    atr=atr,
                    entry_bonus=entry_bonus,
                    hold_bonus=hold_bonus,
                )
                return ev

            # Track adverse excursion relative to entry risk
            adverse_r: Optional[float] = None
            stop_hit = False
            if self.entry_price is not None and self.entry_stop is not None and np.isfinite(self.entry_stop):
                risk = abs(self.entry_price - self.entry_stop)
                if risk > 1e-9:
                    if self.pos > 0:
                        adverse_move = max(0.0, self.entry_price - close)
                        adverse_r = adverse_move / risk
                        stop_hit = close <= self.entry_stop
                    else:
                        adverse_move = max(0.0, close - self.entry_price)
                        adverse_r = adverse_move / risk
                        stop_hit = close >= self.entry_stop

            r_guard = (
                bool(self.cfg.max_adverse_r)
                and self.cfg.max_adverse_r > 0
                and adverse_r is not None
                and adverse_r >= float(self.cfg.max_adverse_r)
            )

            # Hold thresholds:
            # - Long: threshold is in P(LONG) space. Exit long if P(LONG) <= hold_threshold_long.
            # - Short: threshold is in P(SHORT) space. Exit short if P(SHORT) <= hold_threshold_short.
            hold_long_raw = getattr(self.cfg, "hold_threshold_long", None)
            if hold_long_raw is None:
                hold_long_raw = curr_p_sell
            hold_threshold_long = float(hold_long_raw)
            hold_short_raw = getattr(self.cfg, "hold_threshold_short", None)
            if hold_short_raw is None:
                # Default short hold threshold to mirror long logic: exit short when P(LONG) rises above curr_p_buy,
                # i.e. when P(SHORT) falls below (1 - curr_p_buy).
                hold_short_raw = 1.0 - float(curr_p_buy)
            hold_threshold_short = float(hold_short_raw)
            if self.pos > 0:
                bad_prob = p <= hold_threshold_long
            else:
                short_prob = 1.0 - float(p)
                bad_prob = short_prob <= hold_threshold_short
            confirm_req = max(1, int(getattr(self.cfg, "exit_prob_confirm_bars", 1) or 1))
            persist_req = max(1, int(getattr(self.cfg, "persist_prob_bars", 1) or 1))
            if bad_prob:
                self._bad_prob_streak += 1
                self._good_prob_streak = 0
            else:
                self._good_prob_streak += 1
                if self._good_prob_streak >= persist_req:
                    self._bad_prob_streak = 0
                    if persist_req > 1:
                        self._good_prob_streak = persist_req  # cap growth during favorable streaks
            bad_prob_ready = self._bad_prob_streak >= confirm_req

            min_hold_req = max(1, int(getattr(self.cfg, "min_hold_bars", 1) or 1))
            min_hold_met = self.bars_in_trade >= min_hold_req

            # Optional bar-cap (<=0 disables)
            cap_hit = (self.cfg.max_bars_in_trade > 0 and self.bars_in_trade >= self.cfg.max_bars_in_trade)

            prob_exit = bad_prob_ready and min_hold_met
            if bad_prob_ready and not min_hold_met:
                _safe_print(
                    f"MIN_HOLD_BLOCK: bars_in_trade={self.bars_in_trade} < min_hold_bars={min_hold_req}, prob_exit suppressed"
                )
            override_applied = False
            if prob_exit and not (stop_hit or r_guard or cap_hit or (not gate_tod)):
                try:
                    hold_conf = self._hold_confidence(float(p), int(self.pos))
                except Exception:
                    hold_conf = None
                override_prob_min = float(getattr(self.cfg, "override_prob_min", 1.0) or 1.0)
                override_hold_conf_min = float(getattr(self.cfg, "override_hold_conf_min", 1.0) or 1.0)
                if _override_confident_long(
                    side="LONG" if self.pos > 0 else "SHORT",
                    prob_long=float(p),
                    hold_conf=hold_conf,
                    override_prob_min=override_prob_min,
                    override_hold_conf_min=override_hold_conf_min,
                ):
                    prob_exit = False
                    override_applied = True
                    _safe_print(
                        f"OVERRIDE_HOLD: prob={float(p):.4f}>={override_prob_min}, "
                        f"hold_conf={float(hold_conf):.4f}>={override_hold_conf_min} - exit suppressed"
                    )

            if stop_hit or r_guard or (not gate_tod) or prob_exit or cap_hit:
                ev = self._make_event("CLOSE", ts, close, p, gate_prob, gate_vwap, gate_ema, gate_tod)
                if override_applied:
                    ev.setdefault("ctx", {})["override_applied"] = True
                if stop_hit or r_guard or cap_hit:
                    context: Dict[str, Any] = {}
                    if stop_hit:
                        context["stop_hit"] = True
                    if r_guard and adverse_r is not None:
                        context["adverse_r"] = float(adverse_r)
                        context["max_adverse_r"] = float(self.cfg.max_adverse_r)
                    if cap_hit:
                        context["max_bars_hit"] = True
                    if context:
                        ev.setdefault("context", {}).update(context)
                self._trace(
                    ts=ts,
                    action="CLOSE",
                    p=p,
                    close=close,
                    gate_prob=gate_prob,
                    gate_vwap=gate_vwap,
                    gate_ema=gate_ema,
                    gate_tod=gate_tod,
                    gate_vwap_raw=gate_vwap_raw,
                    gate_ema_raw=gate_ema_raw,
                    gate_tod_raw=gate_tod_raw,
                    gate_vwap_enabled=use_vwap,
                    gate_ema_enabled=use_ema,
                    gate_tod_enabled=use_tod,
                    vwap=vwap,
                    ema20=ema20,
                    ema50=ema50,
                    atr=atr,
                    entry_bonus=entry_bonus,
                    hold_bonus=hold_bonus,
                )
                self.pos = 0
                self.bars_in_trade = 0
                self.entry_price = None
                self.entry_time = None
                self.entry_stop = None
                self.entry_target = None
                self._bad_prob_streak = 0
                self._good_prob_streak = 0
                return ev

        # ---- entries / flips ----
        if entry_ok and desired != 0 and desired != self.pos:
            typ = "OPEN" if self.pos == 0 else "FLIP"
            self.pos = desired
            self.bars_in_trade = 0
            self.entry_price = close
            self.entry_time = _ensure_denver_naive(ts)
            ev = self._make_event(typ, ts, close, p, gate_prob, gate_vwap, gate_ema, gate_tod, atr)
            self.entry_stop   = (ev.get("risk") or {}).get("stop")
            self.entry_target = (ev.get("risk") or {}).get("target")
            self._bad_prob_streak = 0
            self._good_prob_streak = 0
            self._trace(
                ts=ts,
                action=typ,
                p=p,
                close=close,
                gate_prob=gate_prob,
                gate_vwap=gate_vwap,
                gate_ema=gate_ema,
                gate_tod=gate_tod,
                gate_vwap_raw=gate_vwap_raw,
                gate_ema_raw=gate_ema_raw,
                gate_tod_raw=gate_tod_raw,
                gate_vwap_enabled=use_vwap,
                gate_ema_enabled=use_ema,
                gate_tod_enabled=use_tod,
                vwap=vwap,
                ema20=ema20,
                ema50=ema50,
                atr=atr,
                entry_bonus=entry_bonus,
                hold_bonus=hold_bonus,
            )
            return ev

        # ---- HOLD ----
        self._trace(
            ts=ts,
            action="HOLD",
            p=p,
            close=close,
            gate_prob=gate_prob,
            gate_vwap=gate_vwap,
            gate_ema=gate_ema,
            gate_tod=gate_tod,
            gate_vwap_raw=gate_vwap_raw,
            gate_ema_raw=gate_ema_raw,
            gate_tod_raw=gate_tod_raw,
            gate_vwap_enabled=use_vwap,
            gate_ema_enabled=use_ema,
            gate_tod_enabled=use_tod,
            vwap=vwap,
            ema20=ema20,
            ema50=ema50,
            atr=atr,
            entry_bonus=entry_bonus,
            hold_bonus=hold_bonus,
        )
        return None

    def _grade(self, p: float, side: int) -> str:
        if side > 0:
            if p >= PROB_BANDS["long"]["A+"]:
                return "A+"
            if p >= PROB_BANDS["long"]["B+"]:
                return "B+"
        else:
            if p <= PROB_BANDS["short"]["A+"]:
                return "A+"
            if p <= PROB_BANDS["short"]["B+"]:
                return "B+"
        return "C"

    def _make_event(
        self,
        typ: str,
        ts: pd.Timestamp,
        price: float,
        p: float,
        gate_prob: bool,
        gate_vwap: bool,
        gate_ema: bool,
        gate_tod: bool,
        atr: Optional[float] = None,
    ) -> Dict[str, Any]:
        side = ("LONG" if self.pos > 0 else ("SHORT" if self.pos < 0 else "FLAT"))
        stop = None
        target = None
        if atr and np.isfinite(atr):
            k = float(RISK_DEFAULTS.get("atr_k", 2.0) or 2.0)
            if self.pos > 0:
                stop = price - k * atr
                target = price + k * atr
            elif self.pos < 0:
                stop = price + k * atr
                target = price - k * atr
        else:
            band = price * 0.0025
            if self.pos > 0:
                stop = price - band
                target = price + band
            elif self.pos < 0:
                stop = price + band
                target = price - band

        ts_bar = _ensure_denver_naive(ts)
        ev = {
            "type": typ,
            "datetime": ts_bar.isoformat() if ts_bar is not None else None,
            "side": side,
            "price": float(price),
            "prob": float(p),
            "model_run_id": self.model_run_id,
            "grade": self._grade(p, +1 if self.pos > 0 else -1),
            "bars_in_trade": int(self.bars_in_trade),
            "gates": {
                "prob": bool(gate_prob),
                "vwap": bool(gate_vwap),
                "ema": bool(gate_ema),
                "tod": bool(gate_tod),
            },
            "risk": {
                "stop": float(stop) if stop is not None else None,
                "target": float(target) if target is not None else None,
            },
        }
        self._apply_contract_size(ev)
        return ev


