@dataclass
class EntryPolicyConfig:
    """Adaptive policy knobs for live streaming/Discord publishing."""

    news_blackout_before_min: int = 0
    news_blackout_after_min: int = 0
    news_impacts: Tuple[str, ...] = ()
    midday_pause: Optional[Tuple[str, str]] = None  # (start, end) in HH:MM (session tz)
    midday_trend_threshold: float = 0.65
    trend_window_bars: int = 6
    trend_threshold: float = 0.70
    chop_threshold: float = 0.40
    chop_range_threshold: float = 1.20
    mode_persist_bars: int = 3
    chop_preset: Optional[str] = None
    trend_preset: Optional[str] = None
    allow_countertrend_in_unresolved: bool = False
    allow_countertrend_fade_in_trend: bool = False
    countertrend_fade_min_vwap_extension_pts: float = 0.0
    countertrend_fade_prob_threshold: float = 0.30
    countertrend_fade_size_multiplier: float = 0.5
    countertrend_fade_pnl_giveback_activate_r: float = 0.0
    countertrend_fade_pnl_giveback_close_r: float = 0.0
    countertrend_fade_pnl_stall_bars: int = 0
