def _infer_orb_minutes_from_features(feature_names: Optional[Iterable[str]]) -> List[int]:
    windows: List[int] = []
    if not feature_names:
        return windows
    for name in feature_names:
        if not name:
            continue
        match = re.match(r"^orb(\d+)_", str(name))
        if match:
            value = int(match.group(1))
            if value not in windows:
                windows.append(value)
    return windows


def _parse_time_value(value: Any) -> Optional[dtime]:
    if value is None:
        return None
    if isinstance(value, dtime):
        return value
    if isinstance(value, (int, float)) and not isinstance(value, bool):
        minutes = int(value) % (24 * 60)
        return dtime(minutes // 60, minutes % 60)
    text = str(value).strip()
    if not text:
        return None
    if ":" in text:
        parts = [p for p in text.split(":") if p != ""]
        if len(parts) >= 2:
            try:
                hh, mm = (int(parts[0]), int(parts[1]))
                return dtime(hh % 24, mm % 60)
            except Exception:
                return None
    try:
        minutes = int(float(text)) % (24 * 60)
        return dtime(minutes // 60, minutes % 60)
    except Exception:
        return None


def _coerce_time_str(value: Any) -> Optional[str]:
    parsed = _parse_time_value(value)
    if parsed is None:
        return None
    return parsed.strftime("%H:%M")


def _parse_time_str(value: str) -> dtime:
    parsed = _parse_time_value(value)
    if parsed is None:
        raise ValueError(f"Invalid time format '{value}' (expected HH:MM)")
    return parsed


def _parse_pause_window(value: str) -> Tuple[str, str]:
    parts = [p.strip() for p in value.split("-") if p.strip()]
    if len(parts) != 2:
        raise ValueError(f"Invalid pause window '{value}' (expected HH:MM-HH:MM)")
    # Validate format (will raise if invalid)
    _ = _parse_time_str(parts[0])
    _ = _parse_time_str(parts[1])
    return parts[0], parts[1]

def _parse_weekdays_value(value: Any) -> Set[int]:
    """
    Parse weekdays into Python weekday integers (Mon=0..Sun=6).

    Accepts:
      - None / "" -> empty set
      - "fri" / "friday" / "mon,tue,fri"
      - [ "fri", "mon" ] / [4] / ["4"]
    """
    if value is None:
        return set()
    if isinstance(value, (set, list, tuple)):
        raw_items = list(value)
    else:
        text = str(value).strip()
        if not text:
            return set()
        raw_items = [p.strip() for p in re.split(r"[,\s]+", text) if p.strip()]

    aliases = {
        "mon": 0,
        "monday": 0,
        "tue": 1,
        "tues": 1,
        "tuesday": 1,
        "wed": 2,
        "weds": 2,
        "wednesday": 2,
        "thu": 3,
        "thur": 3,
        "thurs": 3,
        "thursday": 3,
        "fri": 4,
        "friday": 4,
        "sat": 5,
        "saturday": 5,
        "sun": 6,
        "sunday": 6,
    }
    out: Set[int] = set()
    for item in raw_items:
        if item is None:
            continue
        if isinstance(item, (int, float)) and not isinstance(item, bool):
            idx = int(item)
        else:
            token = str(item).strip().lower()
            if not token:
                continue
            if token in aliases:
                idx = aliases[token]
            else:
                try:
                    idx = int(token)
                except Exception:
                    continue
        if 0 <= idx <= 6:
            out.add(int(idx))
    return out


def _print_signals_pnl(signals_path: Path, instrument: Optional[str], tz: str, contracts: Optional[int]) -> None:
    instrument = (instrument or "ES").upper()
    tz = tz or "America/Denver"
    contracts = contracts or 1
    trades_path = signals_path.parent / "trades.csv"
    if trades_path.exists():
        if _print_trades_pnl(trades_path, instrument=instrument, tz=tz, default_contracts=int(contracts)):
            return
    if not signals_path.exists():
        logger.info("signals.csv not found at %s; skipping P&L summary.", signals_path)
        return
    try:
        raw = pd.read_csv(signals_path)
        if raw.empty or "type" not in raw.columns:
            logger.info("signals.csv contained no trades for %s.", instrument)
            return
        trade_like = raw[raw["type"].astype(str).str.upper().isin(["OPEN", "FLIP", "CLOSE", "EXIT"])]
        if trade_like.empty:
            logger.info("signals.csv contained no trades for %s.", instrument)
            return
    except Exception:
        # If the signals CSV is malformed, skip instead of raising during shutdown summary
        logger.info("signals.csv contained no trades for %s (unparseable).", instrument)
        return
    try:
        stats = compute_pnl_stats(
            str(signals_path),
            instrument=instrument,
            contracts=int(contracts),
            tz=tz,
        )
    except Exception as exc:  # pragma: no cover - logging only
        logger.warning("Failed to compute P&L from %s: %s", signals_path, exc)
        return
    trades = int(stats.get("num_trades", 0) or 0)
    if trades <= 0:
        logger.info("signals.csv contained no trades for %s.", instrument)
        return
    win_rate = float(stats.get("win_rate", 0.0) or 0.0) * 100.0
    total_pnl = float(stats.get("total_pnl", 0.0) or 0.0)
    max_dd = float(stats.get("max_drawdown", 0.0) or 0.0)
    avg_win = float(stats.get("avg_win", 0.0) or 0.0)
    avg_loss = float(stats.get("avg_loss", 0.0) or 0.0)
    max_daily_loss = float(stats.get("max_daily_loss", 0.0) or 0.0)
    profit_factor = stats.get("profit_factor")
    max_loss_streak = stats.get("max_loss_streak")
    logger.info("===== signals.csv P&L (%s) =====", instrument)
    logger.info(
        "Trades: %d | Win rate: %.2f%% | Total PnL: $%.2f | Max drawdown: $%.2f",
        trades,
        win_rate,
        total_pnl,
        max_dd,
    )
    logger.info(
        "Avg win: $%.2f | Avg loss: $%.2f | Max daily loss: $%.2f | PF: %s | Max loss streak: %s",
        avg_win,
        avg_loss,
        max_daily_loss,
        f"{profit_factor:.2f}" if isinstance(profit_factor, (int, float)) else "n/a",
        str(max_loss_streak),
    )


def _print_trades_pnl(trades_path: Path, instrument: str, tz: str, default_contracts: int) -> bool:
    """
    P&L computation from entry/exit-style trades.csv using per-trade qty sizing.
    """
    try:
        df = pd.read_csv(trades_path)
    except Exception as exc:  # pragma: no cover - logging only
        logger.warning("Failed to read trades.csv at %s: %s", trades_path, exc)
        return False
    if df.empty:
        logger.info("trades.csv is empty; skipping P&L fallback.")
        return False
    try:
        df = df.copy()
        df["symbol"] = instrument
        stats = compute_pnl_stats_from_trades(df, day_tz=tz)
    except Exception as exc:  # pragma: no cover - logging only
        logger.warning("Failed to compute P&L from trades.csv at %s: %s", trades_path, exc)
        return False
    trades = int(stats.get("num_trades", 0) or 0)
    if trades <= 0:
        logger.info("trades.csv contained no completed trades for %s.", instrument)
        return False
    win_rate = float(stats.get("win_rate", 0.0) or 0.0) * 100.0
    total_pnl = float(stats.get("total_pnl", 0.0) or 0.0)
    max_dd = float(stats.get("max_drawdown", 0.0) or 0.0)
    avg_win = float(stats.get("avg_win", 0.0) or 0.0)
    avg_loss = float(stats.get("avg_loss", 0.0) or 0.0)
    max_daily_loss = float(stats.get("max_daily_loss", 0.0) or 0.0)
    profit_factor = stats.get("profit_factor")
    max_loss_streak = stats.get("max_loss_streak")
    logger.info("===== trades.csv P&L (%s) =====", instrument)
    logger.info(
        "Trades: %d | Win rate: %.2f%% | Total PnL: $%.2f | Max drawdown: $%.2f",
        trades,
        win_rate,
        total_pnl,
        max_dd,
    )
    logger.info(
        "Avg win: $%.2f | Avg loss: $%.2f | Max daily loss: $%.2f | PF: %s | Max loss streak: %s",
        avg_win,
        avg_loss,
        max_daily_loss,
        f"{profit_factor:.2f}" if isinstance(profit_factor, (int, float)) else "n/a",
        str(max_loss_streak),
    )
    return True


def _derive_phase_thresholds(
    *,
    bar_interval_sec: float,
    currentness_lag_sec_threshold: Optional[float],
    backfill_lag_sec_threshold: Optional[float],
) -> Tuple[float, float]:
    interval = float(bar_interval_sec or 0.0)
    current_threshold = currentness_lag_sec_threshold
    if current_threshold is None:
        if interval > 0:
            current_threshold = min(120.0, max(1.0, interval / 2.0))
        else:
            current_threshold = 120.0
    backfill_threshold = backfill_lag_sec_threshold
    if backfill_threshold is None:
        if interval > 0:
            backfill_threshold = max(600.0, interval * 5.0)
        else:
            backfill_threshold = 1800.0
    return float(backfill_threshold), float(current_threshold)


def _next_phase_state(
    *,
    lag_sec: Optional[float],
    backfill_threshold_sec: float,
    current_threshold_sec: float,
    confirmations_required: int,
    confirmations_so_far: int,
) -> Tuple[str, int, bool]:
    if lag_sec is None:
        return "BACKFILL", 0, False
    lag_val = max(0.0, float(lag_sec))
    if lag_val >= backfill_threshold_sec:
        return "BACKFILL", 0, False
    if lag_val <= current_threshold_sec:
        confirmations = confirmations_so_far + 1
        if confirmations >= max(1, confirmations_required):
            return "LIVE", confirmations, True
        return "CATCHUP", confirmations, True
    return "CATCHUP", 0, False


def _resolve_prediction_id(entry: Mapping[str, Any]) -> str:
    prediction_id = str(entry.get("prediction_id") or "").strip()
    if prediction_id:
        return prediction_id
    fallback = str(entry.get("signal_id") or entry.get("client_order_id") or "").strip()
    return fallback or "MISSING_PREDICTION_ID"


