        run_mode_local = str(run_mode or ("replay" if offline_run else "live")).lower()
        if run_mode_local == "offline":
            run_mode_local = "replay"
        if nt_snapshot_operational_stale_sec is None:
            if run_mode_local == "live":
                self.nt_snapshot_operational_stale_sec = 15.0
            else:
                self.nt_snapshot_operational_stale_sec = 300.0
        else:
            self.nt_snapshot_operational_stale_sec = float(nt_snapshot_operational_stale_sec)
        # Align operational stale threshold with sync cadence to avoid
        # arm/disarm flapping when nt_sync_interval_sec is large (e.g., 30s).
        self.nt_snapshot_operational_stale_sec = max(
            float(self.nt_snapshot_operational_stale_sec or 0.0),
            float(self.nt_sync_interval_sec or 0.0) * 2.0,
        )
