        self._block_active: Dict[str, str] = {}
        self._block_last_detail: Dict[str, Dict[str, Any]] = {}
        self.lockout_path = Path(out_dir) / "lockout.json"
        self.run_id = str(uuid4())
        self._first_trade_block_code: Optional[str] = None
        self._first_trade_block_ts: Optional[str] = None
        self._first_trade_block_detail: Optional[Dict[str, Any]] = None
        self._current_block_code: Optional[str] = None
        self._current_block_ts: Optional[str] = None
        self._last_event_ts: Optional[str] = None
        self._lock_file = FileLock(Path(out_dir) / ".emit.lock")
        if reset_state and self._lock_file.path.exists():
            try:
                self._lock_file.path.unlink()
            except Exception:
                pass
        if self._lock_file.path.exists() and self.emit_lock_stale_sec > 0:
            age_sec = self._emit_lock_age_sec()
            if age_sec is not None and age_sec > self.emit_lock_stale_sec:
                try:
                    self._lock_file.path.unlink()
                    self._emit_block_event(
                        block_code="emit_lock_stale_recovered",
                        block_detail={"path": str(self._lock_file.path), "age_sec": age_sec},
                        owning_layer="execution",
                        operator_action="Stale emit lock cleared automatically.",
                    )
                except Exception:
                    pass
        try:
            self._lock_file.acquire()
            try:
                self._lock_file.path.write_text(self.run_id, encoding="utf-8", newline="\n")
            except Exception:
                pass
        except RuntimeError as exc:
            self._emit_block_event(
                block_code="emit_lock_active",
                block_detail={"path": str(self._lock_file.path), "error": str(exc)},
                owning_layer="execution",
                operator_action="Stop the other streamer or remove stale .emit.lock.",
            )
            self._write_status(force=True)
            raise
        self._load_lockout()
        try:
            if bool(getattr(self, "_hard_lockout_active", False)):
                _safe_print(
                    f"LOCKOUT_ACTIVE code={getattr(self, '_hard_lockout_code', None) or 'unknown'} "
                    f"clear_condition=next_session_open operator_action=explicit_reset"
                )
            else:
                _safe_print("LOCKOUT_CLEAR trading_permitted=1")
        except Exception:
            pass
        if not self.lockout_path.exists():
            try:
                stub = {
                    "run_id": self.run_id,
                    "lockout_code": None,
                    "lockout_detail": {},
                    "sticky": False,
                    "no_lockout_used": True,
                    "ts": utc_ts(),
                }
                self.lockout_path.write_text(
                    _json_dumps(stub, indent=2),
                    encoding="utf-8",
                    newline="\n",
                )
            except Exception:
                logger.debug("Failed to write lockout stub", exc_info=True)
        # Normalize common tz aliases to Olson names (e.g., "denver" â†’ "America/Denver")
        def _norm_tz(tz: Optional[str]) -> Optional[str]:
            if not tz:
                return tz
            low = tz.strip().lower()
            if low in {"denver", "america/denver", "mt", "mst", "mdt"}:
                return "America/Denver"
            return tz

        session_tz = _norm_tz(session_tz) or session_tz
