        self.time_mode = str(time_mode or "").lower()
        if self.time_mode not in {"wall_clock", "sim_clock"}:
            raise ValueError(f"Unsupported time_mode '{time_mode}' (use wall_clock|sim_clock)")
        if self.run_mode == "live" and self.time_mode != "wall_clock":
            raise ValueError("run_mode=live requires time_mode=wall_clock")
        if self.run_mode == "replay" and self.time_mode != "sim_clock":
            raise ValueError("run_mode=replay requires time_mode=sim_clock")
        # Input pinning (replay default)
        self.pin_input = bool(pin_input) if pin_input is not None else (self.run_mode == "replay")
        self.require_pinned_hash_match = (
            bool(require_pinned_hash_match)
            if require_pinned_hash_match is not None
            else (self.run_mode == "replay")
        )
        self.pinned_input_dir = Path(pinned_input_dir).expanduser() if pinned_input_dir else self.out_dir
        self.pinned_input_name = str(pinned_input_name or "pinned_input.csv")
        self.pinned_input_path = (self.pinned_input_dir / self.pinned_input_name).resolve()
        self.original_csv_sha256: Optional[str] = None
        self.pinned_csv_sha256: Optional[str] = None
        self.csv_path = self._apply_input_pinning(self.original_csv_path)
        self.determinism_probe_out_dir = (
            Path(determinism_probe_out_dir).expanduser() if determinism_probe_out_dir else None
        )
        self.live_dry_run = bool(live_dry_run)
        self.prop_guardrails = prop_guardrails
        self.prop_guardrails_enabled = prop_guardrails is not None
        self.prop_guardrails_config_path = str(prop_guardrails_config_path) if prop_guardrails_config_path else None
        self.prop_starting_balance = float(prop_starting_balance or 50000.0)
        self._prop_guardrails_started = False
        self._prop_last_volatility_state: Optional[VolatilityState] = None
        self._prop_last_volatility_log_ts: Optional[float] = None
        # Allow older live data at startup by default (3 days).
        self.freshness_threshold_sec = max(1.0, float(freshness_threshold_sec or 259200.0))
        self.resume_run_id = bool(resume_run_id)
        try:
            self.offline_threshold_min = max(0.0, float(offline_threshold_min))
        except Exception:
            self.offline_threshold_min = 600.0
        self.offline_threshold_sec = self.offline_threshold_min * 60.0
        self._offline_detected = False
        self._offline_reason: Optional[str] = None
        self._offline_delta_min: Optional[float] = None
        self._offline_last_flag: Optional[bool] = None
        self.allow_offline_paper_exec = bool(allow_offline_paper_exec)
        self.i_understand_offline_exec = bool(i_understand_offline_exec)
        self.i_know_what_im_doing = bool(i_know_what_im_doing)
        self._offline_exec_override = bool(self.i_understand_offline_exec or allow_offline_paper_exec)
        self.nt_reset_lockout_on_connect = bool(nt_reset_lockout_on_connect)
        self.replace_existing_run = bool(replace_existing_run)
        self._nt_lockout_reminder_sent = False
        self.auto_time_shift = bool(auto_time_shift)
        self.disable_risk = bool(disable_risk)
        try:
            self.auto_time_shift_max_min = max(0.0, float(auto_time_shift_max_min))
        except Exception:
            self.auto_time_shift_max_min = 90.0
        self._csv_time_shift_sec: Optional[float] = None
        self._csv_time_shift_auto = False
        self._csv_time_shift_hint_logged = False
        self._pending_trade_updates: Dict[str, Dict[str, Any]] = {}
        self._external_nt_cids: set[str] = set()
        self.state_path = self.out_dir / "stream_state.json"
        self.lockout_path = self.out_dir / "lockout.json"
        self.nt_bridge_log_path = self.out_dir / "nt_bridge.jsonl"
        self.signals_csv = self.out_dir / "signals.csv"
        self.signals_jsonl = self.out_dir / "signals.jsonl"
        self.events_jsonl = self.out_dir / "events.jsonl"
        self.blocked_candidates_path = self.out_dir / "blocked_candidates.jsonl"
        self.event_ledger_path = self.out_dir / "event_ledger.jsonl"
        self.status_path = self.out_dir / "status.json"
        self.input_provenance_path = self.out_dir / "input_provenance.json"
        self.trades_csv = self.out_dir / "trades.csv"
        self._trades_csv_lock = threading.Lock()
        self.state_stream_csv = self.out_dir / "state.csv"
        self.lifecycle_events_path = self.out_dir / "lifecycle_events.jsonl"
        self.lifecycle_events_csv_path = self.out_dir / "lifecycle_events.csv"
        self.areas_csv = self.out_dir / "areas.csv"
        self.policy_json_dir = self.out_dir / "policy"
        self.policy_json_dir.mkdir(parents=True, exist_ok=True)
        self.news_csv_path = Path(news_csv).expanduser() if news_csv else None
        self.news_source_tz = news_source_tz or session_tz
        # thresholds (persist for status gating)
        self.p_buy: float = float(p_buy if p_buy is not None else ENGINE.p_buy)
        self.p_sell: float = float(p_sell if p_sell is not None else ENGINE.p_sell)
        try:
            self.override_prob_min = float(override_prob_min) if override_prob_min is not None else 1.0
        except Exception:
            self.override_prob_min = 1.0
        try:
            self.override_hold_conf_min = float(override_hold_conf_min) if override_hold_conf_min is not None else 1.0
        except Exception:
            self.override_hold_conf_min = 1.0
        self.expected_features: Optional[List[str]] = None

        self.phase2_enabled = bool(phase2)
        if self.disable_safety_gates and self.phase2_enabled:
            logger.warning("Safety gates disabled; Phase-2 gating will be ignored.")
            self.phase2_enabled = False
        self.phase2_fail_open = bool(phase2_fail_open)
        self.phase2_setup_model_path = Path(phase2_setup_model_path).expanduser() if phase2_setup_model_path else None
        self.phase2_dir_model_path = Path(phase2_dir_model_path).expanduser() if phase2_dir_model_path else None
        self.phase2_close_enabled = bool(self.phase2_enabled) if phase2_close_enabled is None else bool(phase2_close_enabled)
        self.phase2_close_model_path = Path(phase2_close_model_path).expanduser() if phase2_close_model_path else None
        self.phase2_close_threshold = float(phase2_close_threshold if phase2_close_threshold is not None else 0.60)
        self.phase2_tag = phase2_tag
        self.phase2_feature_hash = phase2_feature_hash
        self.strict_feature_alignment = bool(self.phase2_enabled or self.phase2_feature_hash)
        self._validated_phase2_feature_hash = False
        self.phase2_p_setup = float(phase2_p_setup if phase2_p_setup is not None else 0.60)
        self.phase2_p_long = float(phase2_p_long if phase2_p_long is not None else self.p_buy)
        self.phase2_p_short = float(phase2_p_short if phase2_p_short is not None else 1.0 - self.p_sell)
        self.phase2_short_cut = 1.0 - self.phase2_p_long
        phase2_decision_policy_payload = (
            dict(phase2_decision_policy) if isinstance(phase2_decision_policy, Mapping) else {}
        )
        phase2_decision_policy_payload.setdefault("entry_trend_filter", entry_trend_filter)
        phase2_decision_policy_payload.setdefault(
            "min_signal_persistence_bars", min_signal_persistence_bars
        )
        phase2_decision_policy_payload.setdefault("cooldown_bars_after_flip", cooldown_bars_after_flip)
        self.phase2_decision_policy = Phase2DecisionPolicy.from_mapping(phase2_decision_policy_payload)
        self.phase2_setup_model: Optional[Any] = None
        self.phase2_setup_expected_features: Optional[List[str]] = None
        self.phase2_setup_calibrator: Optional[Any] = None
        self.phase2_setup_meta: Optional[Dict[str, Any]] = None
        self.phase2_setup_model_sha: Optional[str] = None
        self.phase2_dir_model: Optional[Any] = None
        self.phase2_dir_expected_features: Optional[List[str]] = None
        self.phase2_dir_calibrator: Optional[Any] = None
        self.phase2_dir_meta: Optional[Dict[str, Any]] = None
        self.phase2_dir_model_sha: Optional[str] = None
        self.phase2_close_model: Optional[Any] = None
        self.phase2_close_expected_features: Optional[List[str]] = None
        self.phase2_close_calibrator: Optional[Any] = None
        self.phase2_close_meta: Optional[Dict[str, Any]] = None
        self.phase2_close_model_sha: Optional[str] = None
        self._last_phase2_close_prob: Optional[float] = None
        self._phase2_setup_shap_cache: Optional[ShapExplainerCache] = None
        self._phase2_last_decisions: Dict[int, Phase2Decision] = {}
        self._phase2_error_logged = False
        if self.phase2_enabled and self.phase2_dir_model_path is None:
            try:
                self.phase2_dir_model_path = Path(self.model_path)
            except Exception:
                self.phase2_dir_model_path = None
        if self.phase2_enabled and self.phase2_close_enabled and self.phase2_close_model_path is None:
            default_close = PHASE2_CLOSE_MODEL_DEFAULT
            self.phase2_close_model_path = default_close if default_close.exists() else None
        if self.phase2_enabled:
            self._init_phase2_models()
            self.p_buy = self.phase2_p_long
            self.p_sell = self.phase2_short_cut

        # Areas of interest gating/targets
        self._areas_enabled = bool(use_areas_of_interest) and not self.disable_safety_gates
        self.areas_of_interest_config = Path(areas_of_interest_config).expanduser() if areas_of_interest_config else None
        self.areas_of_interest_levels = max(int(areas_of_interest_levels), 1)
        self.areas_of_interest_tolerance = max(float(areas_of_interest_tolerance), 0.0)
        self._areas_of_interest: List[AreaOfInterestLevel] = []
        self._areas_ready = False
        self._areas_warned = False
        self._areas_last_refresh: Optional[dt_type] = None
        if self._areas_enabled:
            self._load_areas_of_interest(reason="startup")

        # tracing & one-line status
        self.trace: bool = False
        self.status = StatusPrinter(bool(status_line), int(status_width))
        self.market_narrator_enabled = bool(market_narrator)
        self.market_narrator_tf = "5m"
        self._market_narrator_warned = False
        self._market_narrator_last_ts: Optional[pd.Timestamp] = None
        self._market_narrator_last_text: Optional[str] = None
        self._market_narrator_last_emitted_ts: Optional[pd.Timestamp] = None
        self._market_narrator_path = Path(self.out_dir) / "market_narrator.csv"
        if self.market_narrator_enabled:
            logger.info("Market narrator enabled (tf=%s).", self.market_narrator_tf)
            try:
                self._market_narrator_path.parent.mkdir(parents=True, exist_ok=True)
                if not self._market_narrator_path.exists():
                    self._market_narrator_path.write_text(
                        "ts_local,instrument,tf,price,narration\n",
                        encoding="utf-8",
                    )
            except Exception as exc:
                logger.warning("Failed to initialize market narrator CSV: %s", exc)

        self.nt_host = str(nt_host or "127.0.0.1")
        self.i_understand_multiport = bool(i_understand_multiport)
        self.nt_port = int(nt_port or 5019)
        allowed_ports = {5019}
        if self.nt_enabled and self.nt_port not in allowed_ports and not self.i_understand_multiport:
            raise RuntimeError(
                f"NT_PORT_POLICY_FAIL|expected=5019|actual={self.nt_port}|use=--i_understand_multiport"
            )
        self.nt_connect_timeout_sec = 120.0 if nt_connect_timeout_sec is None else float(nt_connect_timeout_sec)
        self.nt_snapshot_timeout_sec = float(nt_snapshot_timeout_sec or 120.0)
        self.nt_smoke_test_only = bool(nt_smoke_test_only)
        self.nt_account_mode = str(nt_account_mode or "cli").lower()
        if self.nt_account_mode not in {"cli", "auto", "none"}:
            raise ValueError(f"Unsupported nt_account_mode '{nt_account_mode}' (use cli|auto|none)")
        if self.nt_account_mode == "none":
            self.nt_account = None
        else:
            self.nt_account = str(nt_account or "Sim101") if nt_account is not None else None
            if self.nt_account_mode == "cli" and not self.nt_account:
                raise ValueError("--nt_account is required when --nt_account_mode cli is set")
        self._nt_account_configured = str(self.nt_account or "").strip() if self.nt_account is not None else None
        if self._nt_account_configured and self._nt_account_configured.lower() == "auto":
            self._nt_account_configured = "auto"
        self._nt_account_default = self.nt_account
        self._nt_account_mode_default = self.nt_account_mode
        self.nt_exec_policy_source = str(nt_exec_policy_source or "default")
        self.explicit_policy_flag_present = bool(
            explicit_policy_flag_present or nt_exec_policy_explicit or nt_proof_mode or allow_live_proof_override
        )
        self.allow_live_proof_override = bool(allow_live_proof_override)
        self.nt_required_account = str(nt_required_account).strip() if nt_required_account else None
        if nt_allowed_accounts:
            self.nt_allowed_accounts = [str(item).strip().upper() for item in nt_allowed_accounts if str(item).strip()]
        else:
            self.nt_allowed_accounts = []
        self.nt_account_autoresolve_policy = str(nt_account_autoresolve_policy or "use_ready").lower()
        self.nt_account_allow_prefix = str(nt_account_allow_prefix).strip() if nt_account_allow_prefix else None
        self.nt_account_allow_regex = str(nt_account_allow_regex).strip() if nt_account_allow_regex else None
        exec_policy = str(getattr(self, "nt_exec_policy", "") or "").lower()
        self._nt_account_expected_kind_explicit = nt_account_expected_kind is not None
        if nt_account_expected_kind is None:
            if self.run_mode == "replay":
                self.nt_account_expected_kind = "any"
            elif exec_policy in {"paper", "proof"}:
                self.nt_account_expected_kind = "any"
            else:
                self.nt_account_expected_kind = "live"
        else:
            self.nt_account_expected_kind = str(nt_account_expected_kind).strip().lower()
        self.nt_account_mismatch_max_sec = max(0.0, float(nt_account_mismatch_max_sec or 0.0))
        self.nt_account_mismatch_max_syncs = max(1, int(nt_account_mismatch_max_syncs or 1))
        self._account_mismatch_first_ts: Optional[float] = None
        self._account_mismatch_count = 0
        self._account_mismatch_last_ts: Optional[float] = None
        if nt_account_autoresolve is None:
            self.nt_account_autoresolve = bool(
                self.run_mode == "replay"
                or exec_policy in {"paper", "proof"}
                or str(getattr(self, "nt_adapter", "")).lower() == "mock"
            )
        else:
            self.nt_account_autoresolve = bool(nt_account_autoresolve)
        self._nt_account_detected: Optional[str] = None
        self._nt_account_detected_source: Optional[str] = None
        self._nt_account_chosen: Optional[str] = self._nt_account_configured if self._nt_account_configured != "auto" else None
        self._account_resolution_state: Optional[str] = None
        self._last_account_event_ts: Optional[str] = None
        self.nt_preflight_timeout_sec = float(nt_preflight_timeout_sec or 10.0)
        self.nt_stop_update_cooldown_sec = float(nt_stop_update_cooldown_sec or 5.0)
        self.max_fill_slippage_ticks = float(max_fill_slippage_ticks or 0.0)
        if self.prop_guardrails_enabled:
            try:
                unified_points = float(self.prop_guardrails.config.fill_slippage_max)
                if unified_points > 0 and float(self.tick_size or 0.0) > 0:
                    unified_ticks = unified_points / float(self.tick_size)
                    if self.max_fill_slippage_ticks <= 0:
                        self.max_fill_slippage_ticks = float(unified_ticks)
                    else:
                        self.max_fill_slippage_ticks = min(float(self.max_fill_slippage_ticks), float(unified_ticks))
            except Exception:
                logger.debug("Failed to align legacy fill slippage ticks with prop guardrails", exc_info=True)
        self.nt_exec_state = "DISARMED"
        self._nt_preflight_start_ts: Optional[float] = None
        self._nt_preflight_flatten_sent = False
        self._nt_cleanup_start_ts: Optional[float] = None
        self._nt_cleanup_flatten_sent = False
        self.nt_canonical_instrument: Optional[str] = None
        self._nt_last_pos_qty_by_instrument: Dict[str, float] = {}
        self._nt_stop_update_pending: Dict[str, Any] = {}
        self._nt_stop_update_last_by_instrument: Dict[str, Dict[str, Any]] = {}
        if self.nt_enabled:
            if nt_instrument is None:
                if self.run_mode == "live":
                    raise ValueError(
                        "NT instrument is required when --nt_enable is set in live mode "
                        '(e.g., --nt_instrument "ES 03-26").'
                    )
                logger.warning("NT instrument not provided; will resolve from POSITION_SNAPSHOT in replay.")
                self.nt_instrument = None
            else:
                self.nt_instrument = _validate_nt_instrument_name(str(nt_instrument))
                import re as _re
                full_instr_pattern = _re.compile(r"^[A-Z]{1,4} (\d{2}-\d{2}|[A-Z]{3}\d{2})$")
                if not full_instr_pattern.match(self.nt_instrument):
                    raise ValueError(
                        f"NT instrument must be full contract (e.g., ES 03-26 or ES MAR26); got '{self.nt_instrument}'"
                    )
        else:
            self.nt_instrument = (
                _validate_nt_instrument_name(str(nt_instrument))
                if nt_instrument
                else str(self.instrument_alias or "").strip()
            )
        # Preserve the configured NT instrument (CLI) for debugging even if we later
        # override canonical instruments from snapshots.
        self._nt_instrument_configured = self.nt_instrument
        self.exec_instrument = self.nt_instrument or str(self.instrument_alias or "").strip() or None
        self.exec_instrument_source = "cli" if self.exec_instrument else None
        self.nt_order_type = str(nt_order_type or "MARKET").upper()
        self.nt_flatten_on_close = bool(nt_flatten_on_close)
        self.nt_wait_for_connection = bool(nt_wait_for_connection)
        self.nt_connect_timeout_sec = 120.0 if nt_connect_timeout_sec is None else float(nt_connect_timeout_sec)
        self.nt_snapshot_timeout_sec = float(nt_snapshot_timeout_sec or 120.0)
        if nt_snapshot_timeout_fatal is None:
            env_fatal = str(os.getenv("NINJAREPO_NT_SNAPSHOT_TIMEOUT_FATAL", "") or "").strip().lower()
            self.nt_snapshot_timeout_fatal = env_fatal in {"1", "true", "yes", "y"}
        else:
            self.nt_snapshot_timeout_fatal = bool(nt_snapshot_timeout_fatal)
        self.nt_smoke_test_only = bool(nt_smoke_test_only)
        if nt_require_snapshot is None:
            self.nt_require_snapshot = bool(self.nt_enabled)
        else:
            self.nt_require_snapshot = bool(nt_require_snapshot)
        if nt_require_ref_price is None:
            self.nt_require_ref_price = True
        else:
            self.nt_require_ref_price = bool(nt_require_ref_price)
        # QA smoke scenarios do not provide a reliable reference price.
        if self.qa_emit_signals and self.nt_enabled:
            self.nt_require_ref_price = False
        self._nt_exec_policy_default = "paper" if self.nt_enabled else "disabled"
        requested_policy = str(nt_exec_policy).lower() if nt_exec_policy is not None else None
        requested_policy_explicit = bool(nt_exec_policy_explicit or nt_proof_mode)
        if nt_proof_mode and not nt_exec_policy_explicit:
            requested_policy = "proof"
        self._requested_nt_exec_policy = requested_policy
        self._requested_nt_exec_policy_explicit = requested_policy_explicit
        policy = str(nt_exec_policy or self._nt_exec_policy_default).lower()
        if policy not in {"disabled", "proof", "paper", "live"}:
            raise ValueError(f"Unsupported nt_exec_policy '{nt_exec_policy}' (use disabled|proof|paper|live)")
        self._nt_exec_policy_explicit = bool(nt_exec_policy_explicit or nt_proof_mode)
        if nt_proof_mode and not nt_exec_policy_explicit:
            policy = "proof"
        elif nt_proof_mode and nt_exec_policy_explicit and policy != "proof":
            logger.warning("Both --nt_proof_mode and --nt_exec_policy set; honoring --nt_exec_policy=%s", policy)
        self.nt_exec_policy = policy
        if (
            bool(getattr(self, "offline_run", False))
            and bool(getattr(self, "nt_enabled", False))
            and str(self.nt_exec_policy).lower() in {"paper", "live"}
            and not bool(getattr(self, "i_understand_offline_exec", False))
        ):
            raise RuntimeError(
                "offline_run + nt_exec_policy=paper requires --i_understand_offline_exec because it can send orders."
            )
        self._nt_exec_policy_auto = False
        self.nt_proof_mode = policy == "proof"
        self._validate_exec_policy_guard()
        exec_mode_raw = str(execution_mode or "standard").lower()
        exec_mode_aliases = {
            "model_master": "model_master",
            "model_master_mode": "model_master",
            "model_master_hold": "model_master",
        }
        self.execution_mode = exec_mode_aliases.get(exec_mode_raw, exec_mode_raw)
        if self.execution_mode not in {"standard", "model_master"}:
            raise ValueError(
                "Unsupported execution_mode '%s' (use standard|model_master)" % execution_mode
            )
        default_protection = "stop_only" if self.execution_mode == "model_master" else "stop_and_target"
        protection_aliases = {
            "stop_only_until_model": "stop_only_until_model_close_allowed",
            "stop_only_until_model_close": "stop_only_until_model_close_allowed",
        }
        protection_mode_raw = str(protection_mode or default_protection).lower()
        self.protection_mode = protection_aliases.get(protection_mode_raw, protection_mode_raw)
        if self.protection_mode not in {"stop_only", "stop_and_target", "stop_only_until_model_close_allowed"}:
            raise ValueError(
                "Unsupported protection_mode '%s' (use stop_only|stop_and_target|stop_only_until_model_close_allowed)"
                % protection_mode
            )
        if self.execution_mode == "model_master":
            if self.protection_mode == "stop_and_target":
                logger.info(
                    "execution_mode=model_master honoring protection_mode=stop_and_target for parity-oriented runs"
                )
            if self.close_on_bracket_only and not self._close_on_bracket_only_explicit:
                logger.warning(
                    "execution_mode=model_master forcing close_on_bracket_only=False to honor model CLOSE signals"
                )
                self.close_on_bracket_only = False
        self.allow_replay_exec_to_nt = bool(allow_replay_exec_to_nt)
        self.replay_local_sim = True if replay_local_sim is None else bool(replay_local_sim)
        self.replay_reset_state = True if replay_reset_state is None else bool(replay_reset_state)
        self.replay_emit_legacy_sim_close = bool(replay_emit_legacy_sim_close)
        self.replay_exec_pacing = str(replay_exec_pacing).lower() if replay_exec_pacing else None
        self.replay_exec_min_interval_sec = (
            float(replay_exec_min_interval_sec) if replay_exec_min_interval_sec is not None else None
        )
        self.replay_exec_stepper_path = (
            Path(replay_exec_stepper_path).expanduser() if replay_exec_stepper_path else None
        )
        self._replay_exec_last_send_ts: Optional[float] = None
        self._replay_exec_last_step: Optional[int] = None
        self.nt_replay_wait_for_last_bar = bool(nt_replay_wait_for_last_bar)
        self.pending_timeout_sec = 120
        self._pending_until: Optional[pd.Timestamp] = None
        self._pending_client_order_id: Optional[str] = None
        self._consec_errors: int = 0
        self.max_daily_loss_usd: Optional[float] = None
        self.max_daily_drawdown_usd: Optional[float] = None
        self.max_position_contracts: Optional[int] = None
        self.max_risk_usd_per_trade: Optional[float] = None
        self.max_losses_per_day: Optional[int] = None
        self._max_losses_per_day_cli_explicit = max_losses_per_day is not None
