    def _validate_artifact_run_id_consistency(self) -> None:
        if not bool(getattr(self, "enforce_integrity_gate", True)):
            return
        if bool(getattr(self, "resume_run_id", False)):
            return
        mismatches: List[Dict[str, Any]] = []
        targets = [
            ("signals", getattr(self, "signals_jsonl", None)),
            ("signal_to_order", getattr(self, "signal_to_order_path", None)),
            ("order_events", getattr(self, "order_events_path", None)),
        ]
        for label, path in targets:
            if path is None:
                continue
            file_path = Path(path)
            if not file_path.exists() or file_path.stat().st_size <= 0:
                continue
            try:
                lines = file_path.read_text(encoding="utf-8").splitlines()[:250]
            except Exception:
                continue
            for idx, line in enumerate(lines, start=1):
                try:
                    payload = json.loads(line)
                except Exception:
                    continue
                row_run_id = str(payload.get("run_id") or "").strip()
                if row_run_id and row_run_id != self.run_id:
                    mismatches.append(
                        {
                            "artifact": label,
                            "path": str(file_path),
                            "line": idx,
                            "expected_run_id": self.run_id,
                            "found_run_id": row_run_id,
                        }
                    )
                    break
        if mismatches:
            first = mismatches[0]
            self._log_exec_event({"event": "artifact_run_id_mismatch", "mismatch": first, "count": len(mismatches)})
            raise RuntimeError(
                f"RUN_ARTIFACT_INTEGRITY_FAIL artifact={first['artifact']} line={first['line']} "
                f"expected={self.run_id} found={first['found_run_id']}"
            )

