    def _is_execution_policy_block_reason(self, reason: Optional[str]) -> bool:
        reason_txt = str(reason or "").strip().lower()
        if not reason_txt:
            return False
        return reason_txt in {
            "past_bar_emit",
            "replay_exec_blocked",
            "offline_exec_blocked",
            "replay_wait_for_last_bar",
            "exec_policy_blocked",
            "proof_only",
            "blocked_not_armed",
            "blocked_offline_exec_policy",
            "not_armed",
            "nt_not_ready",
            "blocked_stale_bar",
            "stale_bar",
        }

    def _has_execution_policy_block(
        self,
        *,
        reason: Optional[str],
        blocked_by: Optional[Sequence[Any]] = None,
    ) -> bool:
        replay_eval_mode = self._is_replay_local_sim_active()

        def _is_blocking_token(token_txt: str) -> bool:
            if not token_txt:
                return False
            if replay_eval_mode and token_txt in {"blocked_stale_bar", "stale_bar"}:
                return False
            return self._is_execution_policy_block_reason(token_txt)

        reason_token = str(reason or "").strip().lower()
        if _is_blocking_token(reason_token):
            return True
        for raw in blocked_by or []:
            token = str(raw or "").strip().lower()
            if not token:
                continue
            if _is_blocking_token(token):
                return True
            if ":" in token:
                suffix = token.split(":", 1)[1].strip()
                if _is_blocking_token(suffix):
                    return True
        return False

    def _is_replay_eval_candidate(
        self,
        *,
        decision: str,
        reason: Optional[str],
        action: Optional[str],
        blocked_by: Optional[Sequence[Any]] = None,
    ) -> bool:
        run_mode = str(getattr(self, "run_mode", "live") or "live").lower()
        if run_mode not in {"replay", "offline"}:
            return False
        if str(decision or "").upper() != "BLOCKED":
            return False
        action_upper = str(action or "").upper()
        if action_upper not in {"OPEN", "FLIP", "CLOSE", "EXIT"}:
            return False
        if action_upper in {"OPEN", "FLIP"} and not bool(getattr(self, "allow_replay_exec_to_nt", False)):
            return True
        return self._has_execution_policy_block(reason=reason, blocked_by=blocked_by)

    def _log_signal_to_order(
        self,
        *,
        bar_ts: Optional[pd.Timestamp],
        signal_action: str,
        client_order_id: str,
        sent_to_nt: bool,
        blocked_by: Sequence[str],
        extra: Optional[Mapping[str, Any]] = None,
    ) -> None:
        if not self._phase_allows_execution():
            self._signal_to_order_outside_live_count += 1
            return
        if not client_order_id:
            return
        if not self._signal_to_order_header_written:
            self._init_signal_to_order_log()
        extra_map = dict(extra or {})
        blocked_by_list = list(blocked_by or [])
        signal_action_upper = str(signal_action or "").upper()
        decision = str(extra_map.get("decision") or extra_map.get("executor_decision") or ("SENT" if sent_to_nt else "BLOCKED")).upper()
        reason = (
            extra_map.get("reason")
            or extra_map.get("reason_code")
            or extra_map.get("block_reason")
            or (blocked_by_list[0] if blocked_by_list else None)
        )
        run_mode = str(getattr(self, "run_mode", "live") or "live").lower()
        replay_blocked_open_visibility = bool(
            run_mode in {"replay", "offline"}
            and not bool(getattr(self, "allow_replay_exec_to_nt", False))
            and decision == "BLOCKED"
            and signal_action_upper in {"OPEN", "FLIP"}
        )
        blocked_for_execution = bool(extra_map.get("blocked_for_execution"))
        if not blocked_for_execution:
            blocked_for_execution = bool(
                decision == "BLOCKED" and self._has_execution_policy_block(reason=reason, blocked_by=blocked_by_list)
            )
        accepted_for_sim_evaluation = bool(extra_map.get("accepted_for_sim_evaluation"))
        if not accepted_for_sim_evaluation:
            accepted_for_sim_evaluation = replay_blocked_open_visibility or self._is_replay_eval_candidate(
                decision=decision,
                reason=reason,
                action=signal_action_upper,
                blocked_by=blocked_by_list,
            )
        if blocked_for_execution:
            self._executor_stats["blocked_for_execution_total"] = int(
                self._executor_stats.get("blocked_for_execution_total", 0) or 0
            ) + 1
        if accepted_for_sim_evaluation:
            self._executor_stats["accepted_for_sim_evaluation_total"] = int(
                self._executor_stats.get("accepted_for_sim_evaluation_total", 0) or 0
            ) + 1
        payload: Dict[str, Any] = {
            "ts": utc_ts(),
            "run_id": self.run_id,
            "instrument": self.instrument_alias,
            "bar_ts": _canonical_ts_str(bar_ts) if bar_ts is not None else None,
            "signal_action": signal_action_upper,
            "action": signal_action_upper,
            "client_order_id": str(client_order_id),
            "sent_to_nt": bool(sent_to_nt),
            "blocked_by": blocked_by_list,
            "decision": decision,
            "reason": str(reason) if reason is not None else "",
            "phase": str(extra_map.get("phase") or getattr(self, "_phase", None) or ""),
            "side": str(extra_map.get("side") or ""),
            "prob": extra_map.get("prob"),
            "final_action": str(extra_map.get("final_action") or signal_action_upper),
            "emit_allowed": bool(extra_map.get("emit_allowed", sent_to_nt)),
            "blocked_for_execution": bool(blocked_for_execution),
            "accepted_for_sim_evaluation": bool(accepted_for_sim_evaluation),
        }
        if extra_map:
            payload.update({k: v for k, v in extra_map.items() if v is not None})
        payload.setdefault("requested_action", signal_action_upper)
        payload.setdefault("resolved_action", str(payload.get("final_action") or signal_action_upper).upper())
        payload.setdefault(
            "execution_intent_action",
            str(payload.get("execution_intent_action") or payload.get("resolved_action") or signal_action_upper).upper(),
        )
        strategy_blocked_reason = payload.get("strategy_blocked_reason")
        execution_blocked_reason = payload.get("execution_blocked_reason")
        strategy_gate_result = payload.get("strategy_gate_result")
        if strategy_gate_result is None:
            strategy_gate_result = "blocked" if strategy_blocked_reason else "pass"
            payload["strategy_gate_result"] = strategy_gate_result
        if payload.get("strategy_session_state") is None:
            payload["strategy_session_state"] = "blocked" if str(strategy_blocked_reason or "") == "session" else "pass"
        if payload.get("execution_send_allowed") is None:
            payload["execution_send_allowed"] = bool(
                sent_to_nt
                if strategy_gate_result == "pass"
                else False
            )
        if payload.get("execution_gate_result") is None:
            if strategy_gate_result != "pass":
                payload["execution_gate_result"] = "deferred_by_strategy"
            else:
                payload["execution_gate_result"] = "pass" if payload["execution_send_allowed"] else (
                    "blocked" if execution_blocked_reason else "blocked"
                )
        payload.setdefault("transition_id", str(payload.get("transition_id") or client_order_id or ""))
        payload.setdefault("transition_step", str(payload.get("transition_step") or "").lower())
        if signal_action_upper == "FLIP" and not bool(sent_to_nt):
            transition_id = str(payload.get("transition_id") or client_order_id or "")
            base_rows = [("CLOSE", "close"), ("OPEN", "open")]
            for resolved_action, step in base_rows:
                row_payload = dict(payload)
                row_payload["signal_action"] = resolved_action
                row_payload["action"] = resolved_action
                row_payload["requested_action"] = "FLIP"
                row_payload["resolved_action"] = resolved_action
                row_payload["execution_intent_action"] = str(
                    row_payload.get("execution_intent_action") or resolved_action
                ).upper()
                row_payload["transition_id"] = transition_id
                row_payload["transition_step"] = step
                self._write_jsonl(self.signal_to_order_path, row_payload)
            return
        self._write_jsonl(self.signal_to_order_path, payload)

    def _write_lifecycle_event_helper(self, canonical_record: Dict[str, Any], bar_ts: Optional[Any] = None) -> None:
        """
        Phase 3: Write a canonical lifecycle event to lifecycle_events.jsonl.

        Args:
            canonical_record: Dict with lifecycle record from Phase 1 canonical_lifecycle_record()
            bar_ts: Bar timestamp for the event
        """
        try:
            if canonical_record is None:
                return

            self._ensure_lifecycle_paths()

            # Use dedupe key to prevent duplicate writes
            dedupe_key = f"{bar_ts}|{canonical_record.get('signal_id')}|{canonical_record.get('requested_action')}"
            if dedupe_key in self._lifecycle_event_dedupe:
                return
            self._lifecycle_event_dedupe.add(dedupe_key)

            # Format the lifecycle event entry
            if _LIFECYCLE_CANONICALIZATION_AVAILABLE:
                try:
                    from na.discord_addons.cli.lifecycle_canonicalization import _write_lifecycle_event
                    entry = _write_lifecycle_event(record=canonical_record, bar_ts=bar_ts)
                except Exception:
                    # Fallback to manual construction if Phase 1 helper not available
                    entry = {
                        "ts": dt_type.utcnow().isoformat(),
                        "bar_ts": str(bar_ts) if bar_ts is not None else None,
                        "phase": canonical_record.get("phase", "LIVE"),
                        "requested_action": canonical_record.get("requested_action"),
                        "resolved_action": canonical_record.get("resolved_action"),
                        "execution_intent_action": canonical_record.get("execution_intent_action"),
                        "display_action": canonical_record.get("display_action"),
                        "side": canonical_record.get("side"),
                        "price": canonical_record.get("price"),
                        "prob": canonical_record.get("prob"),
                        "emit_allowed": canonical_record.get("emit_allowed"),
                        "publish_ready": canonical_record.get("publish_ready"),
                        "blocked_reason": canonical_record.get("blocked_reason"),
                        "blocked_by": canonical_record.get("blocked_by", []),
                        "transition_id": canonical_record.get("transition_id"),
                        "transition_step": canonical_record.get("transition_step"),
                        "signal_id": canonical_record.get("signal_id"),
                        "client_order_id": canonical_record.get("client_order_id"),
                        "source": canonical_record.get("source", "model"),
                        "dedupe_key": dedupe_key,
                    }
            else:
                # Fallback when Phase 1 not available
                entry = {
                    "ts": dt_type.utcnow().isoformat(),
                    "bar_ts": str(bar_ts) if bar_ts is not None else None,
                    "phase": canonical_record.get("phase", "LIVE"),
                    "requested_action": canonical_record.get("requested_action"),
                    "resolved_action": canonical_record.get("resolved_action"),
                    "execution_intent_action": canonical_record.get("execution_intent_action"),
                    "display_action": canonical_record.get("display_action"),
                    "side": canonical_record.get("side"),
                    "price": canonical_record.get("price"),
                    "prob": canonical_record.get("prob"),
                    "emit_allowed": canonical_record.get("emit_allowed"),
                    "publish_ready": canonical_record.get("publish_ready"),
                    "blocked_reason": canonical_record.get("blocked_reason"),
                    "blocked_by": canonical_record.get("blocked_by", []),
                    "transition_id": canonical_record.get("transition_id"),
                    "transition_step": canonical_record.get("transition_step"),
                    "signal_id": canonical_record.get("signal_id"),
                    "client_order_id": canonical_record.get("client_order_id"),
                    "source": canonical_record.get("source", "model"),
                    "dedupe_key": dedupe_key,
                }

            # Write to JSONL
            self._write_jsonl(self.lifecycle_events_path, entry)
        except Exception as e:
            logger.debug(f"Failed to write lifecycle event: {e}")

    def _ensure_lifecycle_paths(self) -> None:
        if not hasattr(self, "lifecycle_events_path"):
            self.lifecycle_events_path = Path("lifecycle_events.jsonl")
        if not hasattr(self, "lifecycle_events_csv_path"):
            self.lifecycle_events_csv_path = Path("lifecycle_events.csv")
        if not isinstance(getattr(self, "_lifecycle_event_dedupe", None), set):
            self._lifecycle_event_dedupe = set()
        try:
            self.lifecycle_events_csv_path.parent.mkdir(parents=True, exist_ok=True)
            if not self.lifecycle_events_csv_path.exists():
                with self.lifecycle_events_csv_path.open("w", encoding="utf-8", newline="\n") as fh:
                    csv.writer(fh, lineterminator="\n").writerow(LIFECYCLE_EVENT_CSV_COLUMNS)
        except Exception as exc:
            logger.debug("Failed to initialize lifecycle csv header", exc_info=True)
            self._handle_io_failure(context=str(self.lifecycle_events_csv_path), exc=exc)

    def _lifecycle_bool_text(self, value: Any) -> str:
        if value is None:
            return ""
        return "1" if bool(value) else "0"

    def _canonical_lifecycle_record(
        self,
        *,
        ts: Any,
        action: str,
        side: str,
        price: Any,
        prob: Any,
        state_meta: Optional[Mapping[str, Any]] = None,
        source: str,
    ) -> Dict[str, Any]:
        meta = dict(state_meta or {})
        display_action = str(meta.get("display_action") or action or "").upper()
        requested_action = str(
            meta.get("requested_action")
            or meta.get("blocked_candidate_action")
            or meta.get("original_action")
            or action
            or ""
        ).upper()
        resolved_action = str(
            meta.get("resolved_action")
            or meta.get("final_action")
            or meta.get("execution_intent_action")
            or requested_action
        ).upper()
        execution_intent_action = str(
            meta.get("execution_intent_action")
            or meta.get("final_action")
            or resolved_action
        ).upper()
        signal_id = meta.get("signal_id")
        client_order_id = meta.get("client_order_id")
        transition_id = str(meta.get("transition_id") or client_order_id or signal_id or "")
        transition_step = str(meta.get("transition_step") or "").lower()
        blocked_reason = str(
            meta.get("blocked_reason")
            or meta.get("blocked_candidate_reason")
            or meta.get("policy_block")
            or ""
        )
        payload: Dict[str, Any] = {
            "ts": utc_ts(),
            "bar_ts": _canonical_ts_str(ts) if ts is not None else "",
            "phase": str(meta.get("phase") or getattr(self, "_phase", None) or ""),
            "requested_action": requested_action,
            "resolved_action": resolved_action,
            "display_action": display_action,
            "execution_intent_action": execution_intent_action,
            "side": str(side or "").upper(),
            "price": price,
            "prob": prob,
            "emit_allowed": bool(meta.get("emit_allowed")) if meta.get("emit_allowed") is not None else None,
            "publish_ready": bool(meta.get("publish_ready")) if meta.get("publish_ready") is not None else None,
            "blocked_reason": blocked_reason,
            "transition_id": transition_id,
            "transition_step": transition_step,
            "signal_id": str(signal_id or ""),
            "client_order_id": str(client_order_id or ""),
            "source": source,
            "feature_hash": str(meta.get("feature_hash") or meta.get("features_hash") or ""),
            "model_version": str(meta.get("model_version") or self.model_sha or self.model_path or "unknown"),
            "config_hash": str(meta.get("config_hash") or self._compute_config_hash() or ""),
            "raw_model_output": meta.get("raw_model_output"),
        }
        payload["dedupe_key"] = _row_hash_from_mapping(
            {
                "bar_ts": payload.get("bar_ts"),
                "phase": payload.get("phase"),
                "requested_action": payload.get("requested_action"),
                "resolved_action": payload.get("resolved_action"),
                "display_action": payload.get("display_action"),
                "execution_intent_action": payload.get("execution_intent_action"),
                "side": payload.get("side"),
                "price": payload.get("price"),
                "transition_id": payload.get("transition_id"),
                "transition_step": payload.get("transition_step"),
                "signal_id": payload.get("signal_id"),
                "client_order_id": payload.get("client_order_id"),
                "source": payload.get("source"),
            }
        )
        return payload

    def _append_lifecycle_record(self, payload: Mapping[str, Any]) -> None:
        self._ensure_lifecycle_paths()
        dedupe_key = str(payload.get("dedupe_key") or "")
        if dedupe_key and dedupe_key in self._lifecycle_event_dedupe:
            return
        record = dict(payload)
        self._write_jsonl(self.lifecycle_events_path, record)
        try:
            with self.lifecycle_events_csv_path.open("a", encoding="utf-8", newline="\n") as fh:
                writer = csv.writer(fh, lineterminator="\n")
                writer.writerow([
                    record.get("ts", ""),
                    record.get("bar_ts", ""),
                    record.get("phase", ""),
                    record.get("requested_action", ""),
                    record.get("resolved_action", ""),
                    record.get("display_action", ""),
                    record.get("execution_intent_action", ""),
                    record.get("side", ""),
                    record.get("price", ""),
                    record.get("prob", ""),
                    self._lifecycle_bool_text(record.get("emit_allowed")),
                    self._lifecycle_bool_text(record.get("publish_ready")),
                    record.get("blocked_reason", ""),
                    record.get("transition_id", ""),
                    record.get("transition_step", ""),
                    record.get("signal_id", ""),
                    record.get("client_order_id", ""),
                    record.get("source", ""),
                    record.get("dedupe_key", ""),
                ])
                try:
                    fh.flush()
                    os.fsync(fh.fileno())
                except Exception:
                    pass
            if dedupe_key:
                self._lifecycle_event_dedupe.add(dedupe_key)
            if str(record.get("source") or "") == "state_projection":
                try:
                    self._append_decision_event_csv(
                        canonical_record=record,
                        source_file=str(Path(__file__).resolve()),
                        source_module="na.discord_addons.cli.stream_live_csv",
                        accepted_for_execution=bool(record.get("emit_allowed", True)),
                        rejection_reason=str(record.get("blocked_reason") or ""),
                        raw_model_output=record.get("prob"),
                    )
                except Exception:
                    logger.debug("Failed to append decision event csv", exc_info=True)
        except Exception as exc:
            logger.debug("Failed to append lifecycle record", exc_info=True)
            self._handle_io_failure(context=str(self.lifecycle_events_csv_path), exc=exc)

    def _infer_position_before_after(self, payload: Mapping[str, Any]) -> Tuple[Optional[int], Optional[int]]:
        action = str(payload.get("requested_action") or payload.get("resolved_action") or payload.get("display_action") or "").upper()
        side = str(payload.get("side") or "").upper()
        try:
            position_after = int(getattr(self, "_pos", 0) or 0)
        except Exception:
            position_after = 0 if side == "FLAT" else (1 if side == "LONG" else (-1 if side == "SHORT" else None))
        position_before = None
        if action == "OPEN":
            position_before = 0
        elif action == "CLOSE":
            position_before = -position_after if isinstance(position_after, int) and position_after != 0 else (1 if side == "LONG" else -1 if side == "SHORT" else None)
        elif action == "FLIP":
            if isinstance(position_after, int) and position_after != 0:
                position_before = -position_after
            else:
                position_before = 0
        elif action == "HOLD":
            position_before = position_after
        else:
            position_before = position_after
        return position_before, position_after

    def _append_decision_event_csv(
        self,
        *,
        canonical_record: Mapping[str, Any],
        source_file: str,
        source_module: str,
        accepted_for_execution: bool,
        rejection_reason: Optional[str] = None,
        raw_model_output: Optional[Any] = None,
    ) -> None:
        self._ensure_compat_defaults()
        path = getattr(self, "decision_events_path", None)
        if path is None:
            return
        mode = str(canonical_record.get("phase") or getattr(self, "run_mode", "LIVE") or "LIVE").upper()
        position_before, position_after = self._infer_position_before_after(canonical_record)
        event_created_ts = utc_ts()
        feature_hash = str(canonical_record.get("feature_hash") or canonical_record.get("features_hash") or "")
        model_version = str(
            canonical_record.get("model_version")
            or self.model_sha
            or self.model_path
            or "unknown"
        )
        payload = {
            "event_id": str(
                _row_hash_from_mapping(
                    {
                        "bar_ts": canonical_record.get("bar_ts"),
                        "phase": mode,
                        "requested_action": canonical_record.get("requested_action"),
                        "resolved_action": canonical_record.get("resolved_action"),
                        "transition_id": canonical_record.get("transition_id"),
                        "signal_id": canonical_record.get("signal_id"),
                        "client_order_id": canonical_record.get("client_order_id"),
                    }
                )
            ),
            "bar_ts": canonical_record.get("bar_ts"),
            "event_created_ts": event_created_ts,
            "mode": mode,
            "model_version": model_version,
            "config_hash": str(canonical_record.get("config_hash") or self._compute_config_hash() or ""),
            "feature_hash": feature_hash,
            "raw_model_output": raw_model_output if raw_model_output is not None else canonical_record.get("prob"),
            "probability": canonical_record.get("prob"),
            "requested_action": canonical_record.get("requested_action"),
            "resolved_action": canonical_record.get("resolved_action"),
            "execution_intent_action": canonical_record.get("execution_intent_action"),
            "position_before": position_before,
            "position_after": position_after,
            "transition_id": canonical_record.get("transition_id"),
            "signal_id": canonical_record.get("signal_id"),
            "dedupe_key": canonical_record.get("dedupe_key") or _row_hash_from_mapping(
                {
                    "bar_ts": canonical_record.get("bar_ts"),
                    "transition_id": canonical_record.get("transition_id"),
                    "signal_id": canonical_record.get("signal_id"),
                    "requested_action": canonical_record.get("requested_action"),
                    "resolved_action": canonical_record.get("resolved_action"),
                    "source_file": source_file,
                }
            ),
            "accepted_for_execution": _csv_bool(accepted_for_execution),
            "rejection_reason": rejection_reason or "",
            "source_file": source_file,
            "source_module": source_module,
        }
        _append_csv_row(path, DECISION_EVENTS_CSV_COLUMNS, payload)

    def _append_order_intent_rows(
        self,
        *,
        intent: ExecutionIntent,
        decision: str,
        reason_code: str,
        nt_order_ids: Optional[Sequence[str]] = None,
        rejection_reason: Optional[str] = None,
    ) -> None:
        self._ensure_compat_defaults()
        path = getattr(self, "order_intents_path", None)
        if path is None:
            return
        mode = str(getattr(self, "run_mode", "LIVE") or "LIVE").upper()
        action = str(intent.action or "").upper()
        base_transition = str(intent.intent_id or intent.correlation_id or intent.signal_id or "").split(".", 1)[0]
        seq_rows: List[Tuple[str, int]] = []
        if action == "FLIP":
            seq_rows = [("CLOSE", 1), ("OPEN", 2)]
        else:
            seq_rows = [(action, 1)]
        sent = str(decision or "").upper() == "SENT"
        broker_id = str((nt_order_ids or [None])[0] or "")
        for order_action, seq in seq_rows:
            close_side = None
            if order_action == "CLOSE":
                open_trade = getattr(self, "_open_trade", None) or {}
                close_side = str(open_trade.get("side") or "").upper() or None
            if not close_side:
                close_side = "LONG" if int(getattr(self, "_pos", 0) or 0) > 0 else ("SHORT" if int(getattr(self, "_pos", 0) or 0) < 0 else "")
            intent_id = f"{intent.intent_id}|{order_action}|{seq}"
            row = {
                "order_intent_id": intent_id,
                "transition_id": base_transition or str(intent.intent_id or ""),
                "parent_transition_id": base_transition if action == "FLIP" else "",
                "sequence_in_transition": seq,
                "bar_ts": intent.bar_ts,
                "side": str(intent.side or "").upper() if order_action == "OPEN" else (str(close_side or "").upper() if order_action == "CLOSE" else str(intent.side or "").upper()),
                "order_action": order_action,
                "qty": int(intent.qty or 0),
                "intended_price": intent.entry_price if order_action == "OPEN" else intent.model_price or intent.entry_price,
                "mode": mode,
                "status": "sent" if sent else str(decision or "").lower(),
                "client_order_id": str(intent.intent_id or ""),
                "broker_order_id": broker_id,
                "reject_reason": "" if sent else (rejection_reason or reason_code or ""),
            }
            dedupe_key = f"{row['order_intent_id']}|{row['status']}|{row['broker_order_id']}"
            if not hasattr(self, "_order_intent_dedupe"):
                self._order_intent_dedupe = set()
            if dedupe_key in self._order_intent_dedupe:
                continue
            self._order_intent_dedupe.add(dedupe_key)
            _append_csv_row(path, ORDER_INTENTS_CSV_COLUMNS, row)

    def _append_parity_mismatch_csv(self, payload: Mapping[str, Any]) -> None:
        self._ensure_compat_defaults()
        path = getattr(self, "parity_mismatches_path", None)
        if path is None:
            return
        header = [
            "mismatch_id",
            "bar_ts",
            "mode",
            "mismatch_type",
            "detail",
            "live_value",
            "backfill_value",
            "transition_id",
            "signal_id",
            "client_order_id",
            "source_file",
        ]
        row = dict(payload)
        row.setdefault(
            "mismatch_id",
            _row_hash_from_mapping(
                {
                    "bar_ts": row.get("bar_ts"),
                    "mode": row.get("mode"),
                    "mismatch_type": row.get("mismatch_type"),
                    "transition_id": row.get("transition_id"),
                    "signal_id": row.get("signal_id"),
                    "client_order_id": row.get("client_order_id"),
                }
            ),
        )
        _append_csv_row(path, header, row)

    def _log_exec_event(self, payload: Dict[str, Any]) -> None:
        record = {"ts": utc_ts(), **payload}
        if "run_id" not in record:
            record["run_id"] = self.run_id
        try:
            _append_text_with_retry(self.exec_events_path, _json_dumps(record) + "\n")
        except Exception:
            logger.debug("Failed to append exec event", exc_info=True)

    def _emit_exec_line(
        self,
        *,
        cid: str,
        stage: str,
        mode: Optional[str],
        side: Optional[str],
        qty: Optional[int],
        model_stop_abs: Optional[float],
        model_target_abs: Optional[float],
        stop_sent: Optional[float],
        target_sent: Optional[float],
        fill_px: Optional[float],
        entry_order_id: Optional[str],
        stop_order_id: Optional[str],
        target_order_id: Optional[str],
        nt_state: Optional[str],
        guardrail: Optional[str],
        reason: Optional[str] = None,
    ) -> None:
        line = (
            "EXEC"
            f"|run_id={self.run_id}"
            f"|cid={cid}"
            f"|stage={stage}"
            f"|mode={mode or ''}"
            f"|side={side or ''}"
            f"|qty={qty if qty is not None else ''}"
            f"|model_stop_abs={'' if model_stop_abs is None else model_stop_abs}"
            f"|model_target_abs={'' if model_target_abs is None else model_target_abs}"
            f"|stop_sent={'' if stop_sent is None else stop_sent}"
            f"|target_sent={'' if target_sent is None else target_sent}"
            f"|fill_px={'' if fill_px is None else fill_px}"
            f"|entry_order_id={entry_order_id or ''}"
            f"|stop_order_id={stop_order_id or ''}"
            f"|target_order_id={target_order_id or ''}"
            f"|nt_state={nt_state or ''}"
            f"|guardrail={guardrail or ''}"
            f"|ts={utc_ts()}"
            f"|reason={reason or ''}"
        )
        _safe_print(line)

    def _emit_diff_line(
        self,
        *,
        cid: str,
        what: str,
        model_abs: Optional[float],
        sent: Optional[float],
        nt_working: Optional[float],
        tick: Optional[float],
    ) -> None:
        line = (
            "DIFF"
            f"|run_id={self.run_id}"
            f"|cid={cid}"
            f"|what={what}"
            f"|model_abs={'' if model_abs is None else model_abs}"
            f"|sent={'' if sent is None else sent}"
            f"|nt_working={'' if nt_working is None else nt_working}"
            f"|tick={'' if tick is None else tick}"
            f"|ts={utc_ts()}"
        )
        _safe_print(line)

    def _emit_gate_audit(
        self,
        *,
        ts_dt: Optional[pd.Timestamp],
        action: str,
        gate_state: Mapping[str, bool],
        blocked_by: Sequence[str],
        reason_detail: Optional[str],
        prob: Optional[float],
        phase2_meta: Optional[Mapping[str, Any]],
        extra: Optional[Mapping[str, Any]] = None,
    ) -> None:
        if ts_dt is None:
            return
        self._update_last_bar_ts_guard(ts_dt)
        if self._gate_audit_last_bar_ts is not None and ts_dt == self._gate_audit_last_bar_ts:
            return
        self._gate_audit_last_bar_ts = ts_dt
        if not self._gate_audit_header_written:
            self._init_gate_events_log()
        action_upper = str(action or "").upper()
        normalized_gate_state = OrderedDict((str(k), bool(v)) for k, v in dict(gate_state or {}).items())
        if phase2_meta and phase2_meta.get("setup_pass") is not None:
            normalized_gate_state["setup"] = bool(
                phase2_meta.get("setup_pass")
                or getattr(self, "phase2_force_open_allow_setup_fail_entries", False)
            )
        extra_map = dict(extra or {})
        force_open_setup_allowed = bool(extra_map.get("phase2_force_open_setup_fail_allowed"))
        if force_open_setup_allowed:
            normalized_gate_state["setup"] = True
        setup_fail_entries_allowed = bool(
            getattr(self, "phase2_force_open_allow_setup_fail_entries", False)
        )
        setup_effectively_passed = bool(normalized_gate_state.get("setup", True))
        blocked_list = [
            str(reason)
            for reason in list(blocked_by or [])
            if str(reason)
            and not (
                (setup_fail_entries_allowed or force_open_setup_allowed)
                and setup_effectively_passed
                and str(reason) == "setup"
            )
        ]
        for reason in (
            extra_map.get("strategy_blocked_reason"),
            extra_map.get("execution_blocked_reason"),
        ):
            reason_txt = str(reason or "").strip()
            if (setup_fail_entries_allowed or force_open_setup_allowed) and setup_effectively_passed and reason_txt == "setup":
                continue
            if reason_txt and reason_txt not in blocked_list:
                blocked_list.append(reason_txt)
        blocked_for_audit = blocked_list
        final_action = str(extra_map.get("final_action") or action_upper).upper()
        readiness_raw = extra_map.get("preflight_readiness")
        readiness_snapshot = dict(readiness_raw) if isinstance(readiness_raw, Mapping) else {}
        normalized_reason_detail = _resolve_no_trade_reason_detail(
            action=action_upper,
            final_action=final_action,
            reason_detail=reason_detail,
            blocked_by=blocked_for_audit,
            gate_state=normalized_gate_state,
            entry_block_reason=extra_map.get("entry_block_reason"),
            publish_block_reason=extra_map.get("publish_block_reason"),
            readiness_snapshot=readiness_snapshot,
        )
        first_failing_gate = _resolve_no_trade_reason_detail(
            action="NO_TRADE",
            final_action="NO_TRADE",
            reason_detail="",
            blocked_by=blocked_for_audit,
            gate_state=normalized_gate_state,
            readiness_snapshot=readiness_snapshot,
        )
        if action_upper in {"OPEN", "FLIP"} and not blocked_for_audit:
            self._executor_stats["gating_open_emits_total"] = (
                self._executor_stats.get("gating_open_emits_total", 0) + 1
            )
            self._inc_phase_stat("gating_open_emits_total", phase=str(extra_map.get("phase") or getattr(self, "_phase", "LIVE")))
            if (setup_fail_entries_allowed or force_open_setup_allowed) and setup_effectively_passed:
                if str(extra_map.get("strategy_blocked_reason") or "").strip() == "setup":
                    extra_map["strategy_blocked_reason"] = None
                extra_map.setdefault("strategy_gate_result", "pass")
                extra_map.setdefault("execution_send_allowed", True)
        payload: Dict[str, Any] = {
            "ts": utc_ts(),
            "instrument": self.instrument_alias,
            "bar_ts": _canonical_ts_str(ts_dt),
            "primary_preset": getattr(self, "primary_preset", None),
            "preset": getattr(self, "active_preset_name", None),
            "market_mode": getattr(self, "_market_mode", None),
            "market_mode_source": getattr(self, "_market_mode_source", None),
            "trend_dir": getattr(self, "_trend_direction", None),
            "trend_preset": getattr(getattr(self, "policy", None), "trend_preset", None) or getattr(self, "_configured_trend_preset", None),
            "chop_preset": getattr(getattr(self, "policy", None), "chop_preset", None) or getattr(self, "_configured_chop_preset", None),
            "p_buy": float(self.p_buy) if self.p_buy is not None else None,
            "p_sell": float(self.p_sell) if self.p_sell is not None else None,
            "threshold_p_long": float(self.p_buy) if self.p_buy is not None else None,
            "threshold_p_short_required": (
                float(1.0 - float(self.p_sell))
                if self.p_sell is not None and np.isfinite(self.p_sell)
                else None
            ),
            "threshold_short_cut": float(self.p_sell) if self.p_sell is not None else None,
            "pred_p_long": float(prob) if prob is not None and np.isfinite(prob) else None,
            "pred_p_short": (
                float(1.0 - float(prob))
                if prob is not None and np.isfinite(prob)
                else None
            ),
            "phase2": {
                "setup_threshold": float(self.phase2_p_setup) if self.phase2_p_setup is not None else None,
                "direction_long_threshold": float(self.phase2_p_long) if self.phase2_p_long is not None else None,
                "direction_short_threshold": float(self.phase2_p_short) if self.phase2_p_short is not None else None,
            },
            "gate_state": {k: bool(v) for k, v in normalized_gate_state.items()},
            "blocked_by": blocked_for_audit,
            "action": action,
            "reason_detail": normalized_reason_detail or "",
            "preflight": {
                "first_failing_gate": first_failing_gate,
                "readiness": readiness_snapshot,
            },
        }
        if action_upper in {"OPEN", "FLIP"} and blocked_list:
            payload["blocked_by_gates"] = blocked_list
        payload["override_prob_min"] = float(self.override_prob_min)
        payload["override_hold_conf_min"] = float(self.override_hold_conf_min)
        if prob is not None and np.isfinite(prob):
            payload["prob"] = float(prob)
        if phase2_meta:
            payload["phase2"].update(
                {
                    "setup_prob": phase2_meta.get("setup_prob"),
                    "setup_pass": phase2_meta.get("setup_pass"),
                    "setup_reason": phase2_meta.get("setup_reason"),
                    "setup_threshold": phase2_meta.get("setup_threshold"),
                    "direction_prob": phase2_meta.get("direction_prob"),
                    "short_prob": phase2_meta.get("short_prob"),
                    "direction_signal": phase2_meta.get("direction_signal"),
                }
            )
        if extra:
            payload.update({k: v for k, v in extra_map.items() if v is not None})
            if "strategy_blocked_reason" in extra_map and extra_map.get("strategy_blocked_reason") is None:
                payload["strategy_blocked_reason"] = None
        gate_side = str(payload.get("side") or "").upper()
        if gate_side in {"LONG", "SHORT"}:
            alignment = self._trend_alignment_for_side(gate_side)
            if alignment is not None:
                payload["trend_alignment"] = alignment
        self._write_jsonl(self.gating_events_path, payload)

    def _update_bar_diag_summary(self) -> None:
        payload = {
            "run_id": self.run_id,
            "timestamp": utc_ts(),
            **self._bar_diag_counters,
            "probability_diagnostics": self._probability_diagnostics_summary(),
        }
        try:
            self.bar_diag_summary_path.write_text(_json_dumps(payload), encoding="utf-8")
        except Exception:
            logger.debug("Failed to write bar diagnostics summary", exc_info=True)

    def _record_probability_diagnostic(
        self,
        *,
        prob: Optional[float],
        directional_prob: Optional[float],
        action: str,
        side: Optional[str],
    ) -> None:
        self._ensure_compat_defaults()

        def _update_scalar(prefix: str, value: Optional[float]) -> None:
            if value is None or not np.isfinite(value):
                return
            count_key = f"{prefix}_count"
            sum_key = f"{prefix}_sum"
            sum_sq_key = f"{prefix}_sum_sq"
            min_key = f"{prefix}_min"
            max_key = f"{prefix}_max"
            band_key = f"{prefix}_central_band_count"
            self._prob_diag[count_key] = int(self._prob_diag.get(count_key, 0) or 0) + 1
            self._prob_diag[sum_key] = float(self._prob_diag.get(sum_key, 0.0) or 0.0) + float(value)
            self._prob_diag[sum_sq_key] = float(self._prob_diag.get(sum_sq_key, 0.0) or 0.0) + float(value) * float(value)
            prev_min = self._prob_diag.get(min_key)
            prev_max = self._prob_diag.get(max_key)
            self._prob_diag[min_key] = float(value) if prev_min is None else min(float(prev_min), float(value))
            self._prob_diag[max_key] = float(value) if prev_max is None else max(float(prev_max), float(value))
            if 0.45 <= float(value) <= 0.55:
                self._prob_diag[band_key] = int(self._prob_diag.get(band_key, 0) or 0) + 1

        _update_scalar("prob", prob)
        _update_scalar("directional_prob", directional_prob)
        if action in {"OPEN", "FLIP"}:
            side_txt = str(side or "").upper()
            if side_txt == "LONG":
                self._prob_diag["open_emit_long_count"] = int(self._prob_diag.get("open_emit_long_count", 0) or 0) + 1
            elif side_txt == "SHORT":
                self._prob_diag["open_emit_short_count"] = int(self._prob_diag.get("open_emit_short_count", 0) or 0) + 1

    def _probability_diagnostics_summary(self) -> Dict[str, Any]:
        self._ensure_compat_defaults()

        def _stats(prefix: str) -> Dict[str, Optional[float]]:
            count = int(self._prob_diag.get(f"{prefix}_count", 0) or 0)
            if count <= 0:
                return {
                    "count": 0,
                    "min": None,
                    "max": None,
                    "mean": None,
                    "std": None,
                    "central_band_concentration": None,
                }
            value_sum = float(self._prob_diag.get(f"{prefix}_sum", 0.0) or 0.0)
            value_sum_sq = float(self._prob_diag.get(f"{prefix}_sum_sq", 0.0) or 0.0)
            mean = value_sum / float(count)
            variance = max(0.0, (value_sum_sq / float(count)) - (mean * mean))
            band_count = int(self._prob_diag.get(f"{prefix}_central_band_count", 0) or 0)
            return {
                "count": count,
                "min": _safe_float(self._prob_diag.get(f"{prefix}_min")),
                "max": _safe_float(self._prob_diag.get(f"{prefix}_max")),
                "mean": mean,
                "std": math.sqrt(variance),
                "central_band_concentration": (float(band_count) / float(count)) if count > 0 else None,
            }

        prob_stats = _stats("prob")
        directional_stats = _stats("directional_prob")
        candidate_signals = int(self._executor_stats.get("candidate_signals_total", 0) or 0)
        open_long = int(self._prob_diag.get("open_emit_long_count", 0) or 0)
        open_short = int(self._prob_diag.get("open_emit_short_count", 0) or 0)
        open_total = open_long + open_short
        emit_rate = (float(open_total) / float(candidate_signals)) if candidate_signals > 0 else None
        directional_imbalance = (
            (float(open_long - open_short) / float(open_total))
            if open_total > 0
            else None
        )
        verdict = "insufficient_data"
        prob_std = _safe_float(prob_stats.get("std"))
        if prob_std is not None and emit_rate is not None:
            verdict = "low_separation" if (prob_std < 0.06 and emit_rate < 0.01) else "ok"
        return {
            "prob": prob_stats,
            "directional_prob": directional_stats,
            "emit_rate": emit_rate,
            "open_emit_total": open_total,
            "open_emit_long": open_long,
            "open_emit_short": open_short,
            "directional_imbalance": directional_imbalance,
            "diagnostic_verdict": verdict,
        }

    def _blocked_by_from_gate_state(self, gate_state: Mapping[str, bool]) -> List[str]:
        mapping = OrderedDict(
            [
                ("tod", "tod"),
                ("risk", "risk"),
                ("setup", "setup"),
                ("prob", "prob"),
                ("vwap", "vwap"),
                ("ema", "ema"),
                ("bid_ask", "bid_ask_invalid"),
                ("armed", "blocked_not_armed"),
                ("offline_exec", "blocked_offline_exec_policy"),
                ("stale_bar", "blocked_stale_bar"),
                ("feature_health", "feature_health_violation"),
                ("time_skew", "time_skew_lockout"),
            ]
        )
        blocked: List[str] = []
        for key, label in mapping.items():
            if key in gate_state and not bool(gate_state[key]):
                blocked.append(label)
        return blocked

