def _maybe_enable_db_ingest_for_auto_mysql(args: argparse.Namespace, argv_list: Sequence[str]) -> None:
    if not bool(getattr(args, "auto_ingest_mysql", False)):
        return
    if bool(getattr(args, "db_ingest", False)):
        return
    if bool(getattr(args, "auto_ingest_mysql_no_ingest_zip", False)):
        return

    args.db_ingest = True

    if not bool(getattr(args, "auto_ingest_mysql_no_price_bars", False)) and not getattr(args, "db_ingest_price_bars_csv", None):
        # Prefer the input bars CSV when provided (testability + explicit operator intent).
        csv_path = getattr(args, "csv", None)
        input_mode = str(getattr(args, "input_mode", "csv") or "csv").lower()
        if csv_path and input_mode != "fiber" and str(csv_path).strip().lower() != "fiber":
            args.db_ingest_price_bars_csv = str(csv_path)
        else:
            out_dir = Path(getattr(args, "out_dir", "runs/live")).expanduser().resolve()
            # Fallback to a run-scoped price_bars.csv emitted by the streamer.
            args.db_ingest_price_bars_csv = str(out_dir / "price_bars.csv")

    if _argv_has_flag(argv_list, "--auto_ingest_interval_sec") and not _argv_has_flag(argv_list, "--db_ingest_interval_sec"):
        try:
            args.db_ingest_interval_sec = float(getattr(args, "auto_ingest_interval_sec", 60.0))
        except Exception:
            pass


def _maybe_set_default_csv_for_auto_ingest(
    args: argparse.Namespace,
    *,
    default_csv_path: Path = _DEFAULT_AUTO_INGEST_CSV,
) -> None:
    if getattr(args, "csv", None):
        return
    if not bool(getattr(args, "auto_ingest_mysql", False)):
        return
    if str(getattr(args, "input_mode", "csv") or "csv").lower() == "fiber":
        return
    try:
        if default_csv_path.exists():
            args.csv = str(default_csv_path)
    except Exception:
        return


def _start_watchdog(args: argparse.Namespace) -> Optional[subprocess.Popen]:
    if not getattr(args, "watchdog", False):
        return None
    watchdog_path = getattr(args, "watchdog_path", None)
    if watchdog_path:
        path = Path(watchdog_path).expanduser()
    else:
        path = _simplified_repo_root() / "ninjatrader" / "nt_watchdog.py"
    path = path.resolve()
    cmd = [sys.executable, str(path)]
    logger.info("[watchdog] starting %s", " ".join(cmd))
    return subprocess.Popen(cmd, cwd=str(path.parent))

def _run_replay_harness(run_dir: str) -> None:
    base = Path(run_dir).expanduser()
    required = [
        "signals.jsonl",
        "order_events.jsonl",
        "nt_bridge.jsonl",
        "trades.csv",
    ]
    missing = [name for name in required if not (base / name).exists()]
    if missing:
        raise SystemExit(f"Replay harness missing files: {missing}")
    signals = (base / "signals.jsonl").read_text(encoding="utf-8").splitlines()
    orders = (base / "order_events.jsonl").read_text(encoding="utf-8").splitlines()
    nt = (base / "nt_bridge.jsonl").read_text(encoding="utf-8").splitlines()
    trades = (base / "trades.csv").read_text(encoding="utf-8").splitlines()
    if not signals or not orders or not nt:
        raise SystemExit("Replay harness requires non-empty signals/order_events/nt_bridge logs.")
    if len(trades) < 2:
        raise SystemExit("Replay harness requires trades.csv with header + at least one row.")
    _safe_print(f"REPLAY_OK dir={base} signals={len(signals)} order_events={len(orders)} nt_events={len(nt)} trades={len(trades)-1}")

def _run_nt_smoke_only(args: Any) -> None:
    out_dir = Path(getattr(args, "out_dir", "runs"))
    out_dir.mkdir(parents=True, exist_ok=True)
    nt_port = int(getattr(args, "nt_port", 5019))
    nt_host = str(getattr(args, "nt_host", "127.0.0.1"))
    nt_adapter = str(getattr(args, "nt_adapter", "native"))
    nt_require_snapshot = bool(getattr(args, "nt_require_snapshot", True))
    nt_connect_timeout_sec = float(getattr(args, "nt_connect_timeout_sec", 120.0))
    nt_snapshot_timeout_sec = float(getattr(args, "nt_snapshot_timeout_sec", 120.0))
    nt_account = getattr(args, "nt_account", None) or "Sim101"
    nt_instrument = getattr(args, "nt_instrument", None)
    if nt_require_snapshot and not nt_instrument:
        raise SystemExit("NT_SMOKE_FAIL|missing_nt_instrument")

    shell = LiveCSVStreamer.__new__(LiveCSVStreamer)
    shell.run_id = str(uuid4())
    shell.model_sha = "smoke"
    shell.model_path = "smoke"
    shell.active_preset_name = str(getattr(args, "preset", "") or "smoke")
    shell.primary_preset = shell.active_preset_name
    shell.instrument_alias = str(getattr(args, "instrument", "") or "ES")
    shell.nt_port = nt_port
    shell.nt_host = nt_host
    shell.nt_adapter = nt_adapter
    shell.nt_enabled = True
    shell.out_dir = out_dir
    shell.run_mode = "replay"
    shell._instance_lock_acquired = False
    shell.i_understand_multiport = bool(getattr(args, "i_understand_multiport", False))
    if nt_port != 5019 and not shell.i_understand_multiport:
        raise SystemExit("NT_PORT_POLICY_FAIL|expected=5019|actual=%s|use=--i_understand_multiport" % nt_port)
    _safe_print(f"PORT_POLICY|port={nt_port}|ok=true")
    shell._acquire_instance_lock()

    bridge = None
    flags = {"hello": False, "snapshot": False}
    rx_types: Deque[str] = deque(maxlen=20)
    rx_snippets: Deque[str] = deque(maxlen=5)
    tx_types: Deque[str] = deque(maxlen=5)
    snapshot_tx = False
    ack_sent = False

    def _cb(msg: Dict[str, Any]) -> None:
        nonlocal ack_sent
        try:
            msg_type = str(msg.get("type") or "").upper()
        except Exception:
            msg_type = ""
        if msg_type:
            rx_types.append(msg_type)
        if msg_type == "HELLO":
            flags["hello"] = True
            if not ack_sent and bridge is not None and hasattr(bridge, "send"):
                try:
                    ack = {"type": "ACK", "protocol_version": 1, "timestamp": utc_ts()}
                    if bridge.send(ack):
                        tx_types.append("ACK")
                        ack_sent = True
                except Exception:
                    pass
        elif msg_type in {"POSITION_SNAPSHOT", "SNAPSHOT", "POSITION", "ACCOUNT_SNAPSHOT", "STATE_SNAPSHOT"}:
            flags["snapshot"] = True
            try:
                pos_qty = msg.get("pos_qty", msg.get("qty"))
                orders = msg.get("orders", [])
                fills = msg.get("fills", [])
                _safe_print(
                    f"NT_RX SNAPSHOT_OK|type={msg_type}|pos_qty={pos_qty}|orders={len(orders) if isinstance(orders, list) else 'n/a'}|fills={len(fills) if isinstance(fills, list) else 'n/a'}"
                )
            except Exception:
                pass
        if msg_type and msg_type != "ACK":
            try:
                snippet = _json_dumps(msg)[:200]
            except Exception:
                snippet = str(msg)[:200]
            rx_snippets.append(snippet)

    try:
        if nt_adapter == "mock":
            bridge = MockNTTransport(
                host=nt_host,
                port=nt_port,
                account=str(getattr(args, "nt_account", "SIM") or "SIM"),
                instruments=[shell.instrument_alias],
                protocol_version=1,
            )
            bridge.add_callback(_cb)
            bridge.start()
        else:
            shell._port_guard_before_bridge_start()
            bridge = NTBridgeServer(nt_host, nt_port, logger=logger, log_path=str(out_dir / "nt_bridge.jsonl"))
            bridge.add_callback(_cb)
            bridge.start()

        _safe_print(f"NT waiting for handshake on {nt_host}:{nt_port}...")
        deadline = None if nt_connect_timeout_sec <= 0 else time.monotonic() + max(0.1, nt_connect_timeout_sec)
        while True:
            connected = False
            try:
                connected = bool(getattr(bridge, "is_connected", False))
            except Exception:
                connected = False
            if connected or flags["hello"] or flags["snapshot"] or bool(getattr(bridge, "hello_seen", False)):
                break
            if deadline is not None and time.monotonic() >= deadline:
                handshake_ok = bool(getattr(bridge, "handshake_ok", lambda: False)()) or bool(getattr(bridge, "hello_seen", False)) or flags["hello"]
                _safe_print(
                    f"NT_SOCKET_TIMEOUT|handshake_ok={str(handshake_ok).lower()}|acct={nt_account}|inst={nt_instrument}|rx_tail={','.join(rx_types) if rx_types else 'none'}"
                )
                raise SystemExit("nt_socket_timeout")
            time.sleep(0.1)

        if nt_require_snapshot:
            snap_deadline = time.monotonic() + max(0.1, nt_snapshot_timeout_sec)
            last_ping = 0.0
            while True:
                now = time.monotonic()
                if now - last_ping >= 0.5:
                    try:
                        if bridge is not None and hasattr(bridge, "send"):
                            base = {"protocol_version": 1, "timestamp": utc_ts(), "client_order_id": f"SMOKE|{utc_ts()}"}
                            ping = {"type": "PING", **base, "account": nt_account, "instrument": nt_instrument}
                            sync = {"type": "SYNC", **base, "account": nt_account, "instrument": nt_instrument}
                            bridge.send(ping)
                            bridge.send(sync)
                            tx_types.append("PING")
                            tx_types.append("SYNC")
                            snapshot_tx = True
                            _safe_print(
                                f"NT_TX REQ_SNAPSHOT|account={nt_account}|instrument={nt_instrument}|req_id={base.get('client_order_id')}|attempt={len(tx_types)}"
                            )
                    except Exception:
                        pass
                    last_ping = now
                if flags["snapshot"] or bool(getattr(bridge, "snapshot_seen", False)):
                    break
                if time.monotonic() >= snap_deadline:
                    handshake_ok = bool(getattr(bridge, "handshake_ok", lambda: False)()) or bool(getattr(bridge, "hello_seen", False)) or flags["hello"]
                    _safe_print(
                        f"NT_SNAPSHOT_TIMEOUT|handshake_ok={str(handshake_ok).lower()}|acct={nt_account}|inst={nt_instrument}|rx_tail={','.join(rx_types) if rx_types else 'none'}"
                    )
                    _safe_print(f"NT_SNAPSHOT_TIMEOUT_RX_SNIPPETS|count={len(rx_snippets)}|snippets={list(rx_snippets)}")
                    _safe_print(f"NT_SNAPSHOT_TIMEOUT_TX|sent_snapshot_request={str(snapshot_tx).lower()}|tx_tail={list(tx_types)}")
                    raise SystemExit("nt_snapshot_timeout")
                time.sleep(0.1)

        acct = nt_account
        inst = nt_instrument
        _safe_print(
            f"NT_READY|connected=true|snapshot={str(bool(flags['snapshot'] or getattr(bridge, 'snapshot_seen', False))).lower()}|account={acct}|instrument={inst}|port={nt_port}"
        )
        reason = "smoke_ok"
        exit_code = 0
    except SystemExit as exc:
        reason = str(exc) or "smoke_fail"
        exit_code = 2
    finally:
        try:
            if bridge is not None:
                bridge.shutdown()
        except Exception:
            pass
        _safe_print(f"BRIDGE_STOPPED|port={nt_port}|ok=true|reason={reason}")
        try:
            shell._release_instance_lock()
        except Exception:
            pass
        try:
            shell._assert_port_free(strict=True)
        except SystemExit:
            raise
        except Exception:
            pass
        if exit_code != 0:
            raise SystemExit(exit_code)


def _normalize_trade_window_for_tod(args: argparse.Namespace, argv_list: Sequence[str]) -> Dict[str, Any]:
    preset_name_for_window = getattr(args, "preset", None)
    preset_window_cfg: Mapping[str, Any] = PRESETS.get(preset_name_for_window, {}) if preset_name_for_window else {}
    configured_window_start = (
        _coerce_time_str(preset_window_cfg.get("trade_window_start"))
        if isinstance(preset_window_cfg, Mapping) and preset_window_cfg.get("trade_window_start") is not None
        else _coerce_time_str(getattr(args, "trade_window_start", None))
    )
    configured_window_end = (
        _coerce_time_str(preset_window_cfg.get("trade_window_end"))
        if isinstance(preset_window_cfg, Mapping) and preset_window_cfg.get("trade_window_end") is not None
        else _coerce_time_str(getattr(args, "trade_window_end", None))
    )
    trade_window_start_cli_forced = _argv_has_flag(argv_list, "--trade_window_start")
    trade_window_end_cli_forced = _argv_has_flag(argv_list, "--trade_window_end")
    trade_window_cli_forced = trade_window_start_cli_forced or trade_window_end_cli_forced
    trade_window_effective_reason = "configured"
    if getattr(args, "disable_safety_gates", False):
        if not _argv_has_flag(argv_list, "--gate_vwap", "--no-gate_vwap"):
            args.gate_vwap = False
        if not _argv_has_flag(argv_list, "--gate_ema", "--no-gate_ema"):
            args.gate_ema = False
        if not _argv_has_flag(argv_list, "--gate_tod", "--no-gate_tod"):
            args.gate_tod = False
        if not _argv_has_flag(argv_list, "--trade_window_start"):
            args.trade_window_start = "00:00"
        if not _argv_has_flag(argv_list, "--trade_window_end"):
            args.trade_window_end = "23:59"
        if not _argv_has_flag(argv_list, "--publish_min_grade"):
            args.publish_min_grade = "C"
    if not bool(getattr(args, "gate_tod", True)):
        args.trade_window_start = "00:00"
        args.trade_window_end = "23:59"
        trade_window_effective_reason = "gate_tod_disabled_auto_24h"
    effective_window_start = _coerce_time_str(getattr(args, "trade_window_start", None)) or str(
        getattr(args, "trade_window_start", "") or ""
    )
    effective_window_end = _coerce_time_str(getattr(args, "trade_window_end", None)) or str(
        getattr(args, "trade_window_end", "") or ""
    )
    if (
        trade_window_effective_reason == "gate_tod_disabled_auto_24h"
        and configured_window_start
        and configured_window_end
        and not (configured_window_start == "00:00" and configured_window_end == "23:59")
    ):
        logger.info(
            "Trade window widened to 24h because gate_tod is disabled: preset_window=%s-%s effective_window=%s-%s reason=%s",
            configured_window_start,
            configured_window_end,
            effective_window_start,
            effective_window_end,
            trade_window_effective_reason,
        )
    return {
        "configured_window_start": configured_window_start,
        "configured_window_end": configured_window_end,
        "trade_window_start_cli_forced": trade_window_start_cli_forced,
        "trade_window_end_cli_forced": trade_window_end_cli_forced,
        "trade_window_cli_forced": trade_window_cli_forced,
        "trade_window_effective_reason": trade_window_effective_reason,
        "effective_window_start": effective_window_start,
        "effective_window_end": effective_window_end,
    }


def main(argv: Optional[List[str]] = None) -> None:
    _merge_custom_presets_into_registry()
    ap = _build_arg_parser()
    args = ap.parse_args(argv)
    argv_list = list(argv) if argv is not None else sys.argv[1:]
    _maybe_set_default_csv_for_auto_ingest(args)

    if (
        not getattr(args, "selftest_phase2_logging", False)
        and not getattr(args, "nt_smoke_test_only", False)
        and not getattr(args, "csv", None)
        and str(getattr(args, "input_mode", "csv") or "csv").lower() != "fiber"
    ):
        ap.error("--csv is required unless --selftest_phase2_logging is specified.")

    if getattr(args, "nt_smoke_test_only", False):
        _run_nt_smoke_only(args)
        return

    # Apply preset AFTER parsing CLI to allow CLI to override preset fields
    args = _apply_preset_to_args(args, argv_list)
    window_meta = _normalize_trade_window_for_tod(args, argv_list)
    configured_window_start = window_meta["configured_window_start"]
    configured_window_end = window_meta["configured_window_end"]
    trade_window_start_cli_forced = window_meta["trade_window_start_cli_forced"]
    trade_window_end_cli_forced = window_meta["trade_window_end_cli_forced"]
    trade_window_cli_forced = window_meta["trade_window_cli_forced"]
    trade_window_effective_reason = window_meta["trade_window_effective_reason"]
    effective_window_start = window_meta["effective_window_start"]
    effective_window_end = window_meta["effective_window_end"]

    if getattr(args, "phase2_tag", None):
        manifest_path, manifest = _load_phase2_manifest(str(args.phase2_tag))
        _validate_deployable_phase2_manifest(str(args.phase2_tag), manifest_path, manifest)
        args = _apply_phase2_manifest_overrides(args, manifest_path, manifest, argv_list)

    _maybe_enable_db_ingest_for_auto_mysql(args, argv_list)

    contracts_cli = getattr(args, "pnl_contracts", None)
    if contracts_cli is None:
        contracts_cli = getattr(args, "contracts", None)
    try:
        contracts_value = float(contracts_cli) if contracts_cli is not None else 1.0
    except Exception:
        contracts_value = 1.0
    if contracts_value <= 0:
        contracts_value = 1.0
    args.contracts = contracts_value
    args.pnl_contracts = contracts_value

    if getattr(args, "offline_run", False):
        args.bootstrap_all = True
        args.exit_when_caught_up = True
        args.reset_state = True
        args.poll_sec = 0.0

    # Resolve protection mode once (source of truth for this run).
    run_mode_arg = getattr(args, "run_mode", None)
    run_mode_explicit = run_mode_arg is not None
    resolved_run_mode = str(
        run_mode_arg
        or ("replay" if (bool(getattr(args, "offline_run", False)) or (bool(getattr(args, "sim_mode", False)) and not run_mode_explicit)) else "live")
    ).lower()
    if resolved_run_mode == "offline":
        resolved_run_mode = "replay"
    resolved_exec_policy = str(getattr(args, "nt_exec_policy", "paper") or "paper").lower()
    requested_mode = str(getattr(args, "protection_price_mode", None) or "offset").lower()
    allow_absolute = bool(getattr(args, "i_know_what_im_doing", False))
    allow_absolute_context = resolved_run_mode != "live" or resolved_exec_policy != "paper" or bool(getattr(args, "sim_mode", False))
    resolved_mode = requested_mode
    forced_mode = False
    if requested_mode == "absolute" and not allow_absolute and not allow_absolute_context:
        resolved_mode = "offset"
        forced_mode = True
        logger.warning(
            "protection_price_mode=absolute blocked in live paper; forcing offset (set --i_know_what_im_doing to override)."
        )
    args.protection_price_mode = resolved_mode
    args._protection_mode_forced = forced_mode
    acct_label = getattr(args, "nt_account", None)
    if getattr(args, "nt_account_mode", "cli") == "auto":
        acct_label = "auto"
    _safe_print(
        f"RESOLVED protection_price_mode={resolved_mode} nt_exec_policy={resolved_exec_policy} "
        f"account={acct_label} run_mode={resolved_run_mode}"
    )
    nt_account_flag = _argv_has_flag(argv_list, "--nt_account")
    if getattr(args, "nt_account_mode", "cli") == "auto" and not nt_account_flag:
        # Avoid default Sim101 forcing account_unauthorized when auto-resolve is intended.
        args.nt_account = "auto"
    nt_exec_policy_flag = _argv_has_flag(argv_list, "--nt_exec_policy")
    nt_exec_policy_explicit = nt_exec_policy_flag
    allow_live_proof_override = bool(_argv_has_flag(argv_list, "--allow_live_proof_override"))
    close_on_bracket_only_explicit = _argv_has_flag(
        argv_list, "--close_on_bracket_only", "--allow_signal_close"
    )
    phase_currentness_confirmations_explicit = _argv_has_flag(
        argv_list, "--phase_currentness_confirmations_required"
    )
    if getattr(args, "nt_proof_mode", False) and not nt_exec_policy_explicit:
        args.nt_exec_policy = "proof"
        nt_exec_policy_explicit = True
    elif getattr(args, "nt_proof_mode", False) and nt_exec_policy_explicit and getattr(args, "nt_exec_policy", None) != "proof":
        logger.warning("Both --nt_proof_mode and --nt_exec_policy set; honoring --nt_exec_policy=%s.", args.nt_exec_policy)
    nt_exec_policy_source = "default"
    if nt_exec_policy_flag:
        nt_exec_policy_source = "cli:--nt_exec_policy"
    elif getattr(args, "nt_proof_mode", False):
        nt_exec_policy_source = "cli:--nt_proof_mode"
    elif getattr(args, "offline_run", False):
        nt_exec_policy_source = "cli:--offline_run"
    if getattr(args, "run_mode", None) is None and getattr(args, "offline_run", False):
        args.run_mode = "replay"
    if getattr(args, "offline_run", False) and getattr(args, "nt_exec_policy", None) is None:
        args.nt_exec_policy = "proof"

    nt_allowed_accounts = None
    if getattr(args, "nt_allowed_accounts", None):
        nt_allowed_accounts = [
            item.strip()
            for item in str(args.nt_allowed_accounts).split(",")
            if item.strip()
        ]

    if getattr(args, "selftest_phase2_logging", False):
        LiveCSVStreamer.run_phase2_selftest()
        logger.info("Phase-2 self-test complete; exiting per --selftest_phase2_logging.")
        return

    if getattr(args, "log_ascii_only", False):
        global _LOG_ASCII_ONLY
        _LOG_ASCII_ONLY = True

    if getattr(args, "replay_run_dir", None):
        _run_replay_harness(str(args.replay_run_dir))
        return

    learning_db_url = getattr(args, "learning_db_url", None)
    if learning_db_url:
        os.environ["LEARNING_DB_URL"] = learning_db_url
    elif getattr(args, "own_trades_learning", False) and not os.getenv("LEARNING_DB_URL"):
        default_db = Path("autonomy_results/learning.db").resolve()
        default_db.parent.mkdir(parents=True, exist_ok=True)
        os.environ["LEARNING_DB_URL"] = f"sqlite:///{default_db}"
        logger.info("[learning] own_trades_learning enabled; using %s", os.environ["LEARNING_DB_URL"])
    if str(getattr(args, "input_mode", "csv") or "csv").lower() == "fiber" and not getattr(args, "csv", None):
        args.csv = "fiber"

    # Optional unified YAML config (CLI still overrides)
    alert_sink: Optional[AlertSink] = None
    registry = None
    config_values: Optional[Dict[str, Any]] = None
    try:
        registry = get_registry()
    except Exception as exc:
        logger.debug("Registry load failed: %s", exc)
    champion_manager: Optional[ChampionManager] = None

    if getattr(args, "config", None):
        try:
            full_cfg = load_config_from_yaml(args.config)
            alert_sink = build_runtime_alert_sink(full_cfg)
            if getattr(args, "model", None) is None and full_cfg.model.model_path:
                args.model = full_cfg.model.model_path
            args.p_buy = float(getattr(args, "p_buy", full_cfg.model.p_buy) or full_cfg.model.p_buy)
            args.p_sell = float(getattr(args, "p_sell", full_cfg.model.p_sell) or full_cfg.model.p_sell)
            config_values = {
                "p_buy": full_cfg.model.p_buy,
                "p_sell": full_cfg.model.p_sell,
                "path": getattr(args, "config", None),
            }
            if getattr(args, "instrument", None) is None:
                args.instrument = full_cfg.risk.symbol
            # online bundle
            args.online_alpha = full_cfg.online.online.alpha_online
            args.online_update_every = full_cfg.online.online.update_every_n_trades
            args.online_min_buffer = full_cfg.online.online.min_buffer_size
            args.online_max_buffer = full_cfg.online.online.max_buffer_size
            args.online_max_daily_updates = full_cfg.online.online.max_daily_updates
            args.online_underperf_threshold = full_cfg.online.online.underperf_threshold
            args.online_alpha_decay = full_cfg.online.online.alpha_decay_step
            args.online_rollback_trades = full_cfg.online.online.rollback_window_trades
            args.online_auto_freeze = full_cfg.online.online.auto_freeze
        except Exception as exc:
            logger.debug("Config load failed (%s): %s", getattr(args, "config", None), exc)
            alert_sink = build_alert_sink_from_config(None)
    else:
        alert_sink = build_alert_sink_from_config(None)

    # Hard guard: ensure the runtime config won't disable model-required features.
    try:
        from na.bot.feature_constants import validate_runtime_config_vs_model

        features_cfg = None
        try:
            features_cfg = locals().get("full_cfg", None)
            features_cfg = getattr(features_cfg, "features", None) if features_cfg is not None else None
        except Exception:
            features_cfg = None
        if features_cfg is None:
            try:
                fallback_cfg = default_config()
                features_cfg = getattr(fallback_cfg, "features", None)
            except Exception:
                features_cfg = None
        validate_runtime_config_vs_model(features_cfg if isinstance(features_cfg, Mapping) else {})
    except Exception as exc:
        logger.error("Runtime config incompatible with production model features: %s", exc)
        raise

    preset_name = getattr(args, "preset", None)
    preset_payload: Mapping[str, Any] = PRESETS.get(preset_name, {}) if preset_name else {}
    resolved_thresholds = _resolve_probability_thresholds(
        args=args,
        argv_tokens=argv_list,
        preset_payload=preset_payload,
        preset_name=(str(preset_name) if preset_name else None),
        config_values=config_values,
    )
    args.p_setup = resolved_thresholds["p_setup_required"]
    args.p_buy = resolved_thresholds["p_long_required"]
    args.p_sell = resolved_thresholds["short_cut"]
    args.p_long = resolved_thresholds["p_long_required"]
    args.p_short = resolved_thresholds["p_short_required"]
    requested_run_mode = str(getattr(args, "run_mode", "") or "").lower()
    live_like_run = requested_run_mode in {"", "live"} and not bool(getattr(args, "sim_mode", False))
    if live_like_run and bool(getattr(args, "nt_enable", False)):
        allowed_live_presets = _approved_preset_names_for_exec_policy(getattr(args, "nt_exec_policy", None), args)
        locked_preset = allowed_live_presets[0] if allowed_live_presets else "es_maxpack_10_full_send_prop_safe_pnl"
        if not getattr(args, "preset", None):
            args.preset = locked_preset
            preset_name = locked_preset
            preset_payload = PRESETS.get(preset_name, {}) if preset_name else {}
        elif str(getattr(args, "preset", "")) not in allowed_live_presets:
            raise SystemExit(
                f"LIVE_PRESET_LOCK_FAIL: preset={getattr(args, 'preset', None)} required_one_of={','.join(allowed_live_presets)}"
            )
    if live_like_run and bool(getattr(args, "phase2", False)):
        manifest_disabled = getattr(args, "phase2_use_manifest_thresholds", None) is False
        preset_allows_override = (
            str(getattr(args, "preset", "") or "") in LIVE_APPROVED_THRESHOLD_OVERRIDE_PRESETS
        )
        if manifest_disabled and not preset_allows_override:
            raise SystemExit("LIVE_PHASE2_MANIFEST_REQUIRED: phase2_use_manifest_thresholds must be enabled in live.")
        src_long = str((resolved_thresholds.get("source_map") or {}).get("p_long_required") or "")
        src_short = str((resolved_thresholds.get("source_map") or {}).get("p_short_required") or "")
        src_setup = str((resolved_thresholds.get("source_map") or {}).get("p_setup_required") or "")
        source_map = resolved_thresholds.get("source_map") or {}
        if not _live_threshold_sources_allowed(getattr(args, "preset", None), source_map):
            raise SystemExit(
                f"LIVE_PHASE2_THRESHOLD_SOURCE_FAIL: setup={src_setup} long={src_long} short={src_short} "
                f"preset={getattr(args, 'preset', None)}"
            )

    preset_sources = _resolve_preset_sources(preset_name)
    repo_root = _simplified_repo_root().parent
    config_paths = [
        getattr(args, "config", None),
        preset_sources.get("registry_master"),
        preset_sources.get("extra_yaml"),
        preset_sources.get("custom_yaml"),
        getattr(args, "phase2_manifest_path", None),
    ]
    config_paths = [path for path in config_paths if path]
    bar_interval_sec = float(getattr(args, "bar_interval_sec", 0) or 0.0)
    bar_age_cfg = float(getattr(args, "bar_age_max_sec", 0.0) or 0.0)
    effective_bar_age_max_sec = compute_effective_bar_age_max_sec(bar_interval_sec)
    effective_bar_age_val = float(effective_bar_age_max_sec or 0.0)
    bar_interval_known = bool(bar_interval_sec > 0.0 and effective_bar_age_max_sec is not None)
    phase_backfill_thresh, phase_current_thresh = _derive_phase_thresholds(
        bar_interval_sec=bar_interval_sec,
        currentness_lag_sec_threshold=getattr(args, "phase_currentness_lag_sec_threshold", None),
        backfill_lag_sec_threshold=getattr(args, "phase_backfill_lag_sec_threshold", None),
    )
    guardrails_requested = {
        "price_age_warn_sec": float(getattr(args, "price_age_warn_sec", 5.0) or 0.0),
        "price_age_max_sec": float(getattr(args, "price_age_max_sec", 10.0) or 10.0),
        "snapshot_age_max_sec": float(getattr(args, "snapshot_age_max_sec", 60.0) or 60.0),
        "bar_age_max_sec_configured": bar_age_cfg,
        "bar_age_max_sec_effective": effective_bar_age_val,
        "bar_age_max_sec": effective_bar_age_val,
        "bar_interval_sec": bar_interval_sec,
        "bar_interval_known": bar_interval_known,
        "effective_bar_age_max_sec": effective_bar_age_val,
        "protection_timeout_sec": float(getattr(args, "protection_timeout_sec", 5.0) or 5.0),
        "close_emit_timeout_sec": float(getattr(args, "close_emit_timeout_sec", 3.0) or 3.0),
        "reconciliation_grace_bars": int(getattr(args, "reconciliation_grace_bars", 1) or 1),
        "cancel_loop_max_updates": int(getattr(args, "cancel_loop_max_updates", 3) or 3),
        "max_exit_pending_sec": float(getattr(args, "max_exit_pending_sec", 15.0) or 15.0),
        "protection_repair_enabled": bool(getattr(args, "protection_repair_enabled", True)),
        "auto_flatten_enabled": bool(getattr(args, "auto_flatten_enabled", True)),
    }
    nt_sync_interval_sec = float(getattr(args, "nt_sync_interval_sec", 30.0) or 0.0)
    guardrails_effective = dict(guardrails_requested)
    guardrails_effective["price_age_max_sec"] = max(0.1, float(guardrails_requested["price_age_max_sec"]), nt_sync_interval_sec * 2.0)
    guardrails_effective["snapshot_age_max_sec"] = max(
        0.1, float(guardrails_requested["snapshot_age_max_sec"]), nt_sync_interval_sec * 2.0
    )
    guardrails_effective["protection_timeout_sec"] = max(
        1.0, float(guardrails_requested["protection_timeout_sec"]), nt_sync_interval_sec * 1.0
    )
    guardrails_overrides: List[Dict[str, Any]] = []
    for param in ("price_age_max_sec", "snapshot_age_max_sec", "protection_timeout_sec"):
        try:
            requested_val = guardrails_requested.get(param)
            effective_val = guardrails_effective.get(param)
        except Exception:
            continue
        if requested_val is None or effective_val is None:
            continue
        try:
            req_f = float(requested_val)
            eff_f = float(effective_val)
        except Exception:
            continue
        if abs(eff_f - req_f) <= 1e-12:
            continue
        reason = "derived from runtime parameters"
        if param == "protection_timeout_sec":
            reason = (
                "effective = max(requested, nt_sync_interval_sec * 1) "
                f"= max({req_f:.3f}, {nt_sync_interval_sec:.3f} * 1 = {(nt_sync_interval_sec * 1.0):.3f})"
            )
        elif param in {"price_age_max_sec", "snapshot_age_max_sec"}:
            reason = (
                "effective = max(requested, nt_sync_interval_sec * 2, 0.1) "
                f"= max({req_f:.3f}, {nt_sync_interval_sec:.3f} * 2 = {(nt_sync_interval_sec * 2.0):.3f}, 0.1)"
            )
        guardrails_overrides.append(
            {
                "param": param,
                "requested": req_f,
                "effective": eff_f,
                "reason": reason,
                "nt_sync_interval_sec": float(nt_sync_interval_sec),
            }
        )
        try:
            logger.warning("[CONFIG OVERRIDE] %s: requested=%.3f -> effective=%.3f (%s)", param, req_f, eff_f, reason)
        except Exception:
            pass
        try:
            _safe_print(
                f"[CONFIG OVERRIDE] {param}: requested={req_f:.3f} -> effective={eff_f:.3f}\n"
                f"  Reason: {reason}\n"
                "  See resolved_config.json: guardrails_overrides"
            )
        except Exception:
            pass
    threshold_source_map = dict(resolved_thresholds.get("source_map") or {})
    threshold_source_kinds = {
        key: _threshold_source_kind(threshold_source_map.get(key))
        for key in ("p_setup_required", "p_long_required", "p_short_required", "short_cut")
    }
    core_kinds = {
        threshold_source_kinds.get("p_setup_required"),
        threshold_source_kinds.get("p_long_required"),
        threshold_source_kinds.get("p_short_required"),
    }
    core_kinds.discard(None)
    active_threshold_source = (
        next(iter(core_kinds)) if len(core_kinds) == 1 else "mixed"
    )
    threshold_resolution: Dict[str, Any] = {
        "active_source": active_threshold_source,
        "source_kind_map": threshold_source_kinds,
        "source_map": threshold_source_map,
    }
    if preset_payload:
        preset_threshold_values = {
            "p_setup": _as_float(preset_payload.get("p_setup")),
            "p_long": _as_float(preset_payload.get("p_long")),
            "p_short": _as_float(preset_payload.get("p_short")),
        }
    else:
        preset_threshold_values = {"p_setup": None, "p_long": None, "p_short": None}
    manifest_threshold_values = {
        "p_setup": _as_float((getattr(args, "phase2_manifest_thresholds", {}) or {}).get("p_setup")),
        "p_long": _as_float((getattr(args, "phase2_manifest_thresholds", {}) or {}).get("p_long")),
        "p_short": _as_float((getattr(args, "phase2_manifest_thresholds", {}) or {}).get("p_short")),
    }
    threshold_resolution["preset_values"] = preset_threshold_values
    threshold_resolution["manifest_values"] = manifest_threshold_values
    threshold_resolution["resolved_values"] = {
        "p_setup": resolved_thresholds["p_setup_required"],
        "p_long": resolved_thresholds["p_long_required"],
        "p_short": resolved_thresholds["p_short_required"],
    }
    preset_manifest_threshold_mismatch = False
    mismatch_details: Dict[str, Any] = {}
    preset_manifest_threshold_divergence = False
    divergence_details: Dict[str, Any] = {}
    for key in ("p_setup", "p_long", "p_short"):
        preset_val = preset_threshold_values.get(key)
        manifest_val = manifest_threshold_values.get(key)
        if preset_val is None or manifest_val is None:
            continue
        if abs(float(preset_val) - float(manifest_val)) <= 1e-9:
            continue
        src_key = f"{key}_required"
        source_kind = threshold_source_kinds.get(src_key)
        if source_kind == "manifest":
            preset_manifest_threshold_mismatch = True
            mismatch_details[key] = {
                "preset": float(preset_val),
                "manifest": float(manifest_val),
                "selected_source": threshold_source_map.get(src_key),
            }
        elif source_kind == "preset":
            preset_manifest_threshold_divergence = True
            divergence_details[key] = {
                "preset": float(preset_val),
                "manifest": float(manifest_val),
                "selected_source": threshold_source_map.get(src_key),
            }
    if preset_manifest_threshold_mismatch:
        threshold_resolution["preset_manifest_mismatch"] = mismatch_details
        logger.warning(
            "THRESHOLD_SOURCE_MISMATCH preset=%s mismatch=%s source=%s",
            preset_name or "n/a",
            mismatch_details,
            threshold_source_map,
        )
        _safe_print(
            "WARNING: preset threshold values differ from manifest and manifest source is active. "
            f"preset={preset_name or 'n/a'} mismatch={mismatch_details}"
        )
    if preset_manifest_threshold_divergence:
        threshold_resolution["preset_manifest_divergence"] = divergence_details
        logger.warning(
            "THRESHOLD_SOURCE_DIVERGENCE preset=%s divergence=%s source=%s",
            preset_name or "n/a",
            divergence_details,
            threshold_source_map,
        )
        _safe_print(
            "WARNING: preset threshold values differ from manifest and preset source is active. "
            f"preset={preset_name or 'n/a'} divergence={divergence_details}"
        )
        if bool(getattr(args, "phase2", False)) and bool(getattr(args, "phase2_tag", None)):
            if not bool(getattr(args, "allow_preset_manifest_threshold_mismatch", False)):
                raise SystemExit(
                    "PHASE2_THRESHOLD_MISMATCH_ACK_REQUIRED: preset thresholds diverge from phase2 manifest; "
                    "pass --allow_preset_manifest_threshold_mismatch to acknowledge."
                )
    resolved_preset_payload = PRESETS.get(preset_name, {}) if preset_name else {}
    if not isinstance(resolved_preset_payload, Mapping):
        resolved_preset_payload = {}
    resolved_risk_payload = resolved_preset_payload.get("risk")
    if not isinstance(resolved_risk_payload, Mapping):
        resolved_risk_payload = {}

    def _resolved_risk_value(key: str) -> Any:
        value = resolved_preset_payload.get(key)
        return resolved_risk_payload.get(key) if value is None else value

    resolved_payload = {
            "preset": preset_name,
            "config_path": getattr(args, "config", None),
            "config_paths": config_paths,
            "regime_policy": {
                "primary_preset": preset_name,
                "trend_preset": getattr(args, "trend_preset", None),
                "chop_preset": getattr(args, "chop_preset", None),
                "midday_trend_threshold": getattr(args, "midday_trend_threshold", None),
                "trend_threshold": getattr(args, "trend_threshold", None),
                "chop_threshold": getattr(args, "chop_threshold", None),
                "chop_range_threshold": getattr(args, "chop_range_threshold", None),
                "mode_persist_bars": getattr(args, "mode_persist_bars", None),
                "allow_countertrend_in_unresolved": getattr(args, "allow_countertrend_in_unresolved", None),
                "allow_countertrend_fade_in_trend": getattr(args, "allow_countertrend_fade_in_trend", None),
                "countertrend_fade_min_vwap_extension_pts": getattr(
                    args, "countertrend_fade_min_vwap_extension_pts", None
                ),
                "countertrend_fade_prob_threshold": getattr(args, "countertrend_fade_prob_threshold", None),
                "countertrend_fade_size_multiplier": getattr(args, "countertrend_fade_size_multiplier", None),
                "countertrend_fade_pnl_giveback_activate_r": getattr(args, "countertrend_fade_pnl_giveback_activate_r", None),
                "countertrend_fade_pnl_giveback_close_r": getattr(args, "countertrend_fade_pnl_giveback_close_r", None),
                "countertrend_fade_pnl_stall_bars": getattr(args, "countertrend_fade_pnl_stall_bars", None),
                "countertrend_fade_pnl_stall_min_mfe_r": getattr(args, "countertrend_fade_pnl_stall_min_mfe_r", None),
                "countertrend_fade_pnl_stall_close_below_r": getattr(args, "countertrend_fade_pnl_stall_close_below_r", None),
                "countertrend_fade_pnl_severe_adverse_r": getattr(args, "countertrend_fade_pnl_severe_adverse_r", None),
            },
            "entry_gates": {
                "gate_vwap": bool(getattr(args, "gate_vwap", True)),
                "vwap_gate_mode": _normalize_vwap_gate_mode(getattr(args, "vwap_gate_mode", "trend")),
                "gate_ema": bool(getattr(args, "gate_ema", True)),
                "gate_tod": bool(getattr(args, "gate_tod", True)),
                "gate_mode": str(getattr(args, "gate_mode", "prob_and_one") or "prob_and_one"),
            },
        "execution_targets": {
            "min_target_r_multiple": float(getattr(args, "min_target_r_multiple", 1.0) or 1.0),
        },
        "risk_limits": {
            "max_daily_loss_usd": _resolved_risk_value("max_daily_loss"),
            "max_risk_per_trade_usd": _resolved_risk_value("max_risk_per_trade_usd"),
            "max_trades_per_session": _resolved_risk_value("max_trades_per_session"),
            "max_trades_per_day": _resolved_risk_value("max_trades_per_day"),
            "max_losses_per_day": _resolved_risk_value("max_losses_per_day"),
            "loss_streak_limit": _resolved_risk_value("loss_streak_limit"),
            "cooldown_after_loss": _resolved_risk_value("cooldown_after_loss"),
        },
        "trade_management_overlay": {
            "pnl_overlay_enabled": (
                True if getattr(args, "pnl_overlay_enabled", None) is None else bool(getattr(args, "pnl_overlay_enabled"))
            ),
            "pnl_giveback_activate_r": getattr(args, "pnl_giveback_activate_r", None),
            "pnl_giveback_close_r": getattr(args, "pnl_giveback_close_r", None),
            "pnl_stall_bars": getattr(args, "pnl_stall_bars", None),
            "pnl_stall_min_mfe_r": getattr(args, "pnl_stall_min_mfe_r", None),
            "pnl_stall_close_below_r": getattr(args, "pnl_stall_close_below_r", None),
            "pnl_severe_adverse_r": getattr(args, "pnl_severe_adverse_r", None),
            "pnl_target_arm_min_hold_bars": getattr(args, "pnl_target_arm_min_hold_bars", None),
            "pnl_target_arm_min_unrealized_r": getattr(args, "pnl_target_arm_min_unrealized_r", None),
            "pnl_runner_enabled": getattr(args, "pnl_runner_enabled", None),
            "pnl_runner_arm_r": getattr(args, "pnl_runner_arm_r", None),
            "pnl_runner_hard_exit_r": getattr(args, "pnl_runner_hard_exit_r", None),
            "pnl_runner_giveback_r": getattr(args, "pnl_runner_giveback_r", None),
            "pnl_runner_suppress_target": getattr(args, "pnl_runner_suppress_target", None),
            "pnl_runner_ignore_close_before_arm": getattr(args, "pnl_runner_ignore_close_before_arm", None),
        },
        "phase2": bool(getattr(args, "phase2", False)),
        "phase2_tag": getattr(args, "phase2_tag", None),
        "phase2_manifest": getattr(args, "phase2_manifest_path", None),
        "phase2_close": {
            "enabled": bool(getattr(args, "phase2_close_enabled", False)),
            "model_path": getattr(args, "close_model_path", None),
            "threshold": getattr(args, "phase2_close_threshold", None),
        },
        "phase2_force_open_policy": {
            "enabled": bool(getattr(args, "phase2_force_open_on_gate_pass", False)),
            "min_setup": float(getattr(args, "phase2_force_open_min_setup", 0.0) or 0.0),
            "min_entry_conf": float(getattr(args, "phase2_force_open_min_entry_conf", 0.0) or 0.0),
            "legacy_gate_bypass_allowed": bool(
                getattr(args, "phase2_force_open_allow_legacy_gate_bypass", False)
            ),
            "allow_setup_fail_entries": bool(
                getattr(args, "phase2_force_open_allow_setup_fail_entries", False)
            ),
            "live_only": bool(getattr(args, "phase2_force_open_live_only", False)),
            "startup_cooldown_bypass_allowed": True,
            "source": "cli_or_preset",
        },
        "phase2_decision_policy": getattr(args, "phase2_decision_policy", None),
        "stale_gate_policy": {
            "live_only": bool(getattr(args, "live_only_stale_gate", False)),
        },
        "phase2_manifest_thresholds": getattr(args, "phase2_manifest_thresholds", None),
        "phase2_manifest_thresholds_used": resolved_thresholds.get("manifest_thresholds_used", False),
        "threshold_resolution": threshold_resolution,
        "preset_sources": preset_sources,
        "git_commit": _git_commit_hash(repo_root),
        "resolved_thresholds": {
            "p_long_required": resolved_thresholds["p_long_required"],
            "p_short_required": resolved_thresholds["p_short_required"],
            "p_setup_required": resolved_thresholds["p_setup_required"],
            "short_cut": resolved_thresholds["short_cut"],
            "source_map": resolved_thresholds["source_map"],
        },
        "threshold_sources": resolved_thresholds["source_map"],
        "trade_window_metadata": {
            "configured_start": configured_window_start,
            "configured_end": configured_window_end,
            "effective_start": effective_window_start,
            "effective_end": effective_window_end,
            "effective_reason": trade_window_effective_reason,
            "cli_forced": bool(trade_window_cli_forced),
            "cli_forced_start": bool(trade_window_start_cli_forced),
            "cli_forced_end": bool(trade_window_end_cli_forced),
        },
        # Backward-compat: "guardrails" now reflects the *effective* (capped/derived) settings.
        "guardrails": guardrails_effective,
        "guardrails_requested": guardrails_requested,
        "guardrails_effective": guardrails_effective,
        "guardrails_overrides": guardrails_overrides,
        "phase_state": {
            "enabled": bool(getattr(args, "phase_state_machine_enabled", True)),
            "backfill_lag_sec_threshold": float(phase_backfill_thresh),
            "currentness_lag_sec_threshold": float(phase_current_thresh),
            "currentness_confirmations_required": int(
                getattr(args, "phase_currentness_confirmations_required", 3) or 3
            ),
        },
        "readiness": {
            "bad_count_to_disarm": int(getattr(args, "readiness_bad_count_to_disarm", 2) or 2),
            "good_count_to_rearm": int(getattr(args, "readiness_good_count_to_rearm", 2) or 2),
            "snapshot_age_max_sec": float(getattr(args, "snapshot_age_max_sec", 60.0) or 60.0),
        },
    }
    logger.info(
        "CONFIG_RESOLVED preset=%s config_path=%s phase2=%s p_long=%.3f p_short=%.3f short_cut=%.3f source=%s",
        preset_name or "n/a",
        getattr(args, "config", None) or "n/a",
        bool(getattr(args, "phase2", False)),
        resolved_thresholds["p_long_required"],
        resolved_thresholds["p_short_required"],
        resolved_thresholds["short_cut"],
        resolved_thresholds["source_map"],
    )
    logger.info(
        "GUARDRAILS_RESOLVED price_age<=%.2fs snapshot_age<=%.2fs bar_interval=%.1fs bar_age_configured<=%.1fs bar_age_effective<=%.1fs protection_timeout=%.1fs close_emit_timeout=%.1fs cancel_loop_max=%d max_exit_pending=%.1fs auto_flatten=%s protection_repair=%s",
        guardrails_effective["price_age_max_sec"],
        guardrails_effective["snapshot_age_max_sec"],
        guardrails_effective["bar_interval_sec"],
        guardrails_effective["bar_age_max_sec_configured"],
        guardrails_effective["bar_age_max_sec_effective"],
        guardrails_effective["protection_timeout_sec"],
        guardrails_effective["close_emit_timeout_sec"],
        guardrails_effective["cancel_loop_max_updates"],
        guardrails_effective["max_exit_pending_sec"],
        guardrails_effective["auto_flatten_enabled"],
        guardrails_effective["protection_repair_enabled"],
    )
    logger.info(
        "PHASE_STATE_RESOLVED enabled=%s backfill_lag_sec=%s currentness_lag_sec=%s confirmations_required=%s",
        bool(getattr(args, "phase_state_machine_enabled", True)),
        float(phase_backfill_thresh),
        float(phase_current_thresh),
        int(getattr(args, "phase_currentness_confirmations_required", 3) or 3),
    )
    _write_resolved_config(out_dir=Path(getattr(args, "out_dir", "runs")), payload=resolved_payload)
    _log_effective_run_config(args)

    if getattr(args, "phase2", False):
        if getattr(args, "p_long", None) is not None and float(args.p_long) < 0.5:
            logger.warning("[PHASE2] p_long=%.3f < 0.50; verify manifest/CLI configuration.", float(args.p_long))
        if getattr(args, "p_short", None) is not None and float(args.p_short) < 0.5:
            logger.warning("[PHASE2] p_short=%.3f < 0.50; verify manifest/CLI configuration.", float(args.p_short))

    if getattr(args, "model", None) is None and getattr(args, "phase2", False) and getattr(args, "dir_model_path", None):
        args.model = args.dir_model_path

    if getattr(args, "model", None) is None:
        ap.error(
            "Missing model reference. Provide --model, supply a config with model.model_path, "
            "or pair --phase2 with --dir_model_path."
        )

    if registry:
        try:
            online_cfg = registry.online_learning
            champion_manager = ChampionManager(
                online_cfg.champion_state_dir,
                ev_margin=online_cfg.promotion_ev_margin,
                promotion_min_trades=online_cfg.promotion_min_trades,
            )
        except Exception as exc:
            logger.debug("Champion manager init failed: %s", exc)

    if args.debug:
        logger.setLevel(logging.DEBUG)

    # Router (wire Discord if provided)
    router = None
    if Router is not None:
        try:
            router = Router()
            if args.discord_webhook:
                router.enable_discord(args.discord_webhook)
        except Exception as e:
            logger.warning(f"Discord Router setup failed: {e}")
            router = None

    if router is None:
        r = DiscordEmitter()
        if args.discord_webhook:
            r.enable_discord(args.discord_webhook)
        router = r

    req_policy_profile = getattr(args, "policy_profile", None)
    disable_risk = bool(getattr(args, "norisk", False)) or bool(getattr(args, "disable_safety_gates", False))
    sim_mode = bool(getattr(args, "sim_mode", False))
    logger.info(f"Debug: disable_risk={disable_risk}, sim_mode={sim_mode}")
    if disable_risk and not sim_mode:
        logger.warning("--norisk used in non-sim mode; risk management will be disabled. This may be unsafe for live trading.")
    risk_profile = getattr(args, "risk_profile", None) or "rg_05_moderate"
    if getattr(args, "risk_profile", None) is None and req_policy_profile:
        logger.info(
            "RiskGuard profile defaulting to rg_05_moderate (policy_profile '%s' remains for adaptive logic).",
            req_policy_profile,
        )
    risk_config_path: Optional[str] = None
    risk_tz = getattr(args, "risk_tz", None) or getattr(args, "session_tz", "America/Denver")
    news_cache_path = getattr(args, "news_cache", None)
    state_overrides: Optional[Dict[str, Any]] = {}
    if getattr(args, "risk_persist_dir", None):
        state_overrides["persist_dir"] = args.risk_persist_dir
    if getattr(args, "risk_scope", None):
        state_overrides["scope"] = args.risk_scope
    if getattr(args, "risk_reset_anchor", None):
        state_overrides["reset_anchor"] = args.risk_reset_anchor
    if not state_overrides:
        state_overrides = None
    panic_flatten_cmd = getattr(args, "panic_flatten_cmd", None)
    risk_guard_cfg: Optional[Dict[str, Any]] = None
    if disable_risk:
        logger.warning("RiskGuard disabled via --norisk; skipping all L3 lockouts and policy guard gates.")
        try:
            policy_adapter._guard = None  # type: ignore[attr-defined]
        except Exception:
            pass
    else:
        risk_config_path = getattr(args, "risk_config", None)
    if risk_config_path and not disable_risk:
        risk_cli_overrides = _risk_guard_cli_overrides(
            args,
            prefer_profile_limits=bool(getattr(args, "risk_profile", None)),
        )
        if risk_cli_overrides:
            logger.debug("RiskGuard CLI overrides resolved: %s", risk_cli_overrides)
        materialized_cfg = (
            getattr(args, "risk_materialized_cfg", None)
            or os.getenv("RISK_CFG_MATERIALIZED")
            or os.getenv("RISK_MATERIALIZED_CFG")
        )
        instrument_alias = str(getattr(args, "instrument", "") or "")
        try:
            profile_cfg = load_effective_profile(
                profile=risk_profile,
                instrument=instrument_alias,
                yaml_path=risk_config_path,
                materialized_path=materialized_cfg,
                risk_strict=True,
                cli_overrides=risk_cli_overrides or None,
                env_json_overrides_var="RISK_JSON_OVERRIDES",
                default_tz=risk_tz,
            )
        except Exception as exc:
            logger.warning("Failed to load RiskGuard profile for synchronization: %s", exc)
        else:
            risk_guard_cfg = dict(profile_cfg.data)

        logger.info(
            "Initializing RiskGuard profile=%s config=%s instrument=%s tz=%s",
            risk_profile,
            risk_config_path,
            instrument_alias or "UNKNOWN",
            risk_tz,
        )
        policy_adapter.configure(
            policy_profile=risk_profile,
            risk_config=risk_config_path,
            tz=risk_tz,
            news_cache=news_cache_path,
            instrument=instrument_alias,
            materialized_cfg=materialized_cfg,
            risk_strict=True,
            cli_overrides=risk_cli_overrides or None,
            state_overrides=state_overrides,
            panic_flatten_cmd=panic_flatten_cmd,
            router=router,
        )
        if policy_adapter.guard_loaded():
            snapshot = policy_adapter.policy_snapshot(str(getattr(args, "instrument", "") or ""))
            loss_limit = snapshot.get("loss_limit")
            usd_today = snapshot.get("realized_usd_today")
            try:
                usd_today_val = float(usd_today) if usd_today is not None else 0.0
            except (TypeError, ValueError):
                usd_today_val = 0.0
            max_usd = None
            if risk_cli_overrides:
                max_usd = risk_cli_overrides.get("loss_limits.max_dollar_loss")
            if max_usd is None and isinstance(risk_guard_cfg, dict):
                loss_limits_cfg = risk_guard_cfg.get("loss_limits")
                if isinstance(loss_limits_cfg, dict):
                    max_usd = loss_limits_cfg.get("max_dollar_loss")
            try:
                max_usd_txt = f"{abs(float(max_usd)):.0f}" if max_usd is not None else "n/a"
            except (TypeError, ValueError):
                max_usd_txt = str(max_usd) if max_usd is not None else "n/a"
            logger.info(
                "RiskGuard active profile=%s sha=%s trades=%s/%s losses=%s/%s consec<=%s R<=%s usd<=%s min_signal>=%s dedupe=%sm size_after_loss=%s usd=%.0f persist=%s",
                snapshot.get("profile") or risk_profile,
                snapshot.get("cfg_sha256") or "n/a",
                snapshot.get("trades_today"),
                snapshot.get("trade_limit"),
                snapshot.get("losses_today"),
                snapshot.get("loss_limit"),
                snapshot.get("max_consecutive_losses"),
                snapshot.get("max_R_per_day"),
                snapshot.get("max_dollar_loss"),
                snapshot.get("min_signal_bars"),
                snapshot.get("same_dir_dedupe_min"),
                snapshot.get("size_after_first_loss_mult"),
                usd_today_val,
                snapshot.get("persist_dir"),
            )
        else:
            logger.error("RiskGuard failed to initialize; aborting. Check --risk_config and --risk_profile.")
            raise SystemExit(2)

    policy_cfg: Optional[EntryPolicyConfig] = None
    policy_overrides: Dict[str, Any] = {}
    if getattr(args, "policy_profile", None):
        base_profile = POLICY_PROFILES.get(str(args.policy_profile))
        if base_profile:
            policy_overrides.update(base_profile)
    if isinstance(risk_guard_cfg, dict):
        guard_policy_overrides = _policy_overrides_from_risk_guard(risk_guard_cfg)
        if guard_policy_overrides:
            logger.debug("RiskGuard policy overrides applied: %s", guard_policy_overrides)
            policy_overrides.update(guard_policy_overrides)

    def _maybe_set(attr: str, key: str, transform=None) -> None:
        if not hasattr(args, attr):
            return
        val = getattr(args, attr)
        if val is None:
            return
        policy_overrides[key] = transform(val) if transform else val

    _maybe_set("chop_preset", "chop_preset")
    _maybe_set("trend_preset", "trend_preset")
    _maybe_set("news_blackout_before", "news_blackout_before_min", int)
    _maybe_set("news_blackout_after", "news_blackout_after_min", int)
    _maybe_set("midday_trend_threshold", "midday_trend_threshold", float)
    _maybe_set("trend_threshold", "trend_threshold", float)
    _maybe_set("chop_threshold", "chop_threshold", float)
    _maybe_set("chop_range_threshold", "chop_range_threshold", float)
    _maybe_set("mode_persist_bars", "mode_persist_bars", int)
    _maybe_set("allow_countertrend_in_unresolved", "allow_countertrend_in_unresolved", bool)
    _maybe_set("allow_countertrend_fade_in_trend", "allow_countertrend_fade_in_trend", bool)
    _maybe_set("countertrend_fade_min_vwap_extension_pts", "countertrend_fade_min_vwap_extension_pts", float)
    _maybe_set("countertrend_fade_prob_threshold", "countertrend_fade_prob_threshold", float)
    _maybe_set("countertrend_fade_size_multiplier", "countertrend_fade_size_multiplier", float)
    _maybe_set("countertrend_fade_pnl_giveback_activate_r", "countertrend_fade_pnl_giveback_activate_r", float)
