    _maybe_set("day_stop_r", "day_stop_r", float)
    _maybe_set("dedupe_window_min", "dedupe_window_min", int)

    impacts_arg = getattr(args, "news_impacts", None)
    if impacts_arg is not None:
        splits = [s.strip().lower() for s in str(impacts_arg).split(",") if s.strip()]
        policy_overrides["news_impacts"] = tuple(splits)

    pause_arg = getattr(args, "midday_pause", None)
    if pause_arg:
        try:
            policy_overrides["midday_pause"] = _parse_pause_window(str(pause_arg))
        except Exception as exc:
            logger.warning("Invalid midday_pause '%s': %s", pause_arg, exc)

    if disable_risk:
        policy_cfg = None
    elif policy_overrides:
        policy_cfg = EntryPolicyConfig(**policy_overrides)

    # Optional: resolve champion model from the premarket_charts model registry.
    model_alias_or_path = args.model
    model_run_id: Optional[int] = None
    model_source = getattr(args, "model_source", "path")
    want_champion = bool(getattr(args, "use_champion", False)) or model_source == "champion"
    instrument_arg = str(getattr(args, "instrument", "") or "")
    manager_record = champion_manager.load_current(instrument_arg) if champion_manager else None
    if manager_record:
        model_alias_or_path = manager_record.model_path
        model_run_id = manager_record.model_id
        logger.info(
            "Champion resolved via manager for %s -> %s",
            instrument_arg.upper(),
            manager_record.model_path,
        )
    elif want_champion:
        artifact, run_id = _resolve_champion_artifact(instrument_arg)
        if artifact:
            logger.info(
                "Pre-flight champion check succeeded for %s: model_run_id=%s artifact=%s",
                instrument_arg.upper(),
                run_id,
                artifact,
            )
            model_alias_or_path = artifact
            model_run_id = run_id
        else:
            logger.warning(
                "Pre-flight champion check failed for %s; falling back to CLI --model=%s",
                instrument_arg.upper(),
                args.model,
            )

