    if not getattr(args, "disable_experience_log", False):
        try:
            registry = get_registry()
            exp_cfg = getattr(registry, "experience_config", None)
        except Exception:
            exp_cfg = None
        symbol_for_exp = instrument_arg or getattr(args, "instrument", None) or "ES"
        if exp_cfg:
            exp_dir = Path(getattr(args, "experience_dir", None) or exp_cfg.directory)
            pattern = getattr(args, "experience_pattern", None) or exp_cfg.file_pattern
            try:
                experience_writer = ExperienceWriter(exp_dir, symbol_for_exp, pattern)
                logger.info("Experience logging enabled at %s", experience_writer.path)
            except Exception as exc:
                logger.warning("Failed to initialize experience writer: %s", exc)

    metrics = MetricsCollector(namespace="stream_live_csv")
    prop_guardrails = None
    prop_guardrails_config_path: Optional[Path] = _simplified_repo_root() / "na" / "config" / "prop_config.yaml"
